import type { SignTemplates } from './types';

export const virgoTemplates: SignTemplates = {
  overall: {
    high: [
      { ko: '수성의 빛이 당신의 분석력을 극대화하는 날입니다. 남들이 혼란스러워하는 복잡한 문제 앞에서 처녀자리의 정밀한 사고가 마치 레이저처럼 핵심을 꿰뚫어 봅니다. 당신의 명석함을 두려워하지 말고 오늘 그 빛을 완전히 드러내세요.', en: 'Mercury\'s light maximizes your analytical power today, with Virgo\'s precise thinking cutting through complexity like a laser while others are confused. The clarity you bring to difficult situations is a genuinely rare gift that people around you notice and depend on. Don\'t hold back—let your brilliance show fully today.', zh: '水星之光将你的分析力发挥到极致。在别人感到混乱的复杂问题面前，处女座精密的思维像激光一样洞穿核心。不要畏惧自己的聪明才智，今天让那道光完全展现出来。', ja: '水星の光があなたの分析力を最大化する日です。他の人が混乱する複雑な問題の前で処女座の精密な思考がレーザーのように核心を見抜きます。あなたの明晰さを恐れず今日その光を完全に現してください。', es: 'La luz de Mercurio maximiza tu poder analítico hoy, con el pensamiento preciso de Virgo penetrando la complejidad como láser mientras otros se confunden. Tu claridad es un don genuinamente raro—no te contengas, deja que tu brillantez brille completamente hoy.' },
      { ko: '꼼꼼하게 준비해온 일이 빛을 발하는 시기입니다. 남들이 대충 넘어간 부분에서 당신이 쏟은 정성이 오늘 결정적인 차이를 만들어냅니다. 디테일이 승부를 결정짓는 이 순간, 처녀자리의 완벽한 준비가 당신을 돋보이게 합니다.', en: 'What you\'ve meticulously prepared shines now, with the care you poured into the parts others glossed over making a decisive difference today. The details decide the outcome, and in this moment Virgo\'s thorough preparation sets you distinctly apart. Trust everything you\'ve built—it was worth every painstaking minute.', zh: '精心准备的事情开始发光的时期。你在别人敷衍过去的部分所花的心思，今天创造出决定性的差异。细节决定胜负——这一刻，处女座的完美准备让你脱颖而出。', ja: '丁寧に準備してきたことが輝く時期です。他の人がざっと流した部分にあなたが注いだ丁寧さが今日決定的な差を生み出します。ディテールが勝負を決めるこの瞬間、処女座の完璧な準備があなたを際立たせます。', es: 'Lo que has preparado meticulosamente brilla ahora, con el cuidado que pusiste en partes que otros ignoraron marcando una diferencia decisiva hoy. Los detalles deciden el resultado, y en este momento la preparación minuciosa de Virgo te distingue claramente. Confía en todo lo que has construido.' },
      { ko: '오늘 당신의 실용적 판단력은 주변 모두에게 든든한 기둥이 됩니다. 혼란 속에서도 차분하게 가장 합리적인 길을 찾아내는 처녀자리의 능력이 오늘 가장 필요한 자질입니다. 자신감을 가지세요—당신이 있다는 것만으로 주변 사람들은 안심합니다.', en: 'Your practical judgment is a strong pillar for everyone around you today, with Virgo\'s ability to find the most rational path even in chaos being exactly the quality most needed right now. People around you feel safe simply because you are there—that reliability is a form of deep strength. Be confident in what you offer the world.', zh: '今天你的实用判断力成为周围所有人的坚实支柱。即使在混乱中也能冷静找到最合理道路的处女座能力，是今天最需要的素质。要有自信——仅仅因为你在，周围的人就感到安心。', ja: '今日あなたの実用的な判断力は周りのみんなにとって頼もしい柱になります。混乱の中でも冷静に最も合理的な道を見つける処女座の能力が今日最も必要な資質です。自信を持ってください——あなたがそこにいるだけで周りの人々は安心します。', es: 'Tu juicio práctico es un pilar fuerte para todos hoy, con la habilidad de Virgo de encontrar el camino más racional incluso en el caos siendo exactamente la cualidad más necesaria ahora. La gente se siente segura simplemente porque estás ahí. Ten confianza en lo que ofreces.' },
      { ko: '흙의 안정적 에너지가 견고한 기반을 만들어줍니다. 처녀자리의 대지 원소가 오늘 당신을 단단하게 지지하며, 어떤 변화나 외부 압력에도 쉽게 흔들리지 않는 내적 안정감이 당신을 감싸고 있습니다. 이 흔들리지 않는 하루를 이용해 오래 미뤄온 중요한 결정을 내리세요.', en: 'Earth\'s stable energy creates a solid foundation today, with Virgo\'s earth element firmly supporting you so that no change or external pressure can easily unsettle your inner stability. This unshakable quality is your greatest advantage today. Use this steady day to make the important decisions you\'ve been postponing for too long.', zh: '土元素的稳定能量为你打造坚实基础。处女座的大地元素今天坚定地支撑着你，无论任何变化或外部压力都难以动摇你内心的稳定感。利用这不动摇的一天做出你一直推迟的重要决定。', ja: '土の安定したエネルギーが堅固な基盤を作ってくれます。処女座の大地エレメントが今日あなたをしっかり支え、どんな変化や外部からのプレッシャーにも簡単に揺るがない内的安定感があなたを包んでいます。この揺るがない一日を利用して先延ばしにしてきた重要な決断を下してください。', es: 'La energía estable de la tierra crea una base sólida hoy, con el elemento tierra de Virgo apoyándote firmemente para que ningún cambio o presión externa pueda fácilmente desestabilizar tu estabilidad interior. Usa este día inquebrantable para tomar las decisiones importantes que has estado posponiendo.' },
      { ko: '세심한 관찰력이 남들이 놓친 기회를 포착하게 합니다. 처녀자리의 예리한 눈은 다른 사람들이 그냥 지나치는 작은 단서들 속에서 의미 있는 패턴을 발견하는 특별한 능력을 갖추고 있습니다. 오늘 눈앞의 작은 신호들에 집중하면, 그것이 당신만이 볼 수 있는 기회로 이어질 것입니다.', en: 'Your keen observation catches opportunities others miss today, because Virgo\'s sharp eyes hold a special ability to find meaningful patterns in the small clues others walk right past. Today, focus on the subtle signals directly before you—they form a pathway to an opportunity only you can see. Trust that hyper-attentive instinct completely.', zh: '细致的观察力让你捕捉到别人错过的机会。处女座锐利的眼睛具有在别人忽略的小线索中发现有意义模式的特殊能力。今天专注于眼前的小信号，它将通向只有你才能看见的机会。', ja: '細やかな観察力が他の人が見逃した機会を捉えさせます。処女座の鋭い目は他の人が通り過ぎてしまう小さな手がかりの中に意味のあるパターンを見つける特別な能力を持っています。今日目の前の小さなサインに集中すれば、それがあなただけが見える機会につながるでしょう。', es: 'Tu observación detallada capta oportunidades que otros pierden hoy, porque los ojos agudos de Virgo tienen la habilidad especial de encontrar patrones significativos en pequeñas pistas que otros pasan por alto. Enfócate en las señales sutiles ante ti—forman un camino hacia una oportunidad que solo tú puedes ver.' },
      { ko: '체계적으로 정리한 계획이 완벽하게 실행되는 날입니다. 오늘은 처녀자리가 준비해온 모든 것들이 하나의 완성된 그림으로 맞아떨어지는 특별한 시간입니다. 당신의 노력이 결실을 맺으니, 이 성취감을 충분히 느끼고 다음 목표를 향해 나아가세요.', en: 'Your systematically organized plan executes perfectly today, with everything Virgo has prepared coming together into one complete picture in a truly special convergence. Your efforts are bearing fruit right now in ways you can genuinely see and feel. Absorb this sense of achievement fully, then let it fuel your momentum toward the next goal.', zh: '系统整理的计划完美执行的一天。今天是处女座准备的所有一切如一幅完整的图画完美契合的特别时刻。你的努力终于结出果实——充分感受这份成就感，然后向下一个目标迈进。', ja: '体系的に整理した計画が完璧に実行される日です。今日は処女座が準備してきた全てのものが一つの完成した絵として合わさる特別な時間です。あなたの努力が実を結びますので、この達成感を十分に感じて次の目標に向かって進んでください。', es: 'Tu plan organizado sistemáticamente se ejecuta perfectamente hoy, con todo lo que Virgo ha preparado convergiendo en una imagen completa. Tus esfuerzos dan fruto de maneras que puedes ver y sentir realmente ahora. Absorbe plenamente este sentido de logro y deja que impulse tu momentum hacia la próxima meta.' },
      { ko: '수성이 순행하며 소통과 사고가 매끄럽게 흐릅니다. 처녀자리에게 수성의 순행은 마치 복잡한 기계의 모든 부품이 완벽하게 맞물려 돌아가는 것 같은 최적의 상태입니다. 모든 일이 톱니바퀴처럼 맞아떨어지는 지금, 어렵다고 생각해온 것들을 과감하게 시작해보세요.', en: 'Mercury moves direct today, making communication and thinking flow smoothly—and for Virgo, this is like all parts of a complex machine clicking into perfect alignment. Everything fits together like gears right now, creating the optimal conditions you\'ve been waiting for. This is the moment to boldly begin the things you\'ve been thinking were too difficult.', zh: '水星顺行，沟通和思维顺畅流动。对处女座来说，水星顺行就像复杂机械的所有部件完美咬合运转的最佳状态。一切像齿轮一样完美契合的现在，勇敢地开始你认为困难的事情吧。', ja: '水星が順行しコミュニケーションと思考がスムーズに流れます。処女座にとって水星の順行は複雑な機械の全ての部品が完璧に噛み合って回るような最適な状態です。全てのことが歯車のように合う今、難しいと思ってきたことを大胆に始めてみてください。', es: 'Mercurio avanza directo hoy, haciendo fluir comunicación y pensamiento suavemente—y para Virgo, esto es como todas las piezas de una máquina compleja encajando en perfecta alineación. Todo encaja como engranajes ahora, creando las condiciones óptimas que has estado esperando. Este es el momento de comenzar audazmente lo que pensabas que era demasiado difícil.' },
      { ko: '당신의 성실함을 알아주는 사람이 나타납니다. 소리 없이 꾸준히 해온 노력들이 오늘 드디어 가시적인 형태로 인정받는 특별한 날입니다. 묵묵히 걸어온 길이 결국 가장 멀리까지 이어진다는 것을, 오늘 당신은 증명하게 됩니다.', en: 'Someone recognizes your diligence today, and the efforts you\'ve sustained quietly over time are finally acknowledged in a visible and meaningful way. This is a special day when the path you\'ve walked in silence is confirmed to have led somewhere truly significant. You are proving today that the steady road ultimately travels the farthest.', zh: '有人认识到你的勤勉。你默默持续付出的努力今天终于以可见的形式得到认可，这是一个特别的日子。默默走过的路终究走得最远——今天你将证明这一点。', ja: 'あなたの誠実さを認めてくれる人が現れます。静かに地道に続けてきた努力が今日ついに目に見える形で認められる特別な日です。黙々と歩んできた道が結局最も遠くまで続くことを、今日あなたは証明することになります。', es: 'Alguien reconoce tu diligencia hoy, y los esfuerzos que has sostenido en silencio a lo largo del tiempo finalmente son reconocidos de manera visible y significativa. Este es un día especial en que el camino que has recorrido en silencio se confirma como algo verdaderamente significativo. Estás demostrando que el camino constante llega más lejos.' },
      { ko: '논리와 직관이 조화를 이루는 특별한 하루입니다. 분석적인 처녀자리가 이성과 감성 모두에서 같은 방향을 가리킬 때, 그것은 매우 드물고 강력한 신호입니다. 머리와 가슴이 같은 방향을 가리키는 지금, 오랫동안 확신이 서지 않았던 결정을 이제는 내릴 수 있습니다.', en: 'Logic and intuition harmonize on this special day—and for analytical Virgo, when both reason and feeling point in the same direction, that is a rare and powerful signal worth heeding. Head and heart agree right now, and this alignment is telling you that the decision you\'ve long been uncertain about can finally be made with confidence.', zh: '逻辑与直觉和谐统一的特别一天。对于分析型的处女座，当理性和感性都指向同一方向时，这是一个非常罕见而强烈的信号。头脑和心灵现在指向同一方向——那个长期让你举棋不定的决定，现在可以做出了。', ja: '論理と直感が調和する特別な一日です。分析的な処女座が理性と感性の両方から同じ方向を指す時、それは非常に稀で強力なシグナルです。頭と心が同じ方向を指している今、長い間確信が持てなかった決断を今こそ下すことができます。', es: 'Lógica e intuición se armonizan en este día especial—y para el analítico Virgo, cuando razón y sentimiento apuntan en la misma dirección, esa es una señal rara y poderosa que vale la pena atender. Cabeza y corazón están de acuerdo ahora mismo. La decisión sobre la que has tenido dudas por tanto tiempo puede finalmente tomarse con confianza.' },
      { ko: '봉사의 마음이 예상치 못한 행운으로 돌아옵니다. 처녀자리의 타고난 봉사 정신이 오늘 우주의 풍요 법칙과 공명하여, 당신이 남에게 베푸는 모든 것이 배가 되어 돌아오는 날입니다. 베풀수록 더 많이 채워지는 이 특별한 흐름 속에서, 오늘은 조금 더 관대하게 나눠보세요.', en: 'A spirit of service returns as unexpected luck today, with Virgo\'s innate serving nature resonating with the universe\'s law of abundance so that everything you give multiplies and returns. The more you give, the more you receive today—this special flow is real and available to you right now. Allow yourself to be a little more generous than usual and watch what comes back.', zh: '奉献的心意以意想不到的幸运回报。处女座天生的奉献精神今天与宇宙的丰盛法则产生共鸣，你为他人付出的一切都将加倍返还。在这特别的流动中，今天再慷慨一点地分享——看看什么会回来。', ja: '奉仕の心が予想外の幸運として返ってきます。処女座の生まれながらの奉仕精神が今日宇宙の豊かさの法則と共鳴し、あなたが他の人に与える全てが倍になって返ってくる日です。与えるほど多く満たされるこの特別な流れの中で、今日は少し多めに分け与えてみてください。', es: 'Un espíritu de servicio regresa como suerte inesperada hoy, con la naturaleza servicial innata de Virgo resonando con la ley de abundancia del universo de modo que todo lo que das se multiplica y regresa. Cuanto más das, más recibes hoy. Permítete ser un poco más generoso de lo habitual y observa lo que regresa.' },
    ],
    medium: [
      { ko: '일상의 루틴 속에서 작은 개선점을 발견할 수 있는 날입니다. 처녀자리의 날카로운 눈은 다른 사람들이 보지 못하는 비효율을 발견하는 데 탁월한데, 오늘 그 능력이 당신의 일상을 더 부드럽게 만들어줄 것입니다. 세부 조정이 큰 차이를 만든다는 것을 기억하며, 오늘 한 가지라도 개선해보세요.', en: 'A day to find small improvements in your daily routine, and Virgo\'s sharp eyes are excellent at spotting inefficiencies others miss—today that ability will make your daily life flow more smoothly. Fine-tuning makes a big difference, and the key is to act on what you notice rather than just cataloging it. Pick one thing and improve it today.', zh: '在日常中发现小改进点的一天。处女座锐利的眼睛在发现他人看不到的低效方面出类拔萃，今天这种能力将让你的日常更加顺畅。记住细微调整带来大不同——今天至少改进一件事。', ja: '日常のルーティンの中で小さな改善点を発見できる日です。処女座の鋭い目は他の人が見えない非効率を発見するのに優れており、今日その能力があなたの日常をより滑らかにしてくれます。細部の調整が大きな違いを生むことを覚えながら、今日一つでも改善してみてください。', es: 'Un día para encontrar pequeñas mejoras en tu rutina diaria, y los ojos agudos de Virgo son excelentes para detectar ineficiencias que otros no ven—hoy esa habilidad hará fluir tu vida cotidiana más suavemente. Los ajustes finos marcan la diferencia—elige una cosa y mejórala hoy.' },
      { ko: '평온한 에너지가 흐르고 있습니다. 이 차분한 흐름은 처녀자리에게 자신의 내면을 정돈할 수 있는 귀한 기회입니다. 서두르지 말고 하나씩 차분하게 정리해 나가세요—오늘의 느린 속도가 내일 더 빠르고 명확하게 움직일 수 있는 탄탄한 기반이 됩니다.', en: 'Calm energy flows today, and for Virgo this tranquil pace is a precious opportunity to organize not only external things but your inner world as well. Don\'t rush—work through things one by one at your own deliberate pace. Today\'s slower speed becomes the solid foundation that lets you move faster and more clearly tomorrow.', zh: '平静的能量在流动。这平静的流动对处女座来说是整理内心的珍贵机会。不要着急，一件一件冷静地整理——今天的慢速将成为明天更快更清晰地行动的坚实基础。', ja: '穏やかなエネルギーが流れています。この落ち着いた流れは処女座にとって自分の内面を整える貴重な機会です。焦らず一つずつ落ち着いて整理していってください——今日のゆっくりとしたペースが明日より速く明確に動ける確かな基盤になります。', es: 'Fluye energía tranquila hoy, y para Virgo este ritmo tranquilo es una preciosa oportunidad para organizar no solo cosas externas sino también tu mundo interior. No te apresures—trabaja en las cosas una por una a tu propio ritmo deliberado. La velocidad más lenta de hoy se convierte en la base sólida que te permite moverte más rápido y claramente mañana.' },
      { ko: '계획대로 진행되지 않더라도 유연하게 대처하면 괜찮은 결과를 얻을 수 있습니다. 처녀자리는 변통궁의 별자리로, 사실 변화에 적응하는 본능적인 유연함을 갖추고 있습니다. 오늘의 예상치 못한 변수가 오히려 더 나은 방향을 열어줄 수 있다는 가능성에 마음을 열어두세요.', en: 'Even if things don\'t go as planned today, flexible response brings decent results—and as a mutable sign, Virgo actually carries an instinctive flexibility for adapting to change. The hidden opportunity is that today\'s unexpected variable may open a better direction than the original plan. Keep your mind open to that possibility.', zh: '即使不按计划进行，灵活应对也能获得不错的结果。作为变动宫星座，处女座其实本能地拥有适应变化的灵活性。今天意想不到的变数，可能恰恰开启比原计划更好的方向——对这种可能性保持开放的心态。', ja: '計画通りに進まなくても柔軟に対処すればまずまずの結果を得られます。処女座は変通宮の星座として、実は変化に適応する本能的な柔軟性を持っています。今日の予想外の変数がむしろより良い方向を開いてくれる可能性に心を開いておいてください。', es: 'Aunque las cosas no salgan según el plan hoy, una respuesta flexible trae buenos resultados—y como signo mutable, Virgo en realidad tiene una flexibilidad instintiva para adaptarse al cambio. La oportunidad oculta es que la variable inesperada de hoy puede abrir una mejor dirección que el plan original. Mantén tu mente abierta a esa posibilidad.' },
      { ko: '주변 정리와 환경 개선이 마음의 안정을 가져다줍니다. 처녀자리에게 외부 공간의 질서는 내면의 명확성과 깊이 연결되어 있습니다. 책상 위부터 정돈해보세요—그 5분의 정리가 오늘 하루 집중력과 생산성을 놀랍게 끌어올려줄 것입니다.', en: 'Tidying your surroundings brings mental peace, and for Virgo the order of external space is deeply connected to inner clarity. Start by organizing your desk—those five minutes of tidying will remarkably elevate your focus and productivity for the rest of the day. A clear space creates a clear mind, and a clear mind is Virgo\'s natural state.', zh: '整理周围环境能带来内心的安宁。对处女座来说，外部空间的秩序与内在的清晰度深深相连。从整理桌面开始吧——那5分钟的整理将显著提升今天剩余时间的专注力和生产效率。', ja: '周りの整理と環境改善が心の安定をもたらします。処女座にとって外部空間の秩序は内なる明晰さと深くつながっています。デスクの上から整頓してみてください——その5分の整理が今日一日の集中力と生産性を驚くほど高めてくれるでしょう。', es: 'Ordenar tu entorno trae paz mental, y para Virgo el orden del espacio externo está profundamente conectado con la claridad interior. Empieza organizando tu escritorio—esos cinco minutos de orden elevarán notablemente tu concentración y productividad por el resto del día.' },
      { ko: '수성의 에너지가 안정적으로 흐릅니다. 오늘은 큰 도전보다 탄탄한 기초를 다지는 데 집중하는 것이 지혜입니다. 복잡한 일보다 기본에 충실한 하루를 보내세요—처녀자리의 진정한 힘은 화려한 움직임이 아닌 꾸준한 정확성에서 나오기 때문입니다.', en: 'Mercury\'s energy flows steadily today, and the wisdom here is to focus on building solid foundations rather than attempting big challenges. Focus on basics rather than complicated tasks—because Virgo\'s true power comes not from flashy moves but from consistent precision and reliability. That steady excellence is what ultimately creates exceptional results.', zh: '水星能量稳定流动。今天专注于打好坚实基础而非大挑战是明智的。专注于基本事务而非复杂的事情——因为处女座真正的力量来自于持续的精准性，而非华丽的举动。', ja: '水星のエネルギーが安定的に流れています。今日は大きな挑戦より確かな基礎を固めることに集中するのが賢明です。複雑なことより基本に忠実な一日を過ごしてください——処女座の真の力は華やかな動きではなく、コツコツとした正確さから来るからです。', es: 'La energía de Mercurio fluye establemente hoy, y la sabiduría aquí es enfocarse en construir bases sólidas en lugar de intentar grandes desafíos. Enfócate en lo básico—porque el verdadero poder de Virgo no viene de movimientos llamativos sino de precisión y confiabilidad constantes.' },
      { ko: '자신에게 너무 엄격하지 마세요. 처녀자리의 높은 기준이 성장의 동력이 되기도 하지만, 그 기준이 자기 비판으로 향할 때는 오히려 발목을 잡습니다. 오늘은 있는 그대로의 자신을 인정하는 연습이 필요합니다—당신은 이미 충분히 노력하고 있으며, 그것으로 충분합니다.', en: 'Don\'t be too hard on yourself today—Virgo\'s high standards can fuel growth, but when those standards turn into self-criticism they become a stumbling block instead. Today calls for accepting yourself exactly as you are. You are already trying hard enough, and that effort is genuinely sufficient. Give yourself the compassion you would freely offer others.', zh: '不要对自己太严格。处女座的高标准虽然可以成为成长的动力，但当那种标准转向自我批评时反而会成为绊脚石。今天需要练习接受原本的自己——你已经足够努力了，这就足够了。', ja: '自分に厳しくしすぎないでください。処女座の高い基準は成長の動力にもなりますが、その基準が自己批判に向かう時はむしろ足かせになります。今日はありのままの自分を認める練習が必要です——あなたはすでに十分努力していて、それで十分です。', es: 'No seas tan duro contigo mismo hoy—los altos estándares de Virgo pueden impulsar el crecimiento, pero cuando esos estándares se convierten en autocrítica se vuelven un obstáculo. Hoy necesitas aceptarte tal como eres. Ya estás esforzándote lo suficiente, y ese esfuerzo es genuinamente suficiente.' },
      { ko: '작은 목표를 세우고 하나씩 달성하며 성취감을 쌓아가세요. 처녀자리에게 이 접근법은 단순한 습관이 아닌 가장 강력한 성공 방정식입니다. 꾸준함이 가장 큰 무기이며, 오늘 하나의 작은 목표를 체크하는 그 행동이 앞으로의 모든 큰 성취를 위한 토대입니다.', en: 'Set small goals and build a sense of achievement one by one today—for Virgo, this approach is not just a habit but the most powerful success equation available. Consistency is your greatest weapon, and the act of checking off one small goal today is the foundation upon which all future great achievements will stand. Take that one small action now.', zh: '设定小目标逐一完成，积累成就感。对处女座来说，这种方法不只是习惯，而是最强大的成功方程式。坚持是最大的武器——今天完成一个小目标的那个行动，是未来所有伟大成就的基础。', ja: '小さな目標を立てて一つずつ達成し成就感を積み上げてください。処女座にとってこのアプローチは単なる習慣ではなく最も強力な成功の方程式です。着実さが最大の武器であり、今日一つの小さな目標をチェックするその行動が今後の全ての大きな成就の土台です。', es: 'Establece metas pequeñas y logra una por una hoy—para Virgo, este enfoque no es solo un hábito sino la ecuación de éxito más poderosa disponible. La constancia es tu mejor arma, y el acto de completar una pequeña meta hoy es la base sobre la que se sostendrán todos los grandes logros futuros.' },
      { ko: '분석보다 직감에 귀 기울여보는 것도 좋은 날입니다. 처녀자리의 세심한 관찰이 쌓여온 방대한 경험 데이터가 직감의 형태로 나타날 때, 그것은 가장 빠른 분석 결과입니다. 때로는 느낌이 데이터보다 정확하다는 것—오늘은 그 숨겨진 지식을 믿어볼 기회입니다.', en: 'Today is good for listening to intuition over analysis—because for Virgo, intuition is often the compressed form of all the detailed observations your meticulous mind has accumulated over time. When that vast experiential database surfaces as a feeling, it can be faster and more accurate than any formal analysis. Today is your opportunity to trust that hidden knowledge.', zh: '今天试着倾听直觉而非分析也不错。对处女座来说，直觉往往是你细心观察积累的大量经验数据以快速形式呈现的结果。当那种感觉浮现时，它可以比任何正式分析更快更准确——今天是信任那种隐藏知识的机会。', ja: '分析より直感に耳を傾けてみるのも良い日です。処女座にとって直感はしばしばあなたの細やかな観察が積み重ねてきた膨大な経験データが圧縮された形で現れたものです。その広大な経験データが感覚として浮かぶ時、それは最も速い分析結果です。時には感覚がデータより正確である——今日はその隠れた知識を信じる機会です。', es: 'Hoy es bueno escuchar la intuición sobre el análisis—porque para Virgo, la intuición es a menudo la forma comprimida de todas las observaciones detalladas que tu mente meticulosa ha acumulado. Cuando esa vasta base de datos experiencial surge como un sentimiento, puede ser más rápida y precisa que cualquier análisis formal. Hoy es tu oportunidad de confiar en ese conocimiento oculto.' },
      { ko: '건강한 습관을 유지하면 무난한 하루가 됩니다. 처녀자리는 루틴이 흔들릴 때 전반적인 에너지도 함께 흔들리는 경향이 있는데, 오늘 그 루틴을 잘 지키면 예상치 못한 일이 생겨도 흔들리지 않을 수 있습니다. 규칙적인 생활이 당신의 든든한 방패이며, 오늘 그 방패를 잘 챙기세요.', en: 'Maintaining healthy habits ensures a smooth day today, and for Virgo whose overall energy tends to fluctuate when routine is disrupted, keeping that routine intact creates a buffer against whatever unexpected events may arise. Regular routine is your reliable shield, and it works best precisely on days like today when circumstances could otherwise challenge you.', zh: '保持健康习惯就能度过平稳的一天。处女座在习惯被打乱时整体能量也容易随之波动，今天好好遵守那些习惯，即使发生意外情况也能保持稳定。规律生活是你可靠的盾牌——今天好好珍惜那面盾牌。', ja: '健康的な習慣を維持すれば無難な一日になります。処女座はルーティンが乱れる時に全体的なエネルギーも一緒に揺らぐ傾向がありますが、今日そのルーティンをしっかり守れば予想外のことが起きても揺るがずにいられます。規則的な生活があなたの頼もしい盾ですので、今日その盾をしっかり持ってください。', es: 'Mantener hábitos saludables asegura un día tranquilo hoy, y para Virgo cuya energía general tiende a fluctuar cuando la rutina se interrumpe, mantener esa rutina intacta crea un amortiguador contra cualquier evento inesperado. La rutina regular es tu escudo confiable—funciona mejor precisamente en días como hoy.' },
      { ko: '완벽하지 않아도 충분히 가치 있는 하루입니다. 처녀자리의 내면에 있는 엄격한 채점자가 오늘 오직 A+만을 요구할지 모르지만, 80점짜리 하루도 훌륭하다는 것을 기억하세요. 꾸준히 80점을 쌓아가는 것이 가끔 100점을 내고 나머지를 포기하는 것보다 훨씬 더 멀리 데려다줍니다.', en: 'Even an imperfect day is valuable enough, and while Virgo\'s inner critic may be demanding only A+ today, an 80-point day is genuinely wonderful. Remember that consistently showing up at 80 will take you much farther than occasionally hitting 100 and abandoning the rest. The compound value of good-enough consistency is extraordinary.', zh: '不完美也足够有价值的一天。处女座内心严格的评分者今天可能只要求A+，但请记住80分的一天也很棒。持续积累80分远比偶尔得100分然后放弃其余的走得更远。', ja: '完璧でなくても十分に価値のある一日です。処女座の内なる厳格な採点者が今日A+だけを要求するかもしれませんが、80点の一日も素晴らしいことを覚えておいてください。コツコツと80点を積み重ねていくことが、たまに100点を出して残りをあきらめるより遥かに遠くまで連れていってくれます。', es: 'Un día imperfecto sigue siendo valioso, y aunque el crítico interno de Virgo puede exigir solo A+ hoy, un día de 80 puntos es genuinamente maravilloso. Recuerda que aparecer consistentemente en 80 te llevará mucho más lejos que ocasionalmente alcanzar 100 y abandonar el resto. El valor compuesto de la consistencia suficiente es extraordinario.' },
    ],
    low: [
      { ko: '과도한 걱정이 에너지를 소진시킬 수 있습니다. 처녀자리의 날카로운 분석력이 오늘만큼은 재앙 시나리오를 끝없이 시뮬레이션하고 있을지 모르지만, 걱정 자체가 해결책이 된 적은 단 한 번도 없습니다. 통제할 수 없는 일은 잠시 내려놓는 연습을 하세요—당신의 에너지는 실제로 행동할 수 있는 것에 쓰일 때 가장 빛납니다.', en: 'Excessive worry may drain your energy today, and Virgo\'s sharp analytical mind may be endlessly simulating disaster scenarios—but worry itself has never once become a solution. What you can\'t control isn\'t worth your precious mental energy. Practice the discipline of setting it down, and redirect that intelligence toward what you can actually act on right now.', zh: '过度的担心可能会耗尽你的能量。处女座敏锐的分析力今天可能在不断模拟灾难场景，但担心本身从未成为解决方案。练习放下无法控制的事情——你的能量在能真正采取行动的地方才会最闪耀。', ja: '過度な心配がエネルギーを消耗させる可能性があります。処女座の鋭い分析力が今日に限っては災害シナリオを果てしなくシミュレーションしているかもしれませんが、心配自体が解決策になったことは一度もありません。コントロールできないことは一旦手放す練習をしてください——あなたのエネルギーは実際に行動できることに使われる時に最も輝きます。', es: 'La preocupación excesiva puede agotar tu energía hoy, y la aguda mente analítica de Virgo puede estar simulando escenarios de desastre sin fin—pero la preocupación nunca se convirtió en solución. Lo que no puedes controlar no merece tu valiosa energía mental. Practica la disciplina de dejarlo ir y redirige esa inteligencia hacia lo que realmente puedes hacer ahora.' },
      { ko: '완벽을 추구하다 지칠 수 있는 날입니다. 처녀자리가 설정한 기준은 다른 누구보다 높지만, 오늘 그 기준이 스스로를 옥죄는 족쇄가 되고 있지는 않은지 살펴보세요. 오늘만큼은 기준을 조금 낮추어도 괜찮습니다—75점짜리 결과물도 세상을 바꿀 수 있습니다.', en: 'Pursuing perfection may exhaust you today—Virgo sets standards higher than anyone else, but examine whether those standards are becoming chains that bind you rather than wings that lift you. It\'s okay to lower the bar a little just for today. A 75-point result can still change the world, and a rested Virgo tomorrow is worth more than an exhausted one today.', zh: '追求完美可能让你今天筋疲力尽。处女座设定的标准比任何人都高，但今天检查一下那些标准是否成了束缚自己的枷锁。今天稍微降低标准也没关系——75分的结果也能改变世界，而明天精力充沛的你比今天精疲力竭的你更有价值。', ja: '完璧を追求して疲れる可能性がある日です。処女座が設定する基準は誰よりも高いですが、今日その基準が自分を縛る足かせになっていないか見直してみてください。今日だけは基準を少し下げても大丈夫です——75点の結果も世界を変えることができますし、明日元気な処女座は今日疲れ果てた処女座より価値があります。', es: 'Perseguir la perfección puede agotarte hoy—Virgo establece estándares más altos que nadie, pero examina si esos estándares se están convirtiendo en cadenas que te atan en lugar de alas que te elevan. Está bien bajar el listón un poco solo por hoy. Un resultado de 75 puntos también puede cambiar el mundo, y un Virgo descansado mañana vale más que uno agotado hoy.' },
      { ko: '수성의 역행 기운이 소통에 혼선을 줄 수 있습니다. 이것은 당신만의 문제가 아닙니다—수성 역행은 모든 사람의 커뮤니케이션 경로를 흐트러뜨리는 우주적 교통체증입니다. 중요한 메시지는 두 번 확인하고, 오해가 생겨도 자책하지 마세요. 이 시기는 결정보다 검토의 시간입니다.', en: 'Mercury retrograde energy may cause communication mix-ups today—and this is not your problem alone. Mercury retrograde is a cosmic traffic jam scrambling everyone\'s communication channels, not a personal failing. Double-check important messages before sending, and if misunderstandings arise, resist the urge to self-blame. This is a time for review rather than final decisions.', zh: '水星逆行的气息可能导致沟通混乱。这不只是你的问题——水星逆行是打乱所有人沟通渠道的宇宙大堵车，不是个人失误。重要信息请确认两遍后再发送，即使产生误解也不要自责。这是一个检视而非做最终决定的时期。', ja: '水星の逆行の気運がコミュニケーションに混乱をもたらす可能性があります。これはあなただけの問題ではありません——水星逆行は全員のコミュニケーション経路を乱す宇宙的な交通渋滞であり、個人的な失敗ではありません。重要なメッセージは送る前に二度確認し、誤解が生じても自責しないでください。この時期は最終決断より検討の時間です。', es: 'La energía retrógrada de Mercurio puede causar malentendidos hoy—y este no es solo tu problema. Mercurio retrógrado es un atasco cósmico que perturba los canales de comunicación de todos, no un fracaso personal. Verifica los mensajes importantes antes de enviarlos y si surgen malentendidos, resiste el impulso de culparte. Este es un tiempo para revisar, no para decisiones finales.' },
      { ko: '비판적인 시선을 자기 자신에게 향하지 마세요. 당신이 타인의 결점을 발견하는 것만큼이나 예리하게 자신의 결점을 확대해서 보고 있을지 모릅니다. 오늘 그 내면의 비판자에게 잠시 휴가를 주세요—당신은 충분히 잘하고 있으며, 그 증거는 지금 이 순간에도 쌓이고 있습니다.', en: 'Don\'t turn your critical eye on yourself today—you may be magnifying your own flaws as sharply as you notice others\', and that inner critic needs a day off. You are doing well enough, and the evidence of that is accumulating even in this very moment. Give yourself the same generous assessment you would offer a friend who was trying their best.', zh: '不要用批判的眼光审视自己。你可能正在像发现别人缺点一样敏锐地放大自己的不足。今天给那个内心的批评者放个假吧——你已经做得很好了，那个证明甚至在此刻也在积累。像对待一个尽力而为的朋友那样慷慨地评价自己。', ja: '批判的な視線を自分自身に向けないでください。他人の欠点を見つけるのと同じくらい鋭く自分の欠点を拡大して見ているかもしれません。今日その内なる批判者に少し休暇を与えてください——あなたは十分によくやっており、その証拠はまさに今この瞬間にも積み重なっています。', es: 'No dirijas tu mirada crítica hacia ti mismo hoy—puedes estar magnificando tus propias fallas tan agudamente como notas las de otros, y ese crítico interior necesita un día libre. Lo estás haciendo bastante bien, y la evidencia de eso se acumula incluso en este mismo momento. Date la misma evaluación generosa que le ofrecerías a un amigo que está dando lo mejor de sí.' },
      { ko: '디테일에 매몰되어 전체 그림을 놓칠 수 있습니다. 처녀자리의 숲은 나무들이 너무 아름다워서 종종 숲 자체를 보지 못하게 합니다. 오늘 한 발짝 물러서서 큰 흐름을 살피세요—당신이 지금 집중하고 있는 세부사항이 전체 목표와 여전히 연결되어 있는지 확인해보세요.', en: 'You may lose the big picture by getting lost in details today—Virgo\'s trees are so beautifully intricate that they sometimes prevent seeing the forest itself. Take one deliberate step back and survey the larger flow. Check whether the details you\'re currently focused on are still connected to your overall goal, because the most perfect detail is worthless if it\'s in the wrong direction.', zh: '今天可能因沉迷于细节而忽略全局。处女座的树木太美丽了，有时会让你看不见森林本身。退一步看看大趋势——检查你现在专注的细节是否仍然与总体目标相连，因为方向错误的完美细节毫无价值。', ja: 'ディテールに埋没して全体像を見失う可能性があります。処女座の森の木々はあまりにも美しくて、しばしば森そのものを見えなくさせます。今日は一歩引いて大きな流れを見てください——今集中しているディテールが全体目標とまだつながっているか確認してください。間違った方向の完璧なディテールは意味がありません。', es: 'Puedes perder la visión general al perderte en detalles hoy—los árboles de Virgo son tan bellamente intrincados que a veces impiden ver el bosque en sí. Da un paso deliberado atrás y examina el panorama más amplio. Verifica si los detalles en los que te estás enfocando todavía están conectados con tu objetivo general, porque el detalle más perfecto no vale nada si apunta en la dirección equivocada.' },
      { ko: '신경이 예민해지기 쉬운 날입니다. 이것은 당신의 약함이 아니라 높은 감수성과 세밀한 감각을 가진 처녀자리의 자연스러운 반응입니다. 자연 속 산책이나 깊은 호흡으로 마음을 가라앉히세요—외부 환경을 바꿀 수 없을 때 내면의 조용한 공간으로 퇴각하는 것은 현명한 선택입니다.', en: 'Nerves are easily frayed today, and this is not weakness—it is the natural response of Virgo\'s high sensitivity and finely tuned senses. Calm your mind with a nature walk or deep breathing exercises. When you cannot change the external environment, retreating to a quiet inner space is the wisest possible choice, not an escape but a strategic recharge.', zh: '今天容易神经敏感。这不是你的软弱，而是拥有高度敏感性和细腻感官的处女座的自然反应。通过自然散步或深呼吸来平静心情——无法改变外部环境时，退到内心安静的空间是明智的选择，不是逃避而是战略性充电。', ja: '神経が敏感になりやすい日です。これはあなたの弱さではなく、高い感受性と繊細な感覚を持つ処女座の自然な反応です。自然の中の散歩や深呼吸で心を落ち着けてください——外部環境を変えられない時に内なる静かな空間に退くことは賢明な選択であり、逃避ではなく戦略的な充電です。', es: 'Los nervios se alteran fácilmente hoy, y esto no es debilidad—es la respuesta natural de la alta sensibilidad y los sentidos finamente sintonizados de Virgo. Calma tu mente con un paseo por la naturaleza o ejercicios de respiración profunda. Cuando no puedes cambiar el entorno externo, retirarte a un espacio interior tranquilo es la elección más sabia, no una huida sino una recarga estratégica.' },
      { ko: '모든 것을 혼자 해결하려 하지 마세요. 처녀자리의 독립심과 완벽주의가 결합하면 "내가 직접 하지 않으면 제대로 안 된다"는 罠(함정)에 빠지기 쉽습니다. 도움을 요청하는 것도 지혜입니다—타인에게 기회를 주고 당신이 정말 중요한 것에 집중하게 되는 진정한 효율입니다.', en: 'Don\'t try to solve everything alone today—when Virgo\'s independence and perfectionism combine, it\'s easy to fall into the trap of "if I don\'t do it myself, it won\'t be done right." Asking for help is genuine wisdom. It gives others a chance to contribute while freeing you to focus on what truly matters most to you—that is real efficiency, not a compromise.', zh: '不要试图独自解决所有事情。当处女座的独立性和完美主义结合时，很容易陷入"如果我不亲自做就不会做好"的陷阱。寻求帮助也是智慧——给他人机会贡献，让你专注于真正重要的事情，这才是真正的效率而非妥协。', ja: 'すべてを一人で解決しようとしないでください。処女座の独立心と完璧主義が組み合わさると「自分でやらなければうまくいかない」という罠に陥りやすくなります。助けを求めることも知恵です——他人に機会を与え、あなたが本当に重要なことに集中できるようになる真の効率です。妥協ではありません。', es: 'No intentes resolver todo solo hoy—cuando la independencia y el perfeccionismo de Virgo se combinan, es fácil caer en la trampa de "si no lo hago yo, no se hará bien." Pedir ayuda es genuina sabiduría. Le da a otros la oportunidad de contribuir mientras te libera para enfocarte en lo que realmente importa más—eso es eficiencia real, no un compromiso.' },
      { ko: '계획이 틀어져도 당황하지 마세요. 변통궁에 속하는 처녀자리는 변화에 적응하는 타고난 능력을 갖추고 있습니다—다만 그 능력이 완벽주의의 그늘에 가려져 있을 뿐입니다. 계획 B를 즉흥적으로 만들어내는 것이 오히려 처녀자리의 창의적인 문제해결력이 빛나는 순간입니다.', en: 'Don\'t panic if plans go awry today—as a mutable sign, Virgo carries an innate ability to adapt to change, though that ability is often obscured by perfectionism\'s shadow. Improvising a Plan B is actually the moment when Virgo\'s creative problem-solving shines most brightly. The disruption is not the disaster; it\'s the invitation to demonstrate your true flexibility.', zh: '计划出错也不要慌张。作为变动宫星座，处女座天生具有适应变化的能力——只是那种能力常常被完美主义的阴影遮蔽。即兴创造计划B恰恰是处女座创造性解决问题能力闪光的时刻。变化不是灾难，而是展示你真正灵活性的邀请。', ja: '計画が狂っても慌てないでください。変通宮に属する処女座は変化に適応する生まれながらの能力を持っています——ただその能力が完璧主義の影に隠れているだけです。プランBを即興で作り出すことが、むしろ処女座の創造的な問題解決力が輝く瞬間です。', es: 'No te asustes si los planes cambian hoy—como signo mutable, Virgo tiene una habilidad innata para adaptarse al cambio, aunque esa habilidad a menudo está oscurecida por la sombra del perfeccionismo. Improvisar un Plan B es en realidad el momento en que brilla más el talento creativo de Virgo para resolver problemas. La disrupción no es el desastre—es la invitación a demostrar tu verdadera flexibilidad.' },
      { ko: '불안한 생각이 꼬리를 물 수 있습니다. 처녀자리의 마음은 문제를 해결하도록 설계되어 있어서, 문제가 없을 때조차 문제를 찾아 만들어내는 경향이 있습니다. 종이에 걱정을 모두 적어보세요—실체화된 걱정들이 얼마나 작고 다루기 쉬운지 보면 놀랄 것입니다.', en: 'Anxious thoughts may spiral today—Virgo\'s mind is designed to solve problems, which means it tends to generate new ones even when none exist. Try writing all your worries on paper without filtering them. You may be surprised by how small and manageable those concerns look once they\'re extracted from your mind and placed on a page. Externalizing worry reduces its power.', zh: '不安的想法可能会连环出现。处女座的思维天生就是用来解决问题的，这意味着即使没有问题时也倾向于寻找和制造问题。把所有担忧不加过滤地写在纸上——一旦从脑海中提取出来放在纸上，你可能会惊讶于那些担忧有多小、多容易处理。将担忧外部化会降低它的力量。', ja: '不安な考えが連鎖する可能性があります。処女座の心は問題を解決するように設計されているため、問題がない時でさえ新しい問題を見つけ出す傾向があります。フィルタリングせずに全ての心配を紙に書き出してみてください。心から取り出してページに置かれた時、それらの懸念がいかに小さく扱いやすいかに驚くかもしれません。', es: 'Los pensamientos ansiosos pueden encadenarse hoy—la mente de Virgo está diseñada para resolver problemas, lo que significa que tiende a generar nuevos incluso cuando no existen. Intenta escribir todas tus preocupaciones en papel sin filtrarlas. Puede sorprenderte lo pequeñas y manejables que parecen esas preocupaciones una vez extraídas de tu mente y colocadas en una página.' },
      { ko: '에너지가 낮은 날입니다. 처녀자리에게 쉬는 날은 낭비가 아닙니다—그것은 내일 더 날카롭고 더 강하게 작동할 수 있는 정밀한 도구를 정비하는 시간입니다. 오늘은 생산성보다 회복에 집중하세요. 쉬는 것도 능력이며, 가장 똑똑한 처녀자리는 언제 멈춰야 하는지를 압니다.', en: 'A low-energy day—and for Virgo, a rest day is not waste but the essential maintenance time for a precision tool that needs to operate sharply and strongly tomorrow. Focus on recovery over productivity today. Resting is also a genuine skill, and the wisest Virgo understands exactly when to stop and recharge. Give yourself that unconditional permission now.', zh: '能量低的一天。对处女座来说，休息日不是浪费——而是为精密工具进行保养的时间，让它明天能更敏锐更强力地运作。今天专注于恢复而非生产力。休息也是一种能力，最聪明的处女座知道什么时候该停下来。现在给自己那份无条件的许可。', ja: 'エネルギーが低い日です。処女座にとって休みの日は無駄ではありません——それは明日よりシャープにより強く動くことができるように精密な道具を整備する時間です。今日は生産性より回復に集中してください。休むことも能力であり、最も賢い処女座はいつ止まるべきかを知っています。今その無条件の許可を自分に与えてください。', es: 'Un día de baja energía—y para Virgo, un día de descanso no es desperdicio sino el tiempo esencial de mantenimiento para una herramienta de precisión que necesita operar con agudeza y fuerza mañana. Enfócate en recuperarte hoy más que en ser productivo. Descansar también es una habilidad genuina, y el Virgo más sabio sabe exactamente cuándo detenerse y recargarse.' },
    ],
  },
  love: {
    high: [
      { ko: '세심한 배려가 상대의 마음을 깊이 움직입니다. 처녀자리는 상대가 미처 말하기 전에 필요한 것을 알아차리는 드문 재능을 타고났는데, 오늘 그 재능이 사랑의 언어로 완벽하게 번역됩니다. 작은 챙김이 큰 사랑의 증거가 되는 이 날, 당신이 준비한 그 섬세한 것들을 주저 없이 표현해보세요.', en: 'Your thoughtful care deeply moves your partner today—Virgo is born with the rare gift of noticing what someone needs before they even say it, and today that gift translates perfectly into the language of love. Small gestures become undeniable proof of great love. Express those delicate things you\'ve prepared without hesitation, because your partner will feel the depth behind every one.', zh: '细心的关怀今天深深打动了对方的心。处女座天生具有在对方开口之前就察觉到对方需要什么的罕见才能，今天这种才能完美地转化为爱的语言。小小的关心成为爱情的有力证明——毫不犹豫地表达那些你精心准备的细腻事物吧。', ja: '細やかな配慮が相手の心を深く動かします。処女座は相手が言葉にする前に必要なものを察知する稀な才能を持って生まれましたが、今日その才能が愛の言語として完璧に翻訳されます。小さな気遣いが大きな愛の証になるこの日、あなたが準備した繊細なものたちを躊躇わず表現してみてください。', es: 'Tu cuidado atento conmueve profundamente a tu pareja hoy—Virgo nace con el don raro de notar lo que alguien necesita antes de que lo diga, y hoy ese don se traduce perfectamente en el lenguaje del amor. Los pequeños gestos se convierten en prueba indudable de un gran amor. Expresa sin dudar esas cosas delicadas que has preparado.' },
      { ko: '수성의 소통 에너지가 대화를 풍요롭게 합니다. 오늘 처녀자리의 말은 평소보다 더 정확하고 더 따뜻하게 상대의 마음에 닿습니다. 진심 어린 이야기가 관계를 한층 깊게 하는 이 순간, 오랫동안 전하고 싶었던 감사함이나 마음속에 담아두었던 이야기를 꺼내볼 때입니다.', en: 'Mercury\'s communication energy enriches conversations today, and Virgo\'s words reach your partner\'s heart more precisely and warmly than usual. This is the moment when heartfelt talks genuinely deepen the relationship—the ideal time to finally express the gratitude you\'ve been holding, or to share what you\'ve kept quietly inside. Your words will land exactly as you intend them.', zh: '水星的沟通能量让今天的对话更加丰富。处女座的话今天比平时更准确更温暖地触及对方的心。真心的交谈让关系更加深厚的此刻，是时候说出那些长期想表达的感谢，或分享心中珍藏的话语了——你的话将准确地传达你的意图。', ja: '水星のコミュニケーションエネルギーが会話を豊かにします。今日処女座の言葉は普段より正確に、そして温かく相手の心に届きます。真心のこもった話が関係をさらに深めるこの瞬間、長い間伝えたかった感謝や心の中に秘めていた話を打ち明けてみる時です。', es: 'La energía comunicativa de Mercurio enriquece las conversaciones hoy, y las palabras de Virgo llegan al corazón de tu pareja de manera más precisa y cálida que de costumbre. Este es el momento en que las charlas sinceras profundizan genuinamente la relación—el momento ideal para expresar finalmente la gratitud que has guardado, o para compartir lo que has mantenido en silencio.' },
      { ko: '당신의 진실되고 성실한 모습이 이성에게 큰 매력으로 다가옵니다. 처녀자리는 화려한 제스처보다 꾸준한 진정성으로 사랑받는데, 오늘 그 진정성이 강력한 자기장처럼 사람들을 끌어당깁니다. 꾸미거나 연출하지 않아도 됩니다—자연스럽게 빛나는 당신의 모습 그 자체가 가장 큰 매력입니다.', en: 'Your genuine and sincere nature is powerfully attractive today—Virgo is loved for steady authenticity more than flashy gestures, and right now that authenticity pulls people in like a strong magnet. You don\'t need to perform or embellish. Simply shine naturally as yourself, because in this moment your unfiltered realness is your most compelling quality, and the right person is already noticing it.', zh: '你真实而诚恳的样子今天对异性充满强大的吸引力。处女座因持续的真诚而非华丽的姿态而受到爱慕，今天那种真诚如强力磁场般吸引着人们。不需要装饰或表演——自然地作自己闪耀，那才是最大的魅力，合适的人已经在注意你了。', ja: 'あなたの誠実で真面目な姿が異性に大きな魅力として映ります。処女座は華やかなジェスチャーより一貫した誠実さで愛されますが、今日その誠実さが強力な磁場のように人々を引き付けます。飾ったり演出したりしなくていいです——自然に輝くあなたの姿そのものが最大の魅力であり、その場にいる正しい人はすでに気づいています。', es: 'Tu naturaleza genuina y sincera resulta poderosamente atractiva hoy—Virgo es amado por su autenticidad constante más que por gestos llamativos, y ahora esa autenticidad atrae a la gente como un imán poderoso. No necesitas actuar ni adornar. Simplemente brilla naturalmente como tú mismo, porque en este momento tu realidad sin filtros es tu cualidad más convincente.' },
      { ko: '실용적인 사랑 표현이 상대를 감동시킵니다. 처녀자리의 사랑은 말보다 행동에 있고, 그것이 오늘 가장 강력한 사랑의 언어가 됩니다. 건강한 도시락 하나가 장미 백 송이보다 빛나는 이유는—거기에 당신이 그 사람을 진심으로 생각했다는 증거가 담겨 있기 때문입니다.', en: 'Practical expressions of love move your partner deeply today—Virgo\'s love lives in actions more than words, and that is the most powerful love language available to you right now. A healthy lunch box outshines a hundred roses because it carries undeniable proof that you genuinely thought about that person. The care embedded in your practical gestures today will be felt long after the moment passes.', zh: '实用的爱情表达今天深深感动了对方。处女座的爱更多地存在于行动而非言语中，这就是今天最强大的爱之语言。一个健康便当比一百朵玫瑰更闪耀——因为其中蕴含着你真心思念对方的证明。今天你实际行动中蕴含的关怀，在那个时刻过后很久仍会被感受到。', ja: '実用的な愛の表現が相手を深く感動させます。処女座の愛は言葉より行動にあり、それが今日最も強力な愛の言語になります。健康的なお弁当一つがバラ百本より輝く理由は——そこにあなたがその人を真心から思ったという証拠が込められているからです。今日あなたの実用的なジェスチャーに込められた気遣いは、その瞬間が過ぎた後もずっと感じられるでしょう。', es: 'Las expresiones prácticas de amor conmueven profundamente a tu pareja hoy—el amor de Virgo vive en acciones más que en palabras, y eso es el lenguaje del amor más poderoso disponible para ti ahora. Un almuerzo saludable brilla más que cien rosas porque lleva la prueba innegable de que genuinamente pensaste en esa persona. El cuidado incorporado en tus gestos prácticos hoy se sentirá mucho después de que pase el momento.' },
      { ko: '오랫동안 관찰해온 상대와의 관계가 진전될 기회입니다. 처녀자리는 충분한 데이터를 모은 후에야 마음을 여는 편이지만, 오늘은 분석이 완료된 신호가 왔습니다—이제 행동할 때입니다. 분석을 멈추고 마음을 열어보세요. 준비가 완벽해질 때를 기다리다 보면 그 순간은 영원히 오지 않습니다.', en: 'A chance to advance things with someone you\'ve been observing for a long time—Virgo typically waits until enough data is gathered before opening the heart, but today the signal is clear that analysis is complete and action is called for. Stop analyzing and open your heart. If you keep waiting for perfect readiness, that moment will never arrive. The right time is now, imperfect as it may feel.', zh: '与长期观察的对象关系有进展的机会。处女座通常在收集了足够数据后才打开心扉，但今天完成分析的信号已经来了——是时候行动了。停止分析，打开心扉吧。一直等到准备完美的那一刻，那个时刻可能永远不会来。现在就是合适的时机，尽管感觉可能还不那么完美。', ja: '長い間観察してきた相手との関係が進展するチャンスです。処女座は通常十分なデータを集めてから心を開く傾向がありますが、今日は分析完了のシグナルが来ました——今こそ行動する時です。分析をやめて心を開いてみてください。完璧な準備ができる時を待ち続けると、その瞬間は永遠に来ません。', es: 'Una oportunidad de avanzar con alguien que has estado observando durante mucho tiempo—Virgo típicamente espera hasta reunir suficientes datos antes de abrir el corazón, pero hoy la señal está clara de que el análisis está completo y la acción es necesaria. Deja de analizar y abre tu corazón. Si sigues esperando la preparación perfecta, ese momento nunca llegará.' },
      { ko: '파트너의 필요를 먼저 알아차리는 당신의 능력이 사랑을 더욱 단단하게 만듭니다. 처녀자리는 상대방의 말투 변화, 작은 한숨, 평소와 다른 표정 하나에서 그 사람의 내면 상태를 읽어내는 독보적인 능력이 있습니다. 오늘 그 능력을 십분 발휘하여 상대가 미처 말하지 못한 것을 먼저 채워주세요.', en: 'Your ability to anticipate your partner\'s needs makes your love even stronger today—Virgo has an unmatched ability to read someone\'s inner state from subtle changes in tone, a small sigh, or an expression that\'s slightly different from usual. Use that gift fully today and fill what your partner hasn\'t yet managed to say out loud. That kind of preemptive care is the deepest form of being truly seen.', zh: '你先察觉伴侣需求的能力今天让爱情更加坚固。处女座有独特的能力，能从对方语气的细微变化、小小的叹息或与平时略有不同的表情中读出其内心状态。今天充分发挥那种能力，主动填补对方还未能说出口的需求——那种预先的关怀是被真正看见的最深形式。', ja: 'パートナーのニーズをいち早く察知するあなたの能力が愛をさらに強固にします。処女座は相手の話し方の変化、小さなため息、普段と違う表情一つから、その人の内面の状態を読み取る独自の能力があります。今日その能力を十分に発揮して、相手がまだ言葉にできていないことを先に埋めてあげてください。', es: 'Tu capacidad de anticipar las necesidades de tu pareja fortalece aún más el amor hoy—Virgo tiene una habilidad incomparable para leer el estado interior de alguien a partir de cambios sutiles en el tono, un pequeño suspiro, o una expresión ligeramente diferente a la usual. Usa ese don plenamente hoy y llena lo que tu pareja aún no ha logrado decir en voz alta.' },
      { ko: '신뢰를 기반으로 한 안정적인 관계가 꽃피는 시기입니다. 처녀자리의 사랑은 드라마틱한 감정의 파도보다 깊고 잔잔한 바다와 같아서, 그 깊이를 알아보는 사람은 평생 떠나지 않습니다. 함께 성장하는 기쁨을 느끼세요—오늘의 작은 공유가 내일의 단단한 연대가 됩니다.', en: 'A trust-based stable relationship blooms beautifully now—Virgo\'s love is like a deep, calm sea rather than dramatic emotional waves, and those who recognize its depth never want to leave. Feel the joy of growing together. The small sharing of today becomes the solid solidarity of tomorrow. What you are building with quiet dedication is something extraordinary.', zh: '以信任为基础的稳定关系如今绽放着美丽的花朵。处女座的爱如深邃平静的大海而非戏剧性的情感波涛，认识到其深度的人永远不会离去。感受一起成长的喜悦——今天的小小分享将成为明天坚固的联结。你们以安静的奉献建立的东西是非凡的。', ja: '信頼を基盤にした安定した関係が美しく花開く時期です。処女座の愛はドラマティックな感情の波よりも深く穏やかな海のようで、その深さを理解した人は生涯離れません。一緒に成長する喜びを感じてください——今日の小さな共有が明日の固い連帯になります。', es: 'Una relación estable basada en confianza florece bellamente ahora—el amor de Virgo es como un mar profundo y tranquilo más que olas emocionales dramáticas, y quienes reconocen su profundidad nunca quieren irse. Siente la alegría de crecer juntos. El pequeño compartir de hoy se convierte en la sólida solidaridad de mañana.' },
      { ko: '솔로라면 일상 속 만남에서 인연을 발견할 수 있습니다. 처녀자리의 인연은 화려한 파티나 앱보다 지적인 관심을 공유하는 조용한 공간에서 시작됩니다. 서점이나 강좌에서 눈을 밝히세요—비슷한 책을 집어드는 그 사람이 당신의 세계를 이해할 수 있는 사람일지도 모릅니다.', en: 'If single, you may find a meaningful connection in everyday encounters today—Virgo\'s relationships typically begin not at flashy parties or through apps, but in quiet spaces where intellectual interests are shared. Look around bookstores or classes with open eyes. The person reaching for the same book, sitting in the same workshop, may be someone who can genuinely understand your world.', zh: '如果单身，今天可能在日常邂逅中发现有意义的缘分。处女座的缘分通常不是在华丽的派对或应用程序中开始，而是在分享智识兴趣的安静空间里开始。在书店或课程中睁大眼睛——那个拿起同一本书的人，或许就是能理解你世界的那个人。', ja: 'シングルなら日常の出会いの中で意味のある縁を発見できます。処女座の縁は華やかなパーティーやアプリよりも、知的な関心を共有する静かな空間から始まる傾向があります。書店や講座で目を光らせてください——同じ本を手に取るその人が、あなたの世界を理解できる人かもしれません。', es: 'Si estás soltero/a, puedes encontrar una conexión significativa en encuentros cotidianos hoy—las relaciones de Virgo típicamente no comienzan en fiestas llamativas o a través de apps, sino en espacios tranquilos donde se comparten intereses intelectuales. Observa en librerías o clases con ojos abiertos. La persona que toma el mismo libro puede ser alguien que genuinamente entiende tu mundo.' },
      { ko: '흙 원소의 따뜻한 에너지가 관계에 안정감을 불어넣습니다. 오늘은 자연스럽고 포근한 사랑이 흐르는 날입니다. 화려하고 자극적인 사랑이 아닌, 함께 있는 것 자체가 충분히 좋은 그런 안정적인 사랑—그것이 처녀자리가 진정으로 원하고 또 줄 수 있는 사랑의 형태입니다.', en: 'Earth element\'s warm energy brings beautiful stability to your relationship today—a day where natural, cozy love flows freely. Not flashy or intense love, but the steady kind where simply being together is genuinely enough. This is the form of love Virgo truly wants and is capable of giving: grounded, consistent, and deeply reassuring. Let yourself rest in that warmth fully today.', zh: '土元素的温暖能量今天为关系注入美好的安全感。这是自然温馨的爱自然流淌的一天。不是华丽刺激的爱，而是仅仅在一起本身就足够美好的那种稳定的爱——这才是处女座真正渴望并能给予的爱的形式。今天让自己完全沉浸在那份温暖中。', ja: '土のエレメントの温かいエネルギーが関係に美しい安定感を吹き込みます。今日は自然で温かい愛が流れる日です。華やかで刺激的な愛ではなく、一緒にいること自体で十分に良い、そんな安定した愛——それが処女座が心から望み、また与えることができる愛の形です。今日その温かさに完全に浸ってみてください。', es: 'La energía cálida del elemento tierra trae hermosa estabilidad a tu relación hoy—un día donde fluye libremente un amor natural y acogedor. No un amor llamativo o intenso, sino el tipo constante donde simplemente estar juntos es genuinamente suficiente. Esta es la forma de amor que Virgo realmente quiere y es capaz de dar: arraigado, consistente y profundamente tranquilizador.' },
      { ko: '상대방의 건강과 일상을 챙기는 마음이 진정한 사랑으로 전해집니다. 처녀자리의 사랑 언어는 "충분히 자고 있어?" "오늘 밥은 먹었어?"라는 질문에 담겨 있습니다. 헌신이 빛나는 날인 오늘, 그 꼼꼼한 돌봄을 아끼지 마세요—상대방은 그 속에 담긴 당신의 깊은 사랑을 느끼고 있습니다.', en: 'Caring for your partner\'s health and daily life conveys true love today—Virgo\'s love language lives in questions like "Did you sleep enough?" and "Did you eat today?" Your devotion shines most brilliantly in these precise, practical acts of caring. Don\'t hold back that attentive nurturing today. Your partner feels the depth of love embedded in every small question and gesture you offer.', zh: '关心对方健康和日常的心意今天传达出真正的爱。处女座的爱之语言蕴含在"你睡够了吗？""今天吃饭了吗？"这样的问题中。奉献闪耀的今天，不要吝惜那份细心的关怀——对方正在感受到其中蕴含的你深深的爱。', ja: '相手の健康と日常を気遣う心が真の愛として伝わります。処女座の愛の言語は「十分に眠れている？」「今日ご飯食べた？」という問いかけに込められています。献身が輝く今日、その細やかな気遣いを惜しまないでください——相手はその中に込められたあなたの深い愛を感じています。', es: 'Cuidar la salud y el día a día de tu pareja transmite amor verdadero hoy—el lenguaje del amor de Virgo vive en preguntas como "¿Dormiste bien?" y "¿Comiste hoy?" Tu devoción brilla más brillantemente en estos actos precisos y prácticos de cuidado. No contengas esa atención nutridora hoy. Tu pareja siente la profundidad del amor incorporado en cada pequeña pregunta y gesto que ofreces.' },
    ],
    medium: [
      { ko: '안정적인 연애운입니다. 처녀자리는 화려한 이벤트보다 일상의 소소한 교감에서 진정한 친밀감을 쌓는 데 탁월합니다. 오늘 그 능력을 의식적으로 발휘해보세요—함께 마시는 커피 한 잔, 오늘 있었던 작은 이야기를 나누는 것이 어떤 대단한 이벤트보다 관계를 단단하게 만듭니다.', en: 'Stable love fortune today, and Virgo is particularly skilled at building genuine intimacy through small everyday connections rather than flashy events. Consciously exercise that skill today—sharing coffee together, exchanging small stories about the day, will make the relationship more solid than any grand gesture. The texture of daily life together is where Virgo love truly lives.', zh: '今天恋爱运稳定。处女座特别擅长通过日常的小交流而非华丽的活动来建立真正的亲密感。今天有意识地发挥那种能力——一起喝的咖啡，分享今天发生的小事，比任何盛大的活动都能让关系更加坚固。', ja: '安定した恋愛運です。処女座は華やかなイベントより日常のささやかな交流から真の親密感を積み上げるのに優れています。今日その能力を意識的に発揮してみてください——一緒に飲むコーヒー一杯、今日あった小さな話を分かち合うことが、どんな大したイベントより関係を固くします。', es: 'Fortuna amorosa estable hoy, y Virgo es particularmente hábil en construir intimidad genuina a través de pequeñas conexiones cotidianas más que eventos llamativos. Ejercita conscientemente esa habilidad hoy—compartir café juntos, intercambiar pequeñas historias del día, solidificará la relación más que cualquier gran gesto.' },
      { ko: '서로에 대한 이해를 쌓아가는 시기입니다. 처녀자리의 관계는 충분한 시간과 관찰을 통해 깊어지는 법입니다. 급하게 결론을 내리기보다 천천히 알아가세요—상대방이 어떤 맥락에서 어떤 선택을 하는지 관찰하는 것이 빠른 판단보다 훨씬 정확한 이해를 가져다줍니다.', en: 'A time to build mutual understanding—Virgo\'s relationships deepen through sufficient time and observation, not rushed conclusions. Get to know each other slowly and deliberately. Observing what choices your partner makes in what contexts will bring you far more accurate understanding than any rapid assessment. The patience you invest now pays compound interest in intimacy later.', zh: '积累彼此了解的时期。处女座的关系通过充足的时间和观察而加深，而非仓促的结论。不要急于下结论，慢慢地去了解——观察对方在什么情境下做什么选择，比快速判断带来更准确的理解。你现在投入的耐心之后会以亲密感的形式产生复利。', ja: 'お互いの理解を積み上げていく時期です。処女座の関係は十分な時間と観察を通じて深まるものです。急いで結論を出すよりゆっくり知り合ってください——相手がどんな文脈でどんな選択をするか観察することが、速い判断よりはるかに正確な理解をもたらします。今投資する忍耐が後で親密さとして複利を生みます。', es: 'Un momento para construir comprensión mutua—las relaciones de Virgo se profundizan a través de tiempo suficiente y observación, no de conclusiones apresuradas. Conócense lentamente y deliberadamente. Observar qué elecciones hace tu pareja en qué contextos te dará una comprensión mucho más precisa que cualquier evaluación rápida. La paciencia que inviertes ahora genera interés compuesto en intimidad más tarde.' },
      { ko: '상대의 작은 습관에 대해 지적하고 싶어질 수 있습니다. 처녀자리의 예리한 눈은 개선할 여지가 있는 것들을 자동으로 감지하는데, 그 능력을 사랑하는 사람에게 향하면 때로 부담이 됩니다. 한 번 참고 넘어가는 여유를 가지세요—지적하고 싶은 마음 대신 그 습관이 귀엽게 보이는 연습을 해보세요.', en: 'You may want to point out small habits today—Virgo\'s sharp eyes automatically detect things with room for improvement, but when that ability is directed at a loved one it can feel burdensome. Have the grace to let it go this one time. Instead of the urge to correct, try practicing seeing that habit as endearing. The relationship grows more when you choose appreciation over improvement.', zh: '今天可能想指出对方的小习惯。处女座敏锐的眼睛会自动发现有改进余地的事情，但当那种能力指向爱人时有时会造成负担。给自己一点忍耐和宽容的空间——不要指出，试着练习把那个习惯看作可爱的一面。选择欣赏而非改进时，关系会更加成长。', ja: '相手の小さな習慣を指摘したくなるかもしれません。処女座の鋭い目は改善の余地があるものを自動的に感知しますが、その能力を愛する人に向けると時に負担になります。一度我慢して見過ごす余裕を持ちましょう——指摘したい気持ちの代わりに、その習慣が可愛らしく見える練習をしてみてください。改善より感謝を選ぶ時、関係はより成長します。', es: 'Puede que quieras señalar pequeños hábitos hoy—los ojos agudos de Virgo detectan automáticamente cosas con margen de mejora, pero cuando esa habilidad se dirige a un ser querido puede sentirse como una carga. Ten la gracia de dejarlo pasar esta vez. En lugar del impulso de corregir, intenta practicar ver ese hábito como adorable. La relación crece más cuando eliges la apreciación sobre la mejora.' },
      { ko: '평화로운 시간이 관계를 유지하는 힘이 됩니다. 처녀자리에게 함께 무언가를 만들거나 준비하는 실용적인 공유 활동이 최고의 데이트입니다. 함께 요리하거나 산책하는 시간을 가져보세요—그 과정에서 나누는 이야기와 작은 웃음이 관계의 가장 아름다운 기억이 됩니다.', en: 'Peaceful moments sustain your relationship today—for Virgo, practical shared activities like creating or preparing something together make the best dates. Try cooking together or taking a walk. The conversations and small laughter that emerge during that process become the most beautiful memories of the relationship. Shared tasks are Virgo\'s version of romance, and they work beautifully.', zh: '平和的时光是维系关系的力量。对处女座来说，一起创造或准备某些事情这样实际的共享活动是最好的约会。试着一起做饭或散步——在那个过程中分享的话语和小小的笑声，成为关系中最美好的记忆。共同任务是处女座版本的浪漫，而且效果很好。', ja: '平和な時間が関係を維持する力になります。処女座にとって一緒に何かを作ったり準備する実用的な共有活動が最高のデートです。一緒に料理したり散歩する時間を持ってみてください——その過程で交わす話や小さな笑いが関係の最も美しい記憶になります。共同作業が処女座版のロマンスであり、それは美しく機能します。', es: 'Los momentos pacíficos sostienen tu relación hoy—para Virgo, las actividades compartidas prácticas como crear o preparar algo juntos hacen las mejores citas. Intenten cocinar juntos o pasear. Las conversaciones y pequeñas risas que emergen durante ese proceso se convierten en los recuerdos más hermosos de la relación. Las tareas compartidas son la versión de romance de Virgo, y funcionan maravillosamente.' },
      { ko: '감정 표현이 서툴더라도 행동으로 보여주는 당신의 사랑은 충분히 전달되고 있습니다. 처녀자리는 "사랑해"라는 말보다 "약 챙겨 먹었어?"로 사랑을 표현하는 사람입니다. 그 방식이 덜 낭만적으로 보일 수 있지만, 사실 가장 일관되고 신뢰할 수 있는 사랑의 형태입니다—그리고 상대방은 그것을 알고 있습니다.', en: 'Even if you struggle with emotional expression, your love shown through actions is getting through completely—Virgo expresses love more through "Did you take your medication?" than "I love you," and while that may seem less romantic, it is actually the most consistent and trustworthy form of love. Your partner knows this, even if they don\'t always say so. Your actions speak clearly.', zh: '即使不善于表达感情，你用行动展现的爱已经充分传达了。处女座是用"药吃了吗？"而非"我爱你"来表达爱的人。这种方式看起来可能不那么浪漫，但实际上是最一致、最可信赖的爱的形式——而且对方知道这一点，即使他们并不总是说出来。你的行动表达得很清楚。', ja: '感情表現が苦手でも行動で示すあなたの愛は十分に伝わっています。処女座は「愛してる」より「薬ちゃんと飲んだ？」で愛を表現する人です。その方式がロマンティックに見えないかもしれませんが、実は最も一貫していて信頼できる愛の形です——そして相手はそれを知っています。たとえいつも言葉にしなくても。', es: 'Aunque te cueste expresar emociones, tu amor mostrado en acciones se transmite completamente—Virgo expresa el amor más a través de "¿Tomaste tu medicamento?" que de "Te amo," y aunque eso pueda parecer menos romántico, es en realidad la forma de amor más consistente y confiable. Tu pareja lo sabe, aunque no siempre lo diga. Tus acciones hablan con claridad.' },
      { ko: '관계에서 완벽을 추구하기보다 서로의 불완전함을 받아들이는 연습이 필요한 시기입니다. 처녀자리는 이상적인 관계의 청사진을 머릿속에 가지고 있는데, 그 청사진과 현실의 간극이 불만족의 원천이 될 수 있습니다. 불완전한 현실 속에서도 진정한 연결을 발견하는 것이 더 성숙한 사랑입니다.', en: 'A time to practice accepting each other\'s imperfections rather than seeking perfection in the relationship—Virgo carries a detailed blueprint of an ideal relationship in mind, and the gap between that blueprint and reality can become a source of dissatisfaction. Discovering genuine connection within imperfect reality is the more mature form of love, and it is far more sustainable than chasing an ideal that constantly recedes.', zh: '这是练习接受彼此的不完美而非在关系中追求完美的时期。处女座脑中有一份理想关系的详细蓝图，那份蓝图与现实的差距可能成为不满的来源。在不完美的现实中发现真正的连结是更成熟的爱，比追逐不断后退的理想更可持续。', ja: '関係で完璧を追求するより、お互いの不完全さを受け入れる練習が必要な時期です。処女座は理想的な関係の設計図を頭の中に持っていますが、その設計図と現実のギャップが不満の源になり得ます。不完全な現実の中でも真のつながりを発見することがより成熟した愛であり、常に後退し続ける理想を追うよりはるかに持続可能です。', es: 'Es momento de practicar aceptar las imperfecciones mutuas en vez de buscar la perfección en la relación—Virgo lleva en mente un plano detallado de la relación ideal, y la brecha entre ese plano y la realidad puede convertirse en una fuente de insatisfacción. Descubrir conexión genuina dentro de la realidad imperfecta es la forma más madura de amor, y es mucho más sostenible que perseguir un ideal que constantemente retrocede.' },
      { ko: '연인에게 조언을 할 때 비판이 아닌 응원의 언어를 선택하세요. 처녀자리의 조언은 종종 정확하지만, 그 정확함이 때로 상대에게 상처가 될 수 있습니다. 말 한마디가 관계를 바꿉니다—같은 내용도 "왜 이렇게 했어?"가 아닌 "이렇게 하면 어떨까?"로 표현하는 연습을 해보세요.', en: 'When advising your partner today, consciously choose encouraging words over criticism—Virgo\'s advice is often accurate, but that accuracy can sometimes wound. One word truly changes the relationship. Practice expressing the same content as "What if you tried it this way?" rather than "Why did you do it like that?" The wisdom stays the same; the reception becomes completely different.', zh: '今天给恋人建议时，有意识地选择鼓励而非批评的语言。处女座的建议通常很准确，但那种准确性有时会伤害对方。一句话可以改变关系——练习用"如果这样做会怎么样？"而非"你为什么这么做？"来表达同样的内容。智慧不变，接受方式却完全不同。', ja: '恋人にアドバイスする時、批判ではなく応援の言葉を意識的に選んでください。処女座のアドバイスはしばしば正確ですが、その正確さが時に相手を傷つけることがあります。一言が関係を変えます——同じ内容でも「なぜこうしたの？」ではなく「こうしてみたらどうかな？」と表現する練習をしてみてください。知恵は同じで、受け取られ方は全く変わります。', es: 'Al aconsejar a tu pareja hoy, elige conscientemente palabras de aliento sobre crítica—el consejo de Virgo suele ser preciso, pero esa precisión a veces puede herir. Una palabra realmente cambia la relación. Practica expresar el mismo contenido como "¿Qué pasaría si lo intentaras de esta manera?" en lugar de "¿Por qué lo hiciste así?" La sabiduría se mantiene igual; la recepción se vuelve completamente diferente.' },
      { ko: '혼자만의 시간과 함께하는 시간의 균형을 잘 맞추는 것이 오늘의 과제입니다. 처녀자리는 혼자서 생각을 정리하고 에너지를 회복하는 시간이 필요한 경향이 있습니다. 그 필요를 솔직하게 표현하는 것이 관계에 더 좋습니다—혼자 있고 싶은 것이 상대를 사랑하지 않아서가 아님을 설명해보세요.', en: 'Balancing alone time and time together is today\'s key task—Virgo tends to need time alone to organize thoughts and restore energy, and that is perfectly healthy. Expressing that need honestly is better for the relationship than silently withdrawing. Explain that wanting solitude is not about loving your partner less. A partner who understands this becomes a true ally.', zh: '今天的关键课题是平衡好独处时间和共处时间。处女座倾向于需要独处时间来整理思绪和恢复能量，这是完全健康的。坦诚表达那种需求比默默疏远对关系更好——解释说想要独处不是因为不爱对方。理解这一点的伴侣将成为真正的盟友。', ja: '一人の時間と一緒の時間のバランスをうまく取ることが今日の課題です。処女座は一人で考えを整理してエネルギーを回復する時間が必要な傾向があります。その必要性を正直に表現することが関係にとってより良いです——一人でいたいことが相手を愛していないからではないことを説明してみてください。これを理解するパートナーが真の味方になります。', es: 'Equilibrar el tiempo a solas y el tiempo juntos es la tarea clave de hoy—Virgo tiende a necesitar tiempo solo para organizar pensamientos y restaurar energía, y eso es perfectamente saludable. Expresar esa necesidad honestamente es mejor para la relación que retirarse en silencio. Explica que querer soledad no se trata de amar menos a tu pareja. Un compañero que entiende esto se convierte en un aliado real.' },
      { ko: '현실적인 기대를 가지되 로맨스를 완전히 포기하지는 마세요. 처녀자리의 현실적 감각은 관계의 장기적 안정을 위해 필요하지만, 그것이 삶에서 마법을 완전히 제거해서는 안 됩니다. 실용과 낭만은 공존할 수 있습니다—계획적 낭만도 여전히 낭만입니다.', en: 'Have realistic expectations but don\'t give up romance entirely—Virgo\'s realistic sensibility is necessary for the long-term stability of relationships, but it shouldn\'t eliminate all magic from life. Practicality and romance can genuinely coexist. A planned romantic gesture is still romantic. Schedule beauty into your relationship the same way you schedule everything else, and watch it bloom.', zh: '保持现实的期望，但不要完全放弃浪漫。处女座现实的感觉对关系的长期稳定很有必要，但它不应该完全消除生活中的魔法。实用和浪漫可以真正共存。有计划的浪漫举动依然是浪漫。像安排其他事情一样在关系中安排美好，看着它绽放。', ja: '現実的な期待を持ちつつロマンスを完全に諦めないでください。処女座の現実的な感覚は関係の長期的安定のために必要ですが、それが人生からすべての魔法を取り除くべきではありません。実用と浪漫は本当に共存できます。計画的なロマンティックなジェスチャーもまだロマンティックです。他の全てをスケジューリングするように、関係に美しさをスケジューリングしてみてください。', es: 'Ten expectativas realistas pero no renuncies al romance por completo—el sentido realista de Virgo es necesario para la estabilidad a largo plazo de las relaciones, pero no debería eliminar toda la magia de la vida. Lo práctico y lo romántico pueden genuinamente coexistir. Un gesto romántico planificado sigue siendo romántico. Programa la belleza en tu relación de la misma manera que programas todo lo demás, y observa cómo florece.' },
      { ko: '수성의 에너지가 소통을 부드럽게 합니다. 평소 하지 못했던 이야기를 꺼내보기 좋은 날입니다. 마음속에서 맴돌던 미완성 대화들이 오늘 자연스럽게 흘러나올 수 있습니다—상대방이 먼저 말할 때까지 기다리지 말고, 처녀자리의 정확한 표현 능력을 이 귀한 기회에 활용해보세요.', en: 'Mercury\'s energy smooths communication today, making it a good day to bring up things you haven\'t been able to say. The unfinished conversations circling in your mind can naturally surface now. Don\'t wait for your partner to speak first—use Virgo\'s precise expressive ability in this precious opportunity. The words you find today could resolve something that has been quietly weighing on the relationship.', zh: '水星的能量今天让沟通更加顺畅，是说出平时没能说的话的好日子。心中盘旋的未完成对话今天可能自然浮现——不要等对方先开口，在这个珍贵机会中充分利用处女座精确的表达能力。今天找到的话语可能化解一直在悄悄影响关系的事情。', ja: '水星のエネルギーがコミュニケーションを滑らかにします。普段できなかった話を切り出すのに良い日です。心の中でぐるぐると回っていた未完成の会話が今日自然に流れ出てくるかもしれません——相手が先に話すまで待たずに、処女座の正確な表現能力をこの貴重な機会に活用してみてください。', es: 'La energía de Mercurio suaviza la comunicación hoy, siendo un buen día para traer a colación lo que no has podido decir. Las conversaciones incompletas que circulan en tu mente pueden emerger naturalmente ahora. No esperes a que tu pareja hable primero—usa la capacidad expresiva precisa de Virgo en esta preciosa oportunidad. Las palabras que encuentres hoy podrían resolver algo que ha estado pesando silenciosamente sobre la relación.' },
    ],
    low: [
      { ko: '상대의 단점이 유독 눈에 띄는 날입니다. 처녀자리의 분석적 눈은 오늘 모든 불완전함을 고해상도로 보여주고 있지만, 그 렌즈는 동시에 장점도 똑같이 선명하게 볼 수 있습니다. 비판하기 전에 세 번 생각하고, 상대방이 가진 아름다운 면들을 의식적으로 떠올려보세요—당신이 무엇에 집중하느냐가 관계의 현실을 만들어냅니다.', en: 'Your partner\'s flaws stand out today—Virgo\'s analytical eye is showing every imperfection in high resolution, but that same lens can see strengths with equal clarity if you choose to use it that way. Think three times before criticizing and deliberately recall the beautiful aspects your partner holds. What you focus on creates the reality of your relationship, so choose your focus with care.', zh: '对方的缺点今天格外明显。处女座的分析眼光今天以高清晰度显示每一个不完美，但同样的镜头也能同样清晰地看到优点，如果你选择那样使用它的话。批评前三思，有意识地回想对方拥有的美好之处——你专注于什么，就会创造关系的现实。', ja: '相手の短所が特に目につく日です。処女座の分析的な目が今日すべての不完全さを高解像度で見せていますが、そのレンズは選択次第で長所も同じく鮮明に見ることができます。批判する前に三度考えて、相手の持つ美しい面を意識的に思い出してみてください——何に集中するかが関係の現実を作り出します。', es: 'Los defectos de tu pareja destacan especialmente hoy—el ojo analítico de Virgo está mostrando cada imperfección en alta resolución, pero ese mismo lente puede ver las fortalezas con igual claridad si eliges usarlo de esa manera. Piensa tres veces antes de criticar y deliberadamente recuerda los aspectos hermosos de tu pareja. Lo que eliges enfocar crea la realidad de tu relación.' },
      { ko: '완벽한 파트너는 존재하지 않습니다. 처녀자리는 관계의 이상적인 기준을 매우 높게 설정하는 경향이 있는데, 그 기준이 현실의 상대방을 영원히 부족하게 만들 수 있습니다. 이상과 현실 사이의 간극을 인정해야 마음이 편해집니다—불완전한 사람을 완전하게 사랑하는 것이 사랑의 진정한 의미입니다.', en: 'The perfect partner doesn\'t exist—Virgo tends to set idealized standards for relationships very high, and those standards can make real partners permanently feel insufficient. Accepting the gap between ideal and reality is what brings genuine peace of mind. Loving an imperfect person completely is the true meaning of love, and it requires choosing them as they are, not as you wish they were.', zh: '完美的伴侣不存在。处女座倾向于为关系设定非常高的理想化标准，而那些标准可能让真实的伴侣永远感到不够好。承认理想与现实之间的差距才能真正心安——完整地爱一个不完美的人才是爱的真正含义，这需要选择他们本来的样子，而非你希望他们成为的样子。', ja: '完璧なパートナーは存在しません。処女座は関係の理想的な基準を非常に高く設定する傾向があり、その基準が現実の相手を永遠に不十分に感じさせる可能性があります。理想と現実のギャップを認めることで心が楽になります——不完全な人を完全に愛することが愛の真の意味であり、それは彼らがなってほしい姿ではなくありのままの姿を選ぶことを必要とします。', es: 'La pareja perfecta no existe—Virgo tiende a establecer estándares muy altos para las relaciones, y esos estándares pueden hacer que las parejas reales se sientan permanentemente insuficientes. Aceptar la brecha entre ideal y realidad es lo que trae genuina paz mental. Amar completamente a una persona imperfecta es el verdadero significado del amor, y requiere elegirlos como son, no como desearías que fueran.' },
      { ko: '감정 표현을 미루다 오해가 생길 수 있습니다. 처녀자리는 감정을 논리로 포장하는 경향이 있는데, 오늘 그 포장이 상대에게 차갑게 느껴질 수 있습니다. 논리적 설명 대신 솔직한 감정을 전달해보세요—"나는 이래서 그렇다"보다 "나는 이런 감정이 들었어"가 더 깊이 닿습니다.', en: 'Delaying emotional expression may cause misunderstandings today—Virgo tends to wrap feelings in logic, and today that wrapping can feel cold to your partner. Share honest feelings instead of logical explanations. "I felt hurt when..." lands far deeper than "The reason I reacted was because..." Emotional vulnerability is not a weakness; it is the key that opens genuine connection.', zh: '推迟情感表达今天可能产生误解。处女座倾向于用逻辑包装情感，今天那种包装可能让对方感到冷漠。试着传达真诚的感受而非逻辑解释——"我有这样的感受"比"我是因为这个才这样"触动更深。情感脆弱不是弱点，而是打开真正连结的钥匙。', ja: '感情表現を先延ばしにするとお互いの誤解が生じる可能性があります。処女座は感情を論理で包む傾向がありますが、今日その包みが相手には冷たく感じられる可能性があります。論理的な説明より素直な感情を伝えてみてください——「だから私はこうなんだ」より「こんな感情を感じた」の方がずっと深く届きます。感情的脆弱さは弱さではなく、真のつながりを開く鍵です。', es: 'Retrasar la expresión emocional puede causar malentendidos hoy—Virgo tiende a envolver los sentimientos en lógica, y hoy ese envoltorio puede sentirse frío para tu pareja. Comparte sentimientos honestos en lugar de explicaciones lógicas. "Me sentí herido cuando..." llega mucho más profundo que "La razón por la que reaccioné fue porque..." La vulnerabilidad emocional no es debilidad; es la llave que abre la conexión genuina.' },
      { ko: '잔소리가 사랑에서 비롯된 것이라도 상대에겐 부담이 될 수 있습니다. 처녀자리의 걱정과 지적은 진심으로 상대를 위하는 마음에서 나오지만, 받아들이는 쪽에서는 신뢰받지 못한다는 느낌으로 다가올 수 있습니다. 오늘은 지켜보는 사랑을 연습하세요—말하지 않고도 지지할 수 있습니다.', en: 'Even loving nagging can burden your partner today—Virgo\'s worry and correction come from a genuinely caring place, but from the receiving end it can feel like not being trusted. Practice watchful love today: support without speaking, believe without verifying, trust without controlling. Silence can be the most powerful form of love when it comes from faith rather than indifference.', zh: '即使唠叨出于爱，今天对方也可能感到负担。处女座的担心和指正来自真诚关心对方的心，但从接受者的角度来看，可能感觉像是不被信任。今天练习默默守护的爱——不说话也能支持，不核实也能相信，不控制也能信任。当沉默来自信任而非漠不关心时，它可以是最强大的爱的形式。', ja: 'お小言が愛からのものでも相手には今日負担になり得ます。処女座の心配と指摘は真心から相手を思う気持ちから来ていますが、受け取る側には信頼されていないという感覚として伝わる可能性があります。今日は見守る愛を練習してください——言葉なしでも支えられます。確認しなくても信じられます。コントロールしなくても信頼できます。', es: 'Incluso regañar con amor puede agobiar a tu pareja hoy—la preocupación y la corrección de Virgo vienen de un lugar genuinamente cuidadoso, pero desde el extremo receptor puede sentirse como no ser confiado. Practica el amor observador hoy: apoya sin hablar, cree sin verificar, confía sin controlar. El silencio puede ser la forma más poderosa de amor cuando viene de la fe en lugar de la indiferencia.' },
      { ko: '관계를 분석하느라 정작 감정을 느끼지 못하고 있을 수 있습니다. 처녀자리는 관계 문제를 데이터처럼 처리하는 경향이 있는데, 분석은 답을 줄 수 있지만 온기는 줄 수 없습니다. 머리를 쉬고 가슴으로 느끼세요—오늘만큼은 이해보다 경험을 우선하는 연습을 해보세요.', en: 'You might be too busy analyzing the relationship to actually feel emotions today—Virgo tends to process relationship issues like data, and while analysis can provide answers, it cannot provide warmth. Rest your mind and feel with your heart. Just for today, practice prioritizing experience over understanding. The feeling itself is the information you actually need right now, not the explanation of it.', zh: '今天可能因为分析关系而忽略了真正感受情感。处女座倾向于像处理数据一样处理关系问题，而分析虽然能给出答案，却无法给出温暖。让大脑休息，用心感受——就今天，练习优先体验而非理解。感受本身才是你现在真正需要的信息，而不是对它的解释。', ja: '関係を分析するあまり実際の感情を感じていないかもしれません。処女座は関係の問題をデータのように処理する傾向がありますが、分析は答えを与えられても温もりは与えられません。頭を休めて心で感じてください——今日だけは理解より経験を優先する練習をしてみてください。感情そのものが今実際に必要な情報であり、その説明ではありません。', es: 'Quizás estés demasiado ocupado analizando la relación para realmente sentir emociones hoy—Virgo tiende a procesar los problemas de relación como datos, y mientras el análisis puede dar respuestas, no puede dar calor. Descansa la mente y siente con el corazón. Solo por hoy, practica priorizar la experiencia sobre la comprensión. El sentimiento en sí mismo es la información que realmente necesitas ahora, no la explicación de él.' },
      { ko: '자기비판이 연인 관계에도 영향을 줄 수 있습니다. 처녀자리가 자신에게 너무 가혹할 때, 그 가혹함은 결국 상대방에게도 튀어나오게 됩니다. 자신을 사랑하는 것이 타인을 사랑하는 출발점입니다—오늘 한 가지만 실천해보세요: 자신에게 친구에게 하듯 따뜻하게 말해보세요.', en: 'Self-criticism can affect your romantic relationship today too—when Virgo is too harsh with themselves, that harshness eventually spills onto their partner as well. Loving yourself is genuinely the starting point of loving others. Try just one practice today: speak to yourself the way you would speak to a dear friend who was struggling. That warmth you extend inward will flow outward naturally.', zh: '今天自我批评也会影响恋爱关系。当处女座对自己太苛刻时，那种苛刻最终也会溢出到对方身上。爱自己真的是爱他人的起点——今天只练习一件事：像对待一个正在挣扎的亲密朋友那样温柔地和自己说话。你向内延伸的那份温暖将自然地向外流动。', ja: '自己批判が恋人関係にも影響を与える可能性があります。処女座が自分に対して厳しすぎる時、その厳しさは結局相手にも飛び出てきます。自分を愛することが他人を愛する出発点です——今日一つだけ実践してみてください：苦しんでいる親友に話しかけるように自分に温かく話しかけてみてください。内側に向けたその温もりが自然に外側へ流れていきます。', es: 'La autocrítica puede afectar tu relación romántica hoy también—cuando Virgo es demasiado duro consigo mismo, esa dureza eventualmente se derrama hacia su pareja también. Amarte genuinamente es el punto de partida para amar a otros. Intenta solo una práctica hoy: háblate de la manera en que le hablarías a un querido amigo que estuviera luchando. Esa calidez que extiendes hacia adentro fluirá hacia afuera naturalmente.' },
      { ko: '사소한 일로 다툼이 생길 수 있습니다. 처녀자리는 옳고 그름에 대한 강한 감각을 가지고 있는데, 관계에서 그 감각이 항상 도움이 되는 것은 아닙니다. 옳고 그름을 따지기보다 관계의 평화를 선택하세요—이기는 것과 사랑받는 것은 종종 반대 방향을 가리킵니다.', en: 'Arguments over trivial matters may arise today—Virgo has a strong sense of right and wrong, but in relationships that sense doesn\'t always help. Choose relationship peace over being right. Winning and being loved often point in opposite directions. The person who can let go of needing to be right in the small moments builds something far more valuable than the satisfaction of any single argument won.', zh: '今天可能因小事发生争吵。处女座对对错有强烈的感知，但在关系中那种感知并不总是有帮助的。与其分对错，不如选择关系的和平——赢得争论和被爱往往指向相反的方向。能够在小事上放弃证明自己正确的人，比赢得任何单次争吵的满足感建立了更有价值的东西。', ja: '些細なことで口論が生じる可能性があります。処女座は正しいか間違っているかについての強い感覚を持っていますが、関係においてその感覚が常に助けになるわけではありません。正しさを追求するより関係の平和を選んでください——勝つことと愛されることはしばしば反対方向を指します。小さな瞬間に正しさを必要とすることを手放せる人が、どんな口論に勝つ満足感よりはるかに価値あるものを築きます。', es: 'Pueden surgir discusiones por trivialidades hoy—Virgo tiene un fuerte sentido de lo correcto e incorrecto, pero en las relaciones ese sentido no siempre ayuda. Elige la paz de la relación sobre tener razón. Ganar y ser amado a menudo apuntan en direcciones opuestas. La persona que puede soltar la necesidad de tener razón en los pequeños momentos construye algo mucho más valioso que la satisfacción de cualquier argumento ganado.' },
      { ko: '오늘은 연애보다 자기 치유에 집중하는 것이 좋겠습니다. 비워진 컵으로는 다른 사람에게 줄 수 없습니다. 혼자만의 시간이 관계에도 도움이 됩니다—오늘 자신을 위한 회복의 시간을 충분히 가지면, 내일 더 따뜻하고 온전한 모습으로 상대방 곁에 있을 수 있습니다.', en: 'Better to focus on self-healing than romance today—you cannot pour from an empty cup, and Virgo\'s careful nurturing of others sometimes leaves themselves depleted. Alone time genuinely helps the relationship. Give yourself sufficient recovery time today and you will be able to be beside your partner tomorrow in a warmer, more whole way. Replenishing yourself is an act of love for both of you.', zh: '今天最好专注于自我疗愈而非恋爱。空杯子无法倒给别人。处女座对他人细心的呵护有时会让自己精疲力竭。独处时间对关系真的有帮助——今天给自己足够的恢复时间，明天就能以更温暖、更完整的状态陪伴在对方身边。补充自己是对你们双方的爱的行为。', ja: '今日は恋愛より自己治癒に集中した方が良さそうです。空のコップからは他の人に与えることができません。処女座の他者への丁寧な気遣いが時に自分自身を枯渇させます。一人の時間が関係にも本当に助けになります——今日自分のための回復の時間を十分に取れば、明日より温かく完全な姿でパートナーのそばにいられます。', es: 'Mejor enfocarse en la sanación propia que en el romance hoy—no puedes verter desde una copa vacía, y el cuidadoso cuidado de Virgo hacia los demás a veces los deja agotados. El tiempo a solas genuinamente ayuda a la relación. Date suficiente tiempo de recuperación hoy y podrás estar junto a tu pareja mañana de una manera más cálida y completa. Reponerte es un acto de amor para ambos.' },
      { ko: '수성의 불안정한 에너지가 소통에 오류를 만들 수 있습니다. 오늘 주고받는 문자나 메시지가 원래 의도와 다르게 읽힐 가능성이 높습니다. 문자보다 직접 만나서 이야기하세요—목소리의 온도와 표정이 있어야 처녀자리의 정확한 마음이 온전히 전달됩니다.', en: 'Mercury\'s unstable energy may cause communication errors today—messages you send and receive have a high chance of being read differently than intended. Talk in person rather than by text whenever possible. Virgo\'s precise mind is best conveyed when the temperature of your voice and your expressions are present. Tone carries meaning that text strips away, and today that matters more than usual.', zh: '水星不稳定的能量今天可能导致沟通失误。今天收发的短信或消息很可能被读成与原本意图不同的含义。比起短信，尽可能直接见面聊聊——需要声音的温度和表情，处女座精准的心意才能完整传达。语气携带着文字剥离的含义，今天这一点比平时更加重要。', ja: '水星の不安定なエネルギーがコミュニケーションにエラーを起こす可能性があります。今日やり取りするメッセージが本来の意図と違って読まれる可能性が高いです。メッセージより直接会って話してください——声の温度と表情があってこそ処女座の正確な心が完全に伝わります。トーンはテキストが奪い去る意味を運び、今日それはいつも以上に重要です。', es: 'La energía inestable de Mercurio puede causar errores de comunicación hoy—los mensajes que envías y recibes tienen alta probabilidad de leerse de manera diferente a la intención. Habla en persona en lugar de por texto cuando sea posible. La mente precisa de Virgo se comunica mejor cuando la temperatura de tu voz y tus expresiones están presentes. El tono lleva un significado que el texto elimina, y hoy eso importa más de lo usual.' },
      { ko: '상대를 고치려는 마음을 내려놓으세요. 처녀자리에게 개선 가능성은 가능성이지만, 상대방에게는 "나는 지금 충분하지 않다"는 메시지로 들릴 수 있습니다. 있는 그대로를 존중하는 것이 진정한 사랑입니다—상대방의 성장은 당신이 안전하게 느끼게 해줄 때 저절로 일어납니다.', en: 'Let go of the desire to fix your partner today—to Virgo, spotting improvement potential is simply accurate observation, but to your partner it can land as "I am not enough as I am." Respecting them exactly as they are is true love. Your partner\'s growth happens naturally when you make them feel safe, not when you point out what needs changing. Trust them to find their own way.', zh: '今天放下想改变对方的心。对处女座来说，发现改进的可能性只是准确的观察，但对对方来说可能听成"我现在还不够好"。尊重对方原本的样子才是真正的爱——当你让对方感到安全时，他们的成长自然而然地发生，而不是当你指出需要改变的地方时。相信他们能找到自己的方向。', ja: '相手を直そうとする気持ちを手放してください。処女座にとって改善の可能性を見つけることは単なる正確な観察ですが、相手には「私は今のままでは十分ではない」というメッセージとして届く可能性があります。ありのままを尊重することが真の愛です——相手の成長はあなたが安全に感じさせてくれる時に自然に起こります。変える必要があることを指摘する時ではありません。', es: 'Deja de querer cambiar a tu pareja hoy—para Virgo, detectar potencial de mejora es simplemente observación precisa, pero para tu pareja puede llegar como "No soy suficiente tal como soy." Respetarlos exactamente como son es el verdadero amor. El crecimiento de tu pareja ocurre naturalmente cuando los haces sentir seguros, no cuando señalas lo que necesita cambiar. Confía en que encontrarán su propio camino.' },
    ],
  },
  career: {
    high: [
      { ko: '분석력이 극대화되어 복잡한 프로젝트의 핵심을 꿰뚫는 날입니다. 오늘 처녀자리의 사고는 마치 정밀 레이저처럼 작동하여 다른 사람들이 보지 못하는 패턴과 해결책을 선명하게 보여줍니다. 동료들이 당신의 통찰에 감탄하는 것을 두려워하지 말고 적극적으로 그 분석을 공유하세요.', en: 'Your analytical power peaks today, piercing the core of complex projects like a precision laser revealing patterns and solutions others simply cannot see. Today\'s Virgo thinking is operating at its clearest and sharpest. Don\'t hesitate to share that analysis actively—colleagues will admire your insight, and that admiration is both deserved and professionally valuable. Speak your findings with confidence.', zh: '分析力达到极致，洞穿复杂项目的核心。今天处女座的思维像精密激光一样运作，清晰地展示他人看不见的模式和解决方案。不要犹豫积极分享那些分析——同事们会对你的洞察赞叹不已，那种赞叹是你应得的，也具有职业价值。', ja: '分析力が最大化され複雑なプロジェクトの核心を貫く日です。今日処女座の思考は精密レーザーのように機能し、他の人が見えないパターンと解決策を鮮明に見せてくれます。同僚があなたの洞察に感嘆するのを恐れずに積極的にその分析を共有してください。', es: 'Tu poder analítico alcanza su máximo hoy, penetrando el núcleo de proyectos complejos como un láser de precisión que revela patrones y soluciones que otros simplemente no pueden ver. No dudes en compartir ese análisis activamente—tus colegas admirarán tu perspicacia, y esa admiración es tanto merecida como profesionalmente valiosa.' },
      { ko: '꼼꼼하게 작성한 보고서나 기획안이 상사에게 높은 평가를 받을 수 있습니다. 처녀자리가 놓치지 않는 세부사항과 데이터의 일관성이 오늘 의사결정자의 눈에 확실하게 들어옵니다. 당신의 작업물이 돋보이는 이 기회를 최대한 활용하세요—오늘 제출하는 것은 단순한 서류가 아니라 당신의 역량을 증명하는 명함입니다.', en: 'Your carefully prepared report or proposal may receive high praise from superiors today—the details and data consistency that Virgo never misses will clearly catch decision-makers\' eyes right now. Maximize this opportunity where your work stands out. What you submit today is not just a document; it is a business card that proves your capability. Present it with the confidence it deserves.', zh: '精心撰写的报告或企划案今天可能获得上司的高度评价。处女座从不遗漏的细节和数据一致性，今天将清晰地进入决策者的视野。最大限度地利用你的工作脱颖而出的这个机会——今天提交的不只是一份文件，而是证明你能力的名片。', ja: '丁寧に作成したレポートや企画が上司から高い評価を受ける可能性があります。処女座が見逃さない細部とデータの一貫性が今日意思決定者の目に確実に入ります。あなたの成果物が際立つこの機会を最大限に活用してください——今日提出するものは単なる書類ではなく、あなたの能力を証明する名刺です。', es: 'Tu informe o propuesta cuidadosamente preparada puede recibir altas evaluaciones de superiores hoy—los detalles y la consistencia de datos que Virgo nunca pierde captarán claramente la atención de los tomadores de decisiones ahora mismo. Maximiza esta oportunidad donde tu trabajo destaca. Lo que presentas hoy no es solo un documento; es una tarjeta de presentación que prueba tu capacidad.' },
      { ko: '수성의 에너지가 프레젠테이션과 회의에서 빛납니다. 오늘 처녀자리의 말은 복잡한 내용을 쉽게 설명하는 탁월한 능력으로 발휘되어, 논리적이고 명확한 발언이 청중의 마음을 사로잡습니다. 중요한 발표나 미팅이 있다면 오늘이 최적의 날입니다—준비한 것들이 의도대로 전달될 것입니다.', en: 'Mercury\'s energy shines brilliantly in presentations and meetings today, with Virgo\'s exceptional ability to explain complex content clearly fully activated. Your logical, precise speech will capture the audience\'s attention. If you have an important presentation or meeting, today is the optimal day—what you\'ve prepared will be conveyed exactly as you intend. This is your professional moment; step into it fully.', zh: '水星的能量在演示和会议中闪耀。今天处女座将复杂内容简单解释的卓越能力得到充分发挥，逻辑清晰的发言吸引听众的心。如果有重要的发表或会议，今天是最佳日子——准备好的内容将按照你的意图传达。', ja: '水星のエネルギーがプレゼンテーションと会議で輝きます。今日処女座の複雑な内容をわかりやすく説明する卓越した能力が発揮され、論理的で明確な発言が聴衆の心を掴みます。重要な発表やミーティングがあれば今日が最適な日です——準備したものが意図通りに伝わるでしょう。', es: 'La energía de Mercurio brilla brillantemente en presentaciones y reuniones hoy, con la excepcional habilidad de Virgo de explicar contenido complejo claramente completamente activada. Tu discurso lógico y preciso captará la atención del público. Si tienes una presentación o reunión importante, hoy es el día óptimo—lo que has preparado se transmitirá exactamente como pretendes.' },
      { ko: '업무 프로세스의 비효율을 발견하고 개선안을 제시할 기회입니다. 처녀자리만이 볼 수 있는 시스템의 취약점과 개선 포인트를 오늘 과감하게 제안해보세요. 당신의 제안이 채택될 확률이 높습니다—문제를 발견하는 것을 넘어 구체적인 해결책까지 제시하는 당신의 접근법이 의사결정자를 설득할 것입니다.', en: 'An excellent opportunity today to spot inefficiencies in work processes and propose improvements—only Virgo can see the system vulnerabilities and improvement points that others walk past. Propose them boldly today. Your suggestion has a high chance of adoption, because you don\'t just identify problems—you present concrete solutions. That complete approach is what persuades decision-makers and earns lasting respect.', zh: '今天是发现工作流程低效并提出改进方案的绝佳机会。只有处女座才能看到的系统弱点和改进点，今天大胆地提出来吧。你的建议被采纳的概率很高——不仅仅是发现问题，还提出具体解决方案的你的方式将说服决策者。', ja: '業務プロセスの非効率を発見し改善案を提示する絶好のチャンスです。処女座だけが見えるシステムの弱点と改善ポイントを今日大胆に提案してみてください。あなたの提案が採用される確率が高いです——問題を発見するだけでなく具体的な解決策まで提示するあなたのアプローチが意思決定者を説得するでしょう。', es: 'Una excelente oportunidad hoy para detectar ineficiencias en procesos de trabajo y proponer mejoras—solo Virgo puede ver las vulnerabilidades del sistema y los puntos de mejora que otros pasan por alto. Proponlos con valentía hoy. Tu sugerencia tiene alta probabilidad de ser adoptada, porque no solo identificas problemas—presentas soluciones concretas. Ese enfoque completo es lo que persuade a los tomadores de decisiones.' },
      { ko: '오랫동안 묵묵히 쌓아온 실력이 드디어 인정받는 시기입니다. 처녀자리는 조용히 실력을 키우고 화려하게 자랑하지 않는 사람인데, 오늘 그 조용한 탁월함이 드디어 가시권에 들어옵니다. 승진이나 보상의 기회가 다가옵니다—당신이 마땅히 받아야 할 인정을 자신 있게 받아들이세요.', en: 'Your quietly accumulated skills are finally recognized today—Virgo is someone who builds ability in silence without flashy self-promotion, and today that quiet excellence finally enters the visible range of others. Promotion or reward opportunities approach. Accept the recognition you rightfully deserve with confidence. You have earned this moment through consistent, disciplined effort over a long time.', zh: '长期默默积累的实力今天终于得到认可。处女座是那种默默提升实力而不华丽炫耀的人，今天那种安静的卓越终于进入他人的视野。升职或奖励的机会到来——自信地接受你应得的认可吧。你通过长期一贯的、有纪律的努力赢得了这个时刻。', ja: '長い間黙々と積み上げてきた実力がついに認められる時期です。処女座は静かに実力を磨き華やかに自慢しない人ですが、今日その静かな卓越さがついに他の人の視野に入ります。昇進や報酬のチャンスが近づきます——当然受け取るべき認定を自信を持って受け入れてください。', es: 'Tus habilidades acumuladas en silencio finalmente son reconocidas hoy—Virgo es alguien que construye capacidad en silencio sin autopromoción llamativa, y hoy esa excelencia silenciosa finalmente entra en el rango visible de otros. Se acercan oportunidades de ascenso o recompensa. Acepta con confianza el reconocimiento que mereces justamente. Has ganado este momento a través de esfuerzo consistente y disciplinado durante mucho tiempo.' },
      { ko: '팀원들의 필요를 미리 파악하고 지원하는 당신이 핵심 인재로 부상합니다. 처녀자리의 세밀한 관찰력이 팀의 약점을 선제적으로 보완하는 데 발휘될 때, 그것이 진정한 리더십의 표현입니다. 오늘 당신의 조용하고 실질적인 기여가 팀 전체의 성과를 한 단계 끌어올릴 것입니다.', en: 'You emerge as a key talent today by anticipating and supporting team members\' needs before they\'re even expressed—Virgo\'s fine-grained observation ability deployed to preemptively address team weaknesses is the truest expression of leadership. Your quiet, substantive contribution today will elevate the entire team\'s performance by a full level. That kind of invisible architecture is exactly what great teams are built on.', zh: '提前了解并支持团队成员需求的你今天崭露头角成为核心人才。处女座的细致观察力用于提前弥补团队弱点时，那才是真正领导力的体现。今天你安静而实质性的贡献将把整个团队的成果提升一个层级。这种无形的架构正是伟大团队的基础。', ja: 'チームメンバーのニーズを先に把握しサポートするあなたが核心人材として浮上します。処女座の細やかな観察力がチームの弱点を先制的に補完するために発揮される時、それが真のリーダーシップの表現です。今日あなたの静かで実質的な貢献がチーム全体の成果を一段階引き上げるでしょう。', es: 'Emerges hoy como talento clave al anticipar y apoyar las necesidades de los miembros del equipo antes de que se expresen—la capacidad de observación detallada de Virgo desplegada para abordar preventivamente las debilidades del equipo es la expresión más verdadera del liderazgo. Tu contribución silenciosa y sustantiva hoy elevará el rendimiento de todo el equipo en un nivel completo.' },
      { ko: '데이터 기반의 의사결정이 탁월한 성과로 이어집니다. 처녀자리는 감에 의존하는 사람들이 놓치는 패턴을 숫자에서 읽어내는 탁월한 능력을 가지고 있습니다. 숫자와 근거가 당신의 편인 오늘, 데이터가 보여주는 방향을 과감하게 주장하세요—그 확신이 당신을 차별화하는 요소입니다.', en: 'Data-driven decisions lead to outstanding results today—Virgo has an exceptional ability to read patterns from numbers that gut-instinct driven people consistently miss. Numbers and evidence are firmly on your side today. Boldly advocate for the direction the data is showing you. That conviction backed by solid analysis is precisely what differentiates you and makes your professional opinion worth seeking out.', zh: '基于数据的决策今天带来卓越成果。处女座有卓越的能力从数字中读出依靠感觉的人错过的模式。数字和依据今天站在你这边，大胆主张数据所示的方向——那种以扎实分析为后盾的确信正是区分你并使你的专业意见值得寻求的因素。', ja: 'データに基づく意思決定が卓越した成果につながります。処女座は感に頼る人々が見逃すパターンを数字から読み取る卓越した能力を持っています。数字と根拠が今日あなたの味方ですので、データが示す方向を大胆に主張してください——その確信があなたを差別化する要素です。', es: 'Las decisiones basadas en datos llevan a resultados sobresalientes hoy—Virgo tiene una capacidad excepcional para leer patrones de números que las personas guiadas por instinto consistentemente pierden. Los números y la evidencia están firmemente de tu lado hoy. Aboga valientemente por la dirección que los datos te muestran. Esa convicción respaldada por análisis sólido es precisamente lo que te diferencia.' },
      { ko: '새로운 기술이나 도구를 빠르게 습득하여 업무 효율을 높일 수 있는 날입니다. 처녀자리의 학습 능력은 수성의 날카로운 지성에서 나오는 것으로, 오늘 새로운 시스템이나 방법론을 배워야 하는 상황이라면 다른 날보다 월등히 빠르게 익힐 수 있습니다. 배움에 시간을 투자하면 이후 몇 배의 효율로 돌아옵니다.', en: 'A day to quickly master new skills or tools and significantly boost work efficiency—Virgo\'s learning ability flows from Mercury\'s sharp intellect, and if you need to learn a new system or methodology today, you will master it at a rate far superior to other days. Invest time in learning now and it returns as several times greater efficiency afterward. Your capacity to learn fast is a competitive advantage worth deploying.', zh: '快速掌握新技术或工具大幅提高工作效率的一天。处女座的学习能力来自水星的敏锐智慧，如果今天需要学习新的系统或方法论，你将以远超其他日子的速度掌握它。现在把时间投入学习，之后将以几倍的效率回报。快速学习的能力是值得部署的竞争优势。', ja: '新しい技術やツールを素早く習得して業務効率を大幅に高められる日です。処女座の学習能力は水星の鋭い知性から来るもので、今日新しいシステムや方法論を学ぶ必要があるなら他の日より格段に速く習得できます。今学習に時間を投資すれば、その後何倍もの効率として返ってきます。', es: 'Un día para dominar rápidamente nuevas habilidades o herramientas y aumentar significativamente la eficiencia laboral—la capacidad de aprendizaje de Virgo fluye del intelecto agudo de Mercurio, y si necesitas aprender un nuevo sistema o metodología hoy, lo dominarás a una velocidad muy superior a otros días. Invierte tiempo en aprender ahora y regresa como eficiencia varias veces mayor.' },
      { ko: '흙 원소의 견고한 에너지가 장기 프로젝트에 안정적인 진전을 가져다줍니다. 처녀자리의 지구력과 꾸준함이 오늘 가장 강력하게 발휘되어, 급하지 않지만 중요한 장기 목표를 향한 견실한 걸음을 내딛을 수 있습니다. 화려하지 않아도 오늘의 착실한 전진이 결국 가장 멀리 도달합니다.', en: 'Earth element\'s solid energy brings steady progress to long-term projects today—Virgo\'s endurance and consistency are at their most powerful, allowing you to take firm, solid steps toward important long-term goals that aren\'t urgent but truly matter. Even without fanfare, today\'s steady advancement ultimately reaches the farthest. The quiet discipline of today is tomorrow\'s extraordinary result.', zh: '土元素的坚实能量为长期项目带来稳定进展。处女座的耐力和一贯性今天得到最强有力的发挥，可以向不紧迫但重要的长期目标迈出坚实的步伐。即使不华丽，今天扎实的前进最终到达最远。今天安静的纪律是明天非凡的结果。', ja: '土のエレメントの堅固なエネルギーが長期プロジェクトに安定的な進展をもたらします。処女座の持久力と着実さが今日最も強力に発揮され、急ぎではないが重要な長期目標に向けた確かな一歩を踏み出すことができます。華やかでなくても今日の着実な前進が結局最も遠くまで到達します。', es: 'La energía sólida del elemento tierra trae avance estable a proyectos a largo plazo hoy—la resistencia y consistencia de Virgo están en su punto más poderoso, permitiéndote dar pasos firmes y sólidos hacia metas a largo plazo importantes que no son urgentes pero realmente importan. Incluso sin fanfarria, el avance constante de hoy llega más lejos. La disciplina silenciosa de hoy es el resultado extraordinario de mañana.' },
      { ko: '봉사하는 마음으로 한 일이 큰 성과로 돌아옵니다. 처녀자리는 자신의 이익보다 시스템과 팀의 개선을 먼저 생각하는 자연스러운 봉사자인데, 오늘 그 봉사 정신이 예상치 못한 형태의 보상으로 돌아옵니다. 뒤에서 묵묵히 지원한 것들이 결실을 맺는 이 순간을 충분히 느끼세요.', en: 'Work done with a service mindset returns as great results today—Virgo is a natural servant who thinks first of improving the system and team rather than personal gain, and today that serving spirit returns in unexpected forms of reward. Feel fully the moment when what you quietly supported from behind bears fruit. This is the universe recognizing the value of genuine, unassuming contribution.', zh: '以奉献之心做的事今天以大成果回报。处女座是天生的奉献者，优先考虑系统和团队的改善而非个人利益，今天那种奉献精神以意想不到的奖励形式回报。充分感受那些在幕后默默支持的努力终于结出果实的这一刻。这是宇宙对真诚、谦逊贡献价值的认可。', ja: '奉仕の心で行ったことが大きな成果として返ってきます。処女座は自分の利益より先にシステムとチームの改善を考える自然な奉仕者ですが、今日その奉仕精神が予想外の形の報酬として返ってきます。陰で黙々とサポートしたことが実を結ぶこの瞬間を十分に感じてください。', es: 'El trabajo hecho con una mentalidad de servicio regresa como grandes resultados hoy—Virgo es un servidor natural que piensa primero en mejorar el sistema y el equipo en lugar de la ganancia personal, y hoy ese espíritu de servicio regresa en formas inesperadas de recompensa. Siente plenamente el momento en que lo que apoyaste silenciosamente desde atrás da fruto. Este es el universo reconociendo el valor de la contribución genuina y sin pretensiones.' },
    ],
    medium: [
      { ko: '맡은 업무를 체계적으로 처리하면 무난한 하루가 됩니다. 처녀자리에게 리스트를 만들고 하나씩 체크해 나가는 것은 단순한 생산성 기술이 아니라 내면의 질서가 외부로 표현되는 자연스러운 방식입니다. 오늘 그 방식을 충분히 신뢰하며 하나씩 완성해나가세요.', en: 'Handling tasks systematically ensures a smooth day today—and for Virgo, making a list and checking items off one by one is not just a productivity technique but the natural expression of inner order made visible. Trust that system fully today and work through it one item at a time. Each checkmark is a small victory that builds momentum for the next. Celebrate that quiet progress.', zh: '系统地处理工作就能度过平稳的一天。对处女座来说，列一个清单逐一勾选不只是生产力技巧，而是内在秩序向外表现的自然方式。今天充分信任那种方式，一件一件地完成。每个勾选都是为下一步建立动力的小胜利。', ja: '担当業務を体系的に処理すれば無難な一日になります。処女座にとってリストを作って一つずつチェックしていくことは単なる生産性テクニックではなく、内なる秩序が外部に表れる自然な方式です。今日その方式を十分に信頼しながら一つずつ完成させていきましょう。', es: 'Manejar tareas sistemáticamente asegura un día tranquilo hoy—y para Virgo, hacer una lista y marcar elementos uno por uno no es solo una técnica de productividad sino la expresión natural del orden interior hecho visible. Confía plenamente en ese sistema hoy y trabaja por él un elemento a la vez. Cada marca de verificación es una pequeña victoria que impulsa la siguiente.' },
      { ko: '기본에 충실한 업무 수행이 최선의 전략입니다. 오늘은 새로운 것을 시도하기보다 검증된 방법으로 안정적으로 해내는 것이 더 현명합니다. 화려한 시도보다 정확한 실행에 집중하세요—처녀자리의 진정한 강점은 일관되게 높은 수준을 유지하는 것이며, 그것이 결국 가장 큰 신뢰를 만들어냅니다.', en: 'Sticking to basics is the best strategy today—it\'s wiser to execute reliably with proven methods than to attempt something new. Focus on accurate execution over flashy attempts. Virgo\'s true strength is maintaining consistently high standards, and that consistency ultimately creates the deepest professional trust. The person who reliably delivers good work is always more valued than one who occasionally dazzles.', zh: '忠于基本的工作执行是今天的最佳策略。今天用经过验证的方法稳定地完成比尝试新事物更明智。专注于准确执行而非华丽的尝试——处女座真正的强项是一贯保持高水准，而这最终创造出最大的信任。稳定交付好工作的人总比偶尔令人眼花缭乱的人更有价值。', ja: '基本に忠実な業務遂行が最善の戦略です。今日は新しいことを試みるより検証された方法で安定して実行することが賢明です。華やかな試みより正確な実行に集中してください——処女座の真の強みは一貫して高い水準を維持することであり、それが結局最大の信頼を作り出します。', es: 'Mantenerse en lo básico es la mejor estrategia hoy—es más sabio ejecutar de manera confiable con métodos probados que intentar algo nuevo. Enfócate en la ejecución precisa sobre intentos llamativos. La verdadera fortaleza de Virgo es mantener estándares consistentemente altos, y esa consistencia en última instancia crea la mayor confianza profesional.' },
      { ko: '동료와의 소통에서 명확하게 의사를 전달하는 것이 중요합니다. 처녀자리는 이미 머릿속에서 완성된 그림을 가지고 있지만, 상대방은 그 그림을 볼 수 없습니다. 애매한 표현을 피하고, 당신의 생각을 충분히 구체적으로 설명해보세요—명확한 소통이 오늘의 가장 중요한 업무 능력입니다.', en: 'Clear communication with colleagues is key today—Virgo already has a completed picture in mind, but others cannot see that picture. Avoid ambiguous expressions and explain your thinking with sufficient concreteness. The gap between what you assume is obvious and what others actually understand can be significant. Bridge that gap deliberately, and watch collaboration improve dramatically today.', zh: '今天与同事沟通时明确传达意见非常重要。处女座脑中已经有了完整的图景，但对方看不到那幅图景。避免模糊的表达，充分具体地解释你的想法——你认为显而易见的和他人实际理解的之间可能存在很大差距。有意识地弥合那个差距，看合作今天如何显著改善。', ja: '同僚とのコミュニケーションで明確に意思を伝えることが重要です。処女座はすでに頭の中に完成した絵を持っていますが、相手はその絵を見ることができません。曖昧な表現を避け、自分の考えを十分具体的に説明してみてください——あなたが明らかだと思っていることと他の人が実際に理解していることとのギャップは大きいかもしれません。', es: 'La comunicación clara con colegas es clave hoy—Virgo ya tiene una imagen completa en mente, pero otros no pueden ver esa imagen. Evita expresiones ambiguas y explica tu pensamiento con suficiente concreción. La brecha entre lo que asumes que es obvio y lo que otros realmente entienden puede ser significativa. Cierra esa brecha deliberadamente y observa cómo mejora dramáticamente la colaboración.' },
      { ko: '업무 환경을 정리정돈하면 집중력이 높아집니다. 처녀자리에게 외부 공간의 혼란은 내부 사고의 혼란으로 이어지는 경향이 있습니다. 책상과 파일 정리부터 시작해보세요—단 5분의 정리가 이후 몇 시간의 집중력을 회복시켜주는 처녀자리만의 생산성 비밀 무기입니다.', en: 'Organizing your workspace boosts focus today—for Virgo, chaos in external space tends to translate directly into chaos in internal thinking. Start by tidying your desk and files. Just five minutes of organizing is Virgo\'s secret productivity weapon that restores hours of focus afterward. A clear space creates a clear mind, and a clear Virgo mind is capable of remarkable precision and output.', zh: '整理工作环境可以提高注意力。对处女座来说，外部空间的混乱往往直接转化为内部思维的混乱。从整理桌面和文件开始——仅5分钟的整理是处女座专属的生产力秘密武器，能恢复此后数小时的专注力。清晰的空间创造清晰的思维，清晰的处女座思维能够产生非凡的精准度和产出。', ja: '業務環境を整理整頓すると集中力が高まります。処女座にとって外部空間の混乱は内部思考の混乱につながる傾向があります。デスクとファイルの整理から始めてみてください——たった5分の整理がその後何時間もの集中力を回復させる処女座だけの生産性秘密兵器です。', es: 'Organizar tu espacio de trabajo aumenta la concentración hoy—para Virgo, el caos en el espacio externo tiende a traducirse directamente en caos en el pensamiento interno. Empieza ordenando tu escritorio y archivos. Solo cinco minutos de organización son el arma secreta de productividad de Virgo que restaura horas de enfoque afterward. Un espacio claro crea una mente clara.' },
      { ko: '작은 실수를 방지하기 위해 이중 확인하는 습관이 도움이 됩니다. 처녀자리에게 이 습관은 이미 자연스러운 것이지만, 오늘 그 꼼꼼함이 특히 중요한 역할을 합니다. 꼼꼼함이 당신의 무기입니다—오늘 제출하거나 전달하는 것은 최종 확인을 한 번 더 거치세요. 그 한 번이 큰 차이를 만들 수 있습니다.', en: 'Double-checking habits help prevent small mistakes today—and while this habit already comes naturally to Virgo, today it plays a particularly important role. Meticulousness is your weapon, and today that weapon is most needed. Give one more final verification to everything you submit or send today. That one extra check could prevent the kind of error that would cost far more time to correct later.', zh: '双重检查的习惯有助于今天防止小失误。虽然这个习惯对处女座来说已经很自然，但今天它扮演着特别重要的角色。细致是你的武器——今天提交或传达的所有东西再做一次最终确认。那一次可能防止稍后需要花更多时间纠正的错误。', ja: '小さなミスを防ぐためにダブルチェックする習慣が今日助けになります。この習慣はすでに処女座にとって自然なものですが、今日そのきめ細かさが特に重要な役割を果たします。丁寧さがあなたの武器です——今日提出または伝えるものは最終確認をもう一度行ってください。', es: 'El hábito de verificar dos veces previene pequeños errores hoy—y aunque este hábito ya viene naturalmente a Virgo, hoy juega un papel particularmente importante. La meticulosidad es tu arma, y hoy esa arma es más necesaria. Da una verificación final más a todo lo que presentes o envíes hoy. Esa verificación adicional podría prevenir el tipo de error que costaría mucho más tiempo corregir más tarde.' },
      { ko: '무리한 목표보다 현실적인 계획을 세우세요. 처녀자리는 높은 기준을 설정하는 것이 자연스럽지만, 오늘은 달성 불가능한 목표가 오히려 의욕을 꺾을 수 있습니다. 달성 가능한 목표가 동기 부여의 원천이 됩니다—오늘 해낼 수 있는 것들만 리스트에 올리고, 그것을 완벽하게 완료하는 데 집중하세요.', en: 'Set realistic plans over overambitious goals today—while setting high standards comes naturally to Virgo, today unattainable goals could actually undermine motivation. Achievable goals fuel motivation. Put only what you can genuinely accomplish today on your list and focus on completing those things perfectly. The satisfaction of truly finishing something is more energizing than half-finishing many things.', zh: '今天制定现实的计划而非过于勉强的目标。对处女座来说设定高标准很自然，但今天无法实现的目标可能会反而打击积极性。可实现的目标是动力的源泉——只把今天真正能完成的事情放在清单上，专注于完美地完成它们。真正完成某事的满足感比半完成很多事情更能补充能量。', ja: '無理な目標より現実的な計画を立ててください。高い基準を設定することは処女座にとって自然なことですが、今日は達成不可能な目標がむしろやる気をそいでしまう可能性があります。達成可能な目標がモチベーションの源になります——今日達成できるものだけリストに入れて、それを完璧に完了することに集中してください。', es: 'Establece planes realistas sobre metas excesivas hoy—aunque establecer altos estándares viene naturalmente a Virgo, hoy las metas inalcanzables podrían minar la motivación. Las metas alcanzables alimentan la motivación. Pon en tu lista solo lo que genuinamente puedes lograr hoy y enfócate en completar esas cosas perfectamente. La satisfacción de terminar verdaderamente algo es más energizante que medio terminar muchas cosas.' },
      { ko: '새로운 업무를 배우기 좋은 날입니다. 수성의 학습 에너지가 처녀자리의 분석적 두뇌와 결합하면 새로운 기술과 지식을 흡수하는 능력이 평소보다 훨씬 높아집니다. 배우고 싶었던 것, 익혀야 했지만 미루어온 것들을 오늘 시작해보세요—역량을 키우는 이 시간이 당신의 미래 경쟁력을 만듭니다.', en: 'A good day to learn new tasks—Mercury\'s learning energy combined with Virgo\'s analytical brain creates an absorption capacity far above normal. Start today the things you\'ve wanted to learn but kept postponing. The skills and knowledge you invest in building right now shape your future competitiveness directly. What you master today becomes the advantage that sets you apart in challenges yet to come.', zh: '今天是学习新工作的好日子。水星的学习能量与处女座分析性大脑结合，使吸收新技术和知识的能力远超平时。开始那些你一直想学习但一直推迟的事情吧——现在建立能力所投入的时间直接塑造你未来的竞争力。', ja: '新しい業務を学ぶのに良い日です。水星の学習エネルギーが処女座の分析的な頭脳と組み合わさると、新しい技術や知識を吸収する能力が普段よりずっと高まります。学びたかったこと、身につけるべきだったが先延ばしにしてきたことを今日始めてみてください。', es: 'Buen día para aprender nuevas tareas—la energía de aprendizaje de Mercurio combinada con el cerebro analítico de Virgo crea una capacidad de absorción muy por encima de lo normal. Comienza hoy las cosas que has querido aprender pero has seguido posponiendo. Las habilidades y el conocimiento en los que inviertes ahora dan forma directamente a tu competitividad futura.' },
      { ko: '팀 프로젝트에서 조율자 역할이 적합한 날입니다. 처녀자리는 전체 그림을 이해하면서 세부 일정까지 챙기는 드문 능력을 가지고 있습니다. 세부 일정 관리를 맡아보세요—처녀자리가 만든 계획은 구체적이고 현실적이어서 팀 전체가 실제로 따를 수 있는 로드맵이 됩니다.', en: 'A day suited for a coordinator role in team projects—Virgo has the rare ability to understand the overall picture while simultaneously tracking the fine details of scheduling. Take charge of detailed scheduling. Plans created by Virgo are specific and realistic enough that the whole team can actually follow them as a genuine roadmap, not just an aspirational document that gets abandoned.', zh: '今天适合在团队项目中担任协调者角色。处女座有既理解全局又照顾到细节日程的罕见能力。接手详细日程管理——处女座制定的计划具体而现实，整个团队实际上可以将其作为真正的路线图遵循，而不只是一份被搁置的宏愿文件。', ja: 'チームプロジェクトで調整役が適している日です。処女座は全体像を理解しながら細部のスケジュールまで管理する稀な能力を持っています。詳細なスケジュール管理を担当してみてください——処女座が作った計画は具体的で現実的なので、チーム全体が実際に従えるロードマップになります。', es: 'Un día apto para el rol de coordinador en proyectos de equipo—Virgo tiene la rara habilidad de comprender el panorama general mientras rastrea simultáneamente los detalles finos de la programación. Encárgate de la planificación detallada. Los planes creados por Virgo son suficientemente específicos y realistas para que todo el equipo pueda seguirlos como una hoja de ruta genuina, no solo un documento aspiracional que se abandona.' },
      { ko: '완벽하지 않더라도 일단 제출하고 피드백을 반영하는 방식이 효율적일 수 있습니다. 처녀자리는 완벽한 결과물을 위해 계속 다듬는 경향이 있는데, 오늘은 그 경향을 잠시 내려놓아 보세요. 80%의 완성도로 제출하고 피드백을 받아 개선하는 것이 때로는 혼자서 100%를 향해 달리는 것보다 훨씬 빠릅니다.', en: 'Submitting even if imperfect and incorporating feedback can be more efficient today—Virgo tends to keep refining toward perfect output, but consider setting that tendency aside temporarily. Submitting at 80% completion and improving with feedback is sometimes far faster than running toward 100% alone. External perspective often reveals exactly what internal perfectionism misses. Iterate rather than agonize.', zh: '今天即使不完美也先提交再反映反馈的方式可能更有效率。处女座倾向于为了完美的结果不断打磨，但今天试着暂时放下那种倾向。以80%的完成度提交然后根据反馈改进，有时比单独追求100%快得多。外部视角往往揭示内部完美主义所忽略的东西。迭代而非煎熬。', ja: '完璧でなくてもまず提出してフィードバックを反映する方式が今日効率的かもしれません。処女座は完璧な成果物のために磨き続ける傾向がありますが、今日はその傾向を一時的に置いてみてください。80%の完成度で提出してフィードバックで改善する方が、一人で100%を目指して走るより時にずっと速いです。', es: 'Entregar aunque no sea perfecto e incorporar retroalimentación puede ser más eficiente hoy—Virgo tiende a seguir refinando hacia un resultado perfecto, pero considera dejar esa tendencia a un lado temporalmente. Entregar con el 80% de completitud y mejorar con retroalimentación a veces es mucho más rápido que correr hacia el 100% solo. La perspectiva externa a menudo revela exactamente lo que el perfeccionismo interno pierde.' },
      { ko: '안정적인 페이스를 유지하며 오늘 하루의 업무를 성실하게 마무리하세요. 처녀자리의 진정한 힘은 폭발적인 한 방이 아니라 꾸준하고 신뢰할 수 있는 일관성에 있습니다. 오늘 그 페이스를 무너뜨리지 말고 끝까지 유지하세요—지속 가능한 리듬이 장기적으로 가장 큰 성과를 만들어냅니다.', en: 'Maintain a steady pace and diligently wrap up today\'s work—Virgo\'s true power lies not in explosive one-time performances but in steady, trustworthy consistency. Don\'t break that pace today; maintain it to the end. A sustainable rhythm produces the greatest long-term results. Ending the day with work properly completed is a form of professional integrity that accumulates into an unassailable reputation.', zh: '保持稳定的节奏，认真完成今天的工作。处女座真正的力量不在于爆发性的一击，而在于稳定可靠的一致性。今天不要破坏那种节奏，坚持到最后——可持续的节奏从长远来看产生最大的成果。以正确完成的工作结束这一天是一种职业诚信，这种积累会形成无可辩驳的声誉。', ja: '安定したペースを維持しながら今日一日の業務を誠実に仕上げてください。処女座の真の力は爆発的な一打ではなく、着実で信頼できる一貫性にあります。今日そのペースを崩さず最後まで維持してください——持続可能なリズムが長期的に最大の成果を作り出します。', es: 'Mantén un ritmo estable y termina el trabajo de hoy con diligencia—el verdadero poder de Virgo no radica en actuaciones explosivas de una sola vez sino en una consistencia constante y confiable. No rompas ese ritmo hoy; mantenlo hasta el final. Un ritmo sostenible produce los mayores resultados a largo plazo. Terminar el día con el trabajo correctamente completado es una forma de integridad profesional que se acumula en una reputación inatacable.' },
    ],
    low: [
      { ko: '완벽주의가 업무 진행을 늦출 수 있습니다. 처녀자리의 완벽주의는 높은 품질을 만들어내는 강점이지만, 오늘 그것이 진행을 막는 장벽이 되고 있다면 전략을 바꿔야 합니다. 오늘은 완벽보다 완료에 초점을 맞추세요—제출된 70%가 마음속에 있는 100%보다 항상 더 많은 가치를 만들어냅니다.', en: 'Perfectionism may slow your progress today—Virgo\'s perfectionism is a strength that creates high quality, but if it\'s becoming a barrier to progress right now, the strategy must change. Focus on completion over perfection today. A submitted 70% always creates more value than a 100% that exists only in your mind. Done and improved is infinitely better than theoretically perfect and never finished.', zh: '完美主义今天可能拖慢工作进度。处女座的完美主义是创造高质量的强项，但如果它现在成为阻碍进展的障碍，策略就必须改变。今天专注于完成而非完美——提交的70%总是比心中的100%创造更多价值。完成并改进，无限优于理论上完美但从未完成。', ja: '完璧主義が業務の進行を遅らせる可能性があります。処女座の完璧主義は高い品質を生み出す強みですが、今日それが進行の障壁になっているなら戦略を変える必要があります。今日は完璧より完了に焦点を合わせてください——提出された70%はいつも頭の中にある100%より多くの価値を生み出します。', es: 'El perfeccionismo puede retrasar tu progreso hoy—el perfeccionismo de Virgo es una fortaleza que crea alta calidad, pero si se está convirtiendo en una barrera para el progreso ahora mismo, la estrategia debe cambiar. Enfócate en completar más que en perfeccionar hoy. Un 70% entregado siempre crea más valor que un 100% que existe solo en tu mente. Terminado y mejorado es infinitamente mejor que perfectamente teórico y nunca terminado.' },
      { ko: '동료의 업무 방식에 대한 비판을 삼가세요. 처녀자리의 눈에는 더 효율적인 방법이 보이겠지만, 오늘 그것을 지적하는 것이 관계를 악화시킬 수 있습니다. 지적보다 격려가 팀 분위기를 살립니다—그 더 좋은 방법을 의견이 아닌 질문의 형태로 제안해보세요.', en: 'Refrain from criticizing colleagues\' work methods today—to Virgo\'s eyes, a more efficient approach is clearly visible, but pointing it out today risks damaging relationships. Encouragement over correction lifts team morale. Try offering that better method in the form of a question rather than a statement. "What if we tried..." opens doors that "You should do it this way..." shuts permanently.', zh: '今天避免批评同事的工作方式。处女座的眼睛能看到更高效的方法，但今天指出它可能会破坏关系。鼓励比指正更能活跃团队氛围——试着以问题而非陈述的形式提出那种更好的方法。"如果我们试试……"开启的门，是"你应该这样做……"永远关闭的。', ja: '同僚の業務方式への批判は控えてください。処女座の目にはより効率的な方法が見えるかもしれませんが、今日それを指摘すると関係を悪化させる可能性があります。指摘より励ましがチームの雰囲気を活かします——その良い方法を意見ではなく質問の形で提案してみてください。', es: 'Abstente de criticar los métodos de trabajo de colegas hoy—a los ojos de Virgo, un enfoque más eficiente es claramente visible, pero señalarlo hoy arriesga dañar relaciones. El aliento sobre la corrección mejora el estado de ánimo del equipo. Intenta ofrecer ese mejor método en forma de pregunta en lugar de declaración. "¿Y si intentamos...?" abre puertas que "Deberías hacerlo así" cierra permanentemente.' },
      { ko: '수성의 불안정한 에너지가 커뮤니케이션 오류를 유발할 수 있습니다. 전달했다고 생각한 것이 상대방에게 다르게 도착하는 날입니다. 중요한 이메일은 재확인하세요—특히 감정이 섞인 내용이나 중요한 요청은 보내기 전에 24시간 후의 자신의 눈으로 다시 읽어보는 것이 좋습니다.', en: 'Mercury\'s unstable energy may cause communication errors today—what you think you\'ve communicated clearly may arrive very differently to the recipient. Double-check important emails, and especially for anything emotionally charged or containing important requests, try reading it again through the eyes of your future self 24 hours from now before sending. That pause prevents many regrettable sends.', zh: '水星不稳定的能量今天可能导致沟通错误。你认为清晰传达的东西可能对接收者来说截然不同。重要邮件请再次确认——特别是带有情绪的内容或重要请求，发送前尝试通过24小时后的自己的眼光再次阅读。那个停顿可以防止很多令人遗憾的发送。', ja: '水星の不安定なエネルギーがコミュニケーションエラーを引き起こす可能性があります。伝えたと思ったことが相手には違う形で届く日です。重要なメールは再確認してください——特に感情が混じった内容や重要なリクエストは送る前に24時間後の自分の目で読み直すことをお勧めします。', es: 'La energía inestable de Mercurio puede causar errores de comunicación hoy—lo que crees que has comunicado claramente puede llegar muy diferente al destinatario. Revisa correos importantes, y especialmente para algo emocionalmente cargado o que contenga solicitudes importantes, intenta leerlo nuevamente a través de los ojos de tu yo futuro 24 horas después antes de enviarlo.' },
      { ko: '모든 일을 혼자 떠안으려 하지 마세요. 처녀자리의 높은 기준이 "내가 직접 해야 제대로 된다"는 믿음을 만들어내지만, 그 믿음이 번아웃의 주요 원인이 됩니다. 위임은 무능이 아니라 효율적인 리더십입니다—타인에게 맡기면서 기대치를 명확히 하는 연습을 해보세요.', en: 'Don\'t try to shoulder everything alone today—Virgo\'s high standards create the belief that "only if I do it myself will it be done right," but that belief is one of the primary causes of burnout. Delegation is efficient leadership, not incompetence. Practice entrusting things to others while clearly communicating expectations. You can maintain quality standards while also building others\' capacity and protecting your own energy.', zh: '今天不要试图独自承担所有事情。处女座的高标准产生了"只有我亲自做才能做好"的信念，但那种信念是职业倦怠的主要原因之一。委派不是无能，而是高效的领导力——练习在明确沟通期望的同时把事情托付给他人。你可以在建立他人能力和保护自己精力的同时维持质量标准。', ja: 'すべてを一人で抱え込もうとしないでください。処女座の高い基準が「自分でやらなければ正しくできない」という信念を作り出しますが、その信念がバーンアウトの主な原因になります。委任は無能ではなく効率的なリーダーシップです——期待値を明確にしながら他の人に任せる練習をしてみてください。', es: 'No intentes cargar todo solo hoy—los altos estándares de Virgo crean la creencia de que "solo si lo hago yo mismo estará bien hecho," pero esa creencia es una de las principales causas del agotamiento. Delegar es liderazgo eficiente, no incompetencia. Practica confiar cosas a otros mientras comunicas claramente las expectativas. Puedes mantener estándares de calidad mientras también desarrollas la capacidad de otros y proteges tu propia energía.' },
      { ko: '과도한 분석이 오히려 판단을 흐릴 수 있습니다. 처녀자리는 데이터가 충분하지 않을 때 불안해지며 더 많은 정보를 수집하려는 경향이 있는데, 오늘 그 사이클에서 빠져나올 필요가 있습니다. 충분한 정보가 모이면 결단하세요—완벽한 정보는 결코 존재하지 않으며, 기다리는 것 자체가 결정입니다.', en: 'Over-analysis may cloud judgment today—Virgo becomes anxious without sufficient data and tends to gather more and more information, but today you need to break out of that cycle. Decide once you have enough information. Perfect information never exists, and waiting itself is a decision—often the worst one. Set a clear threshold of "enough information" and commit when you reach it.', zh: '过度分析今天反而可能模糊判断。处女座在数据不足时会感到不安，并倾向于收集越来越多的信息，但今天需要从那个循环中跳出来。信息足够时就做决定——完美的信息从不存在，而等待本身就是一个决定——通常是最糟糕的那个。设定"足够信息"的明确阈值，达到时就做出承诺。', ja: '過度な分析がかえって判断を曇らせる可能性があります。処女座はデータが不十分な時に不安になり、より多くの情報を収集しようとする傾向がありますが、今日そのサイクルから抜け出す必要があります。十分な情報が集まったら決断してください——完璧な情報は決して存在せず、待つこと自体が決断です。', es: 'El análisis excesivo puede nublar el juicio hoy—Virgo se vuelve ansioso sin datos suficientes y tiende a recopilar cada vez más información, pero hoy necesitas salir de ese ciclo. Decide cuando tengas suficiente información. La información perfecta nunca existe, y esperar en sí mismo es una decisión—a menudo la peor. Establece un umbral claro de "información suficiente" y comprométete cuando lo alcances.' },
      { ko: '비판을 받았다면 개인적으로 받아들이지 마세요. 처녀자리는 자신의 작업물과 자신을 동일시하는 경향이 강해서, 업무 비판이 자아 비판처럼 들릴 수 있습니다. 하지만 피드백은 성장의 기회입니다. 업무에 대한 피드백일 뿐입니다—그것을 분리해서 듣고, 개선할 수 있는 정보로만 활용하세요.', en: 'If criticized, don\'t take it personally today—Virgo strongly tends to identify with their work, making professional feedback feel like personal criticism. But feedback is an opportunity for growth. It\'s just feedback on the work, not on you as a person. Practice separating the two and using only what\'s actionable for improvement. The ability to receive feedback well is itself a rare professional strength worth developing.', zh: '如果受到批评，今天不要当作个人攻击。处女座强烈倾向于将自己与工作认同，使职业反馈感觉像个人批评。但反馈是成长的机会。这只是对工作的反馈，不是对你这个人的批评——将两者分开听，只将其作为可以改进的信息使用。善于接受反馈本身就是值得培养的罕见职业优势。', ja: '批判を受けたなら個人的に受け止めないでください。処女座は自分の作業物と自分を同一視する傾向が強く、業務批判が自我批判のように聞こえることがあります。しかしフィードバックは成長の機会です。業務に対するフィードバックに過ぎません——それを分離して聞き、改善できる情報としてだけ活用してください。', es: 'Si te critican, no lo tomes personalmente hoy—Virgo fuertemente tiende a identificarse con su trabajo, haciendo que la retroalimentación profesional se sienta como crítica personal. Pero la retroalimentación es una oportunidad de crecimiento. Es solo retroalimentación sobre el trabajo, no sobre ti como persona. Practica separar los dos y usar solo lo que es accionable para mejora.' },
      { ko: '업무 스트레스가 신체 증상으로 나타날 수 있습니다. 처녀자리는 스트레스를 소화 문제, 두통, 어깨 긴장의 형태로 몸에 저장하는 경향이 있습니다. 점심시간에 잠깐이라도 바깥 공기를 쐬세요—5분의 산책이 오후 내내의 생산성을 회복시켜줄 수 있습니다.', en: 'Work stress may manifest physically today—Virgo tends to store stress in the body as digestive issues, headaches, or shoulder tension. Get some fresh air during lunch, even briefly. A five-minute walk outside can restore your afternoon productivity far more effectively than powering through. Your body is giving you signals worth listening to, not ignoring in the service of getting more done.', zh: '工作压力今天可能以身体症状表现。处女座倾向于以消化问题、头痛或肩部紧张的形式将压力储存在身体中。午休时即使短暂也到外面透透气——5分钟的散步可以比硬撑更有效地恢复下午的生产力。你的身体正在给你值得倾听的信号，而不是为了完成更多工作而忽视它。', ja: '業務ストレスが身体症状として現れる可能性があります。処女座はストレスを消化器問題、頭痛、肩の緊張の形で体に蓄積する傾向があります。昼休みに少しでも外の空気を吸ってください——5分間の散歩が午後の生産性をがんばり続けるよりずっと効果的に回復させてくれます。', es: 'El estrés laboral puede manifestarse físicamente hoy—Virgo tiende a almacenar el estrés en el cuerpo como problemas digestivos, dolores de cabeza o tensión en los hombros. Toma aire fresco durante el almuerzo, aunque sea brevemente. Una caminata de cinco minutos afuera puede restaurar tu productividad de la tarde mucho más efectivamente que aguantar. Tu cuerpo te está dando señales que vale la pena escuchar.' },
      { ko: '계획 변경에 저항하지 말고 유연하게 대응하세요. 처녀자리는 계획을 세밀하게 준비할수록 그 계획이 바뀔 때 받는 충격도 큽니다. 그러나 변통궁의 적응력을 믿으세요—변화가 왔을 때 가장 빠르게 새로운 최선의 경로를 찾아내는 것이 처녀자리의 숨겨진 능력입니다.', en: 'Don\'t resist plan changes today—respond flexibly instead. The more meticulously Virgo prepares a plan, the greater the shock when it changes, but trust your mutable sign\'s adaptability. Finding the new best path fastest when change arrives is Virgo\'s hidden superpower. That agility, combined with your analytical precision, makes you uniquely equipped to navigate disruption better than almost anyone else.', zh: '今天不要抗拒计划变更，灵活应对。处女座越细致地准备计划，变化时受到的冲击就越大。但相信变动宫的适应力——当变化来临时最快找到新的最佳路径是处女座隐藏的能力。这种敏捷性加上你的分析精准度，使你有独特的能力比几乎任何人都能更好地应对干扰。', ja: '計画変更に抵抗せず柔軟に対応してください。処女座は計画を細密に準備するほど、その計画が変わった時に受ける衝撃も大きくなります。しかし変通宮の適応力を信じてください——変化が来た時に最も速く新しい最善の経路を見つけ出すことが処女座の隠れた能力です。', es: 'No te resistas a los cambios de plan hoy—responde con flexibilidad en cambio. Cuanto más meticulosamente Virgo prepara un plan, mayor es el shock cuando cambia, pero confía en la adaptabilidad de tu signo mutable. Encontrar el nuevo mejor camino más rápidamente cuando llega el cambio es el superpoder oculto de Virgo. Esa agilidad, combinada con tu precisión analítica, te hace únicamente equipado para navegar la disrupción mejor que casi cualquier otro.' },
      { ko: '사소한 실수에 자책하지 마세요. 처녀자리는 자신의 실수를 다른 누구보다 크게 보는 경향이 있는데, 그 자책이 실수 자체보다 훨씬 더 큰 에너지를 소모시킵니다. 실수는 성장의 재료이지 실패의 증거가 아닙니다—처리하고, 배우고, 앞으로 나아가세요.', en: 'Don\'t blame yourself for small mistakes today—Virgo tends to see their own mistakes as larger than anyone else would, and that self-blame consumes far more energy than the mistake itself. Mistakes are fuel for growth, not proof of failure. Process it, extract what\'s useful to learn, and move forward. The amount of self-criticism you invest in a small error is never proportional to its actual impact.', zh: '今天不要为小失误自责。处女座倾向于比任何人都更大地看待自己的失误，而那种自责消耗的能量远超失误本身。错误是成长的材料，不是失败的证据——处理它，提取有用的学习，然后前进。你为小错误投入的自我批评量从来不与其实际影响成比例。', ja: '些細なミスに自責しないでください。処女座は自分のミスを誰よりも大きく見る傾向があり、その自責がミスそのものよりはるかに多くのエネルギーを消耗させます。ミスは成長の材料であって失敗の証拠ではありません——処理して、学べることを引き出して、前に進んでください。', es: 'No te culpes por errores pequeños hoy—Virgo tiende a ver sus propios errores más grandes de lo que lo haría cualquier otro, y esa autocrítica consume mucha más energía que el error en sí. Los errores son combustible para crecer, no prueba de fracaso. Procésalo, extrae lo útil para aprender y avanza. La cantidad de autocrítica que inviertes en un error pequeño nunca es proporcional a su impacto real.' },
      { ko: '새로운 프로젝트를 시작하기보다 기존 업무를 정리하는 데 집중하는 것이 좋겠습니다. 처녀자리는 미완성 항목들이 마음에 남아 에너지를 소모시키는 경향이 있습니다. 오늘은 추가하는 날이 아닌 마무리하는 날로 정하세요—완료된 것들을 체크하면서 얻는 성취감이 내일의 에너지를 충전해줍니다.', en: 'Better to focus on organizing existing work rather than starting new projects today—Virgo tends to have unfinished items that linger in the mind and drain energy. Declare today a finishing day rather than an adding day. The sense of achievement you get from checking off completed items will charge tomorrow\'s energy. Closing open loops is one of the highest-value activities a Virgo can do on a difficult day.', zh: '今天比起开始新项目，专注于整理现有工作更好。处女座倾向于有未完成的项目留在脑海中消耗能量。今天定为完成日而非添加日——从勾选完成项目中获得的成就感会为明天的能量充电。关闭未完成的循环是处女座在困难日子里可以做的最高价值活动之一。', ja: '新しいプロジェクトを始めるより既存の業務を整理することに集中した方が良さそうです。処女座には未完成の項目が心に残ってエネルギーを消耗させる傾向があります。今日は追加する日ではなく仕上げる日に定めてください——完了したものをチェックしながら得る達成感が明日のエネルギーを充電してくれます。', es: 'Mejor enfocarse en organizar el trabajo existente que en empezar proyectos nuevos hoy—Virgo tiende a tener elementos sin terminar que permanecen en la mente y drenan energía. Declara hoy un día de finalización en lugar de un día de adición. El sentido de logro que obtienes al marcar elementos completados cargará la energía de mañana. Cerrar los bucles abiertos es una de las actividades de mayor valor que un Virgo puede hacer en un día difícil.' },
    ],
  },
  health: {
    high: [
      { ko: '흙 원소의 안정적 에너지가 몸과 마음에 활력을 불어넣습니다. 꾸준히 쌓아온 건강한 루틴이 오늘 그 복리 효과를 드러내며, 몸 전체가 최적의 상태로 기능하는 느낌을 받을 것입니다. 이 활력을 에너지가 넘치는 도전에 쓰세요—오늘 당신의 몸은 평소보다 더 많은 것을 해낼 준비가 되어 있습니다.', en: 'Earth element\'s stable energy revitalizes body and mind today, with your consistently maintained healthy routine revealing its compound effects—your whole body functioning at its optimal state. Use this vitality for energetic challenges. Your body is prepared to accomplish more than usual today, and this is the right time to push the edge of what you thought your limits were.', zh: '土元素的稳定能量今天为身心注入活力。持续积累的健康习惯今天显现出其复利效果，整个身体感觉处于最佳状态。把这种活力用于充满挑战的事情——今天你的身体比平时更准备好了，这是拓展你认为的极限边界的好时机。', ja: '土のエレメントの安定したエネルギーが体と心に活力を吹き込みます。コツコツと積み上げてきた健康的なルーティンが今日その複利効果を現し、体全体が最適な状態で機能する感覚を受けるでしょう。この活力をエネルギーあふれる挑戦に使ってください——今日あなたの体は普段より多くのことをやり遂げる準備ができています。', es: 'La energía estable de la tierra revitaliza cuerpo y mente hoy, con tu rutina saludable consistentemente mantenida revelando sus efectos compuestos—todo tu cuerpo funcionando en su estado óptimo. Usa esta vitalidad para desafíos enérgicos. Tu cuerpo está preparado para lograr más de lo usual hoy, y este es el momento adecuado para empujar el límite de lo que pensabas que eran tus limitaciones.' },
      { ko: '새로운 건강 습관을 시작하기에 최적의 날입니다. 처녀자리는 새 습관을 분석하고 체계화하는 능력이 탁월하여, 오늘 시작한 루틴이 다른 날보다 훨씬 높은 확률로 정착됩니다. 식단 개선이나 운동 프로그램을 계획해보세요—시작하는 오늘이 가장 중요한 첫날입니다.', en: 'The perfect day to start new health habits—Virgo excels at analyzing and systematizing new habits, meaning routines begun today have a significantly higher probability of sticking than on other days. Plan dietary improvements or exercise programs with your characteristic precision. The systems you build today for your health become the infrastructure of your wellbeing for years to come. Today is genuinely the best day to begin.', zh: '今天是开始新健康习惯的最佳日子。处女座在分析和系统化新习惯方面表现出色，意味着今天开始的习惯比其他日子更有可能坚持下来。精确地计划改善饮食或运动计划——今天建立的健康系统成为未来多年健康的基础设施。今天确实是开始的最佳日子。', ja: '新しい健康習慣を始めるのに最適な日です。処女座は新しい習慣を分析し体系化する能力に優れており、今日始めたルーティンが他の日よりずっと高い確率で定着します。食事改善や運動プログラムを特有の正確さで計画してみてください——今日健康のために構築するシステムが今後何年もの健康の基盤になります。', es: 'El día perfecto para iniciar nuevos hábitos de salud—Virgo sobresale en analizar y sistematizar nuevos hábitos, lo que significa que las rutinas comenzadas hoy tienen una probabilidad significativamente mayor de mantenerse que en otros días. Planifica mejoras en dieta o ejercicio con tu característica precisión. Los sistemas que construyes hoy para tu salud se convierten en la infraestructura de tu bienestar durante años.' },
      { ko: '소화기 건강이 좋은 상태입니다. 처녀자리는 소화기 계통과 특별한 연결이 있는 별자리로, 오늘 그 계통이 최적으로 기능하고 있습니다. 장 건강을 위한 발효 식품을 즐겨보세요—요거트, 김치, 케피어 등이 오늘 당신의 몸에 특별히 잘 맞을 것입니다. 좋은 날에 좋은 것을 더하세요.', en: 'Digestive health is in excellent shape today—Virgo has a special connection to the digestive system as a zodiac sign, and today that system is functioning optimally. Enjoy fermented foods for gut health—yogurt, kimchi, kefir will be particularly well-suited to your body today. Add good things on a good day. The gut-brain connection Virgo understands intuitively is operating at its clearest right now.', zh: '今天消化系统健康状况良好。处女座作为星座与消化系统有特殊联系，今天那个系统处于最佳运作状态。享用发酵食品来促进肠道健康——酸奶、泡菜、开菲尔今天与你的身体特别契合。好日子多添好东西。处女座直觉理解的肠-脑连接现在运作得最清晰。', ja: '消化器の健康が良い状態です。処女座は星座として消化器系統と特別なつながりがあり、今日その系統が最適に機能しています。腸の健康のために発酵食品を楽しんでみてください——ヨーグルト、キムチ、ケフィアなどが今日あなたの体に特によく合うでしょう。良い日に良いものを加えてください。', es: 'La salud digestiva está en excelente forma hoy—Virgo tiene una conexión especial con el sistema digestivo como signo zodiacal, y hoy ese sistema está funcionando óptimamente. Disfruta alimentos fermentados para la salud intestinal—el yogur, kimchi, kéfir serán particularmente bien adaptados a tu cuerpo hoy. Añade cosas buenas en un buen día. La conexión intestino-cerebro que Virgo entiende intuitivamente está operando con más claridad ahora.' },
      { ko: '수성의 에너지가 심신의 균형을 맞춰줍니다. 처녀자리에게 수성은 신경계와 정신을 관장하는 행성으로, 오늘 그 균형이 완벽하게 맞춰져 있습니다. 요가나 필라테스가 큰 효과를 줄 것입니다—마음과 몸을 동시에 연결하는 이 운동들이 오늘 당신에게 특별히 깊이 작용할 것입니다.', en: 'Mercury\'s energy balances mind and body beautifully today—for Virgo, Mercury governs the nervous system and the mind, and today that balance is perfectly calibrated. Yoga or Pilates will have great effect. These mind-body connection exercises will work with particular depth for you today, creating a sense of integration between your analytical mind and your physical body that is uniquely restorative for Virgo.', zh: '水星的能量今天完美地平衡了身心。对处女座来说，水星掌管神经系统和精神，今天那种平衡完美校准。瑜伽或普拉提会有很好的效果——这些同时连接心智和身体的运动今天将以特别的深度对你发挥作用，创造出分析性思维与身体之间的整合感，这对处女座具有独特的恢复作用。', ja: '水星のエネルギーが心身のバランスを美しく整えてくれます。処女座にとって水星は神経系と精神を司る惑星であり、今日そのバランスが完璧に整っています。ヨガやピラティスが大きな効果を与えるでしょう——心と体を同時に結ぶこれらの運動が今日あなたに特別に深く作用し、処女座に独自の回復をもたらす統合感を生み出します。', es: 'La energía de Mercurio equilibra mente y cuerpo bellamente hoy—para Virgo, Mercurio gobierna el sistema nervioso y la mente, y hoy ese equilibrio está perfectamente calibrado. El yoga o Pilates tendrá gran efecto. Estos ejercicios de conexión mente-cuerpo funcionarán con profundidad particular para ti hoy, creando una sensación de integración entre tu mente analítica y tu cuerpo físico que es singularmente restauradora para Virgo.' },
      { ko: '자연 속에서 시간을 보내면 치유의 에너지를 받을 수 있습니다. 처녀자리는 흙 원소의 별자리로 자연과 깊은 연결을 가지고 있으며, 특히 숲이나 대지와의 접촉이 강력한 재충전 효과를 줍니다. 숲길 산책을 추천합니다—맨발로 땅을 밟는 어싱(earthing)을 시도해보세요.', en: 'Spending time in nature brings healing energy today—Virgo is an earth sign with a deep connection to nature, and contact with forest or earth in particular provides powerful recharging effects. A forest walk is strongly recommended. Consider trying earthing—walking barefoot on grass or soil—as the direct connection to earth is especially restorative for Virgo\'s earth-element nature today.', zh: '在大自然中度过时间今天可以获得治愈能量。处女座是土象星座，与自然有深厚的联系，特别是与森林或大地的接触能提供强大的充电效果。强烈推荐森林散步——考虑尝试接地气（earthing）——在草地或土壤上赤脚行走，因为与大地的直接接触今天对处女座的土元素本性特别有恢复作用。', ja: '自然の中で時間を過ごすと治癒のエネルギーを受け取れます。処女座は土のエレメントの星座として自然と深いつながりを持っており、特に森や大地との接触が強力な充電効果を与えます。森の散歩がおすすめです——裸足で地面を踏むアーシング(earthing)を試してみてください。地球との直接のつながりが今日処女座の土のエレメントの本質に特別に回復力をもたらします。', es: 'Pasar tiempo en la naturaleza trae energía curativa hoy—Virgo es un signo de tierra con una conexión profunda con la naturaleza, y el contacto con el bosque o la tierra en particular proporciona efectos de recarga poderosos. Se recomienda enfáticamente un paseo por el bosque. Considera intentar el earthing—caminar descalzo en hierba o suelo—ya que la conexión directa a la tierra es especialmente restauradora para la naturaleza de elemento tierra de Virgo hoy.' },
      { ko: '건강 관련 정보를 수집하고 적용하기 좋은 날입니다. 처녀자리의 분석적 두뇌가 오늘 특별히 영양학, 의학, 웰니스 관련 정보를 흡수하고 실용적으로 적용하는 데 탁월합니다. 영양 공부를 시작해보세요—오늘 읽은 건강 정보가 실생활에서 즉각적으로 적용될 가능성이 높습니다.', en: 'A good day to gather and apply health information—Virgo\'s analytical brain is especially excellent today at absorbing and practically applying information related to nutrition, medicine, and wellness. Start studying nutrition. Health information read today has a high probability of being immediately implemented in your real life, because Virgo\'s mind naturally bridges the gap between knowledge and actionable practice.', zh: '今天是收集和应用健康信息的好日子。处女座的分析性大脑今天特别擅长吸收并实际应用营养学、医学和健康相关信息。开始学习营养学——今天阅读的健康信息很可能立即在实际生活中得到应用，因为处女座的思维自然地弥合了知识与可行实践之间的差距。', ja: '健康関連の情報を収集し活用するのに良い日です。処女座の分析的な頭脳が今日特に栄養学、医学、ウェルネス関連の情報を吸収し実用的に活用することに優れています。栄養の勉強を始めてみてください——今日読んだ健康情報が実際の生活で即座に応用される可能性が高いです。', es: 'Buen día para recopilar y aplicar información de salud—el cerebro analítico de Virgo es especialmente excelente hoy para absorber y aplicar prácticamente información relacionada con nutrición, medicina y bienestar. Empieza a estudiar nutrición. La información de salud leída hoy tiene alta probabilidad de implementarse inmediatamente en tu vida real, porque la mente de Virgo naturalmente cierra la brecha entre el conocimiento y la práctica accionable.' },
      { ko: '규칙적인 수면 패턴이 면역력을 높이는 시기입니다. 처녀자리는 루틴이 최고로 잘 돌아갈 때 건강이 극대화되는 별자리입니다. 취침 루틴을 잘 유지하세요—오늘 밤 같은 시간에 잠자리에 드는 작은 결정이 다음 며칠간의 에너지 수준 전체를 결정짓는 중요한 기반이 됩니다.', en: 'Regular sleep patterns boost immunity significantly right now—Virgo is a sign whose health is maximized when routines are running at their best. Maintain your bedtime routine with care. The small decision to go to bed at the same time tonight becomes the crucial foundation determining your energy levels for the next several days. Consistent sleep timing is one of Virgo\'s highest-value health investments.', zh: '现在规律的睡眠模式显著提高免疫力。处女座是当习惯运作最佳时健康达到最大化的星座。好好维持就寝习惯——今晚在同一时间上床睡觉的小决定，成为决定接下来几天整体能量水平的关键基础。稳定的睡眠时间是处女座健康投资中价值最高的之一。', ja: '規則的な睡眠パターンが今免疫力を大幅に高めます。処女座はルーティンが最高に機能する時に健康が最大化する星座です。就寝ルーティンをしっかり維持してください——今夜同じ時間に床につくという小さな決断が次の数日間のエネルギーレベル全体を決定する重要な基盤になります。', es: 'Los patrones regulares de sueño aumentan la inmunidad significativamente ahora—Virgo es un signo cuya salud se maximiza cuando las rutinas funcionan a su mejor nivel. Mantén tu rutina de dormir con cuidado. La pequeña decisión de acostarte a la misma hora esta noche se convierte en la base crucial que determina tus niveles de energía durante los próximos días. El tiempo de sueño consistente es una de las inversiones de salud de mayor valor de Virgo.' },
      { ko: '세밀한 자기 관찰이 건강 상태를 최적으로 유지하게 합니다. 처녀자리는 자신의 몸에서 보내는 미세한 신호를 포착하는 탁월한 능력을 가지고 있습니다. 몸의 변화에 주의를 기울이세요—오늘 느끼는 에너지, 소화 상태, 기분의 패턴을 관찰하면 당신만의 건강 바로미터가 만들어집니다.', en: 'Detailed self-observation keeps your health optimal today—Virgo has an exceptional ability to pick up on the subtle signals their body sends. Pay close attention to body changes. By observing the patterns of energy, digestion, and mood you feel today, you create your own personal health barometer that is more precise than any generic health guideline. Trust that detailed self-knowledge completely.', zh: '今天细致的自我观察让健康状态保持最佳。处女座有卓越的能力捕捉身体发出的微妙信号。注意身体的变化——通过观察今天感受到的能量、消化状态和情绪的规律，你建立了比任何通用健康指南都更精确的个人健康晴雨表。完全信任那种细致的自我认知。', ja: '細やかな自己観察が健康状態を最適に維持させます。処女座は体が送る微妙なシグナルを捉える卓越した能力を持っています。体の変化に注意を払ってください——今日感じるエネルギー、消化状態、気分のパターンを観察することで、あらゆる一般的な健康ガイドラインより正確なあなただけの健康バロメーターが作られます。', es: 'La autoobservación detallada mantiene tu salud óptima hoy—Virgo tiene una capacidad excepcional para captar las señales sutiles que envía su cuerpo. Presta mucha atención a los cambios corporales. Al observar los patrones de energía, digestión y estado de ánimo que sientes hoy, creas tu propio barómetro de salud personal que es más preciso que cualquier pauta de salud genérica. Confía completamente en ese conocimiento propio detallado.' },
      { ko: '디톡스에 좋은 날입니다. 처녀자리의 소화기 계통이 오늘 최고로 활성화되어 있어 해독 과정이 효율적으로 진행됩니다. 가벼운 해독 식단으로 몸속 노폐물을 정리해보세요—채소즙, 생수, 허브차가 오늘 당신의 몸에 특별히 잘 맞습니다. 몸이 준비되어 있을 때 정화를 도와주세요.', en: 'A great day for detox—Virgo\'s digestive system is highly activated today, allowing the detoxification process to proceed efficiently. Try a light cleansing diet to clear out toxins. Vegetable juices, pure water, and herbal teas are particularly well-suited to your body today. Support the purification when the body is ready for it. What you release today creates space for better energy tomorrow.', zh: '今天非常适合排毒。处女座的消化系统今天高度活跃，使排毒过程高效进行。用轻量解毒饮食清理体内废物——蔬菜汁、纯净水、草本茶今天与你的身体特别契合。身体准备好时帮助净化。今天释放的东西为明天更好的能量创造空间。', ja: 'デトックスに良い日です。処女座の消化器系統が今日最高に活性化されており、解毒過程が効率的に進みます。軽い解毒食で体内の老廃物を整理してみてください——野菜ジュース、純水、ハーブティーが今日あなたの体に特によく合います。体が準備されている時に浄化を助けてください。', es: 'Un gran día para desintoxicarte—el sistema digestivo de Virgo está altamente activado hoy, permitiendo que el proceso de desintoxicación proceda eficientemente. Prueba una dieta ligera de limpieza para eliminar toxinas. Los jugos de verduras, agua pura y tés herbales son particularmente bien adaptados a tu cuerpo hoy. Apoya la purificación cuando el cuerpo está listo para ella. Lo que liberas hoy crea espacio para mejor energía mañana.' },
      { ko: '스트레스 없는 맑은 에너지가 흐릅니다. 이런 날은 처녀자리에게 드물고 소중한 선물입니다—마음의 잡음이 사라지고 몸이 자연스럽게 이완될 때, 비로소 진정한 자신의 모습이 드러납니다. 이 기분을 유지할 수 있는 습관을 만들어두세요. 오늘의 평화가 내일을 위한 설계도가 됩니다.', en: 'Clear, stress-free energy flows today—this kind of day is a rare and precious gift for Virgo. When the mind\'s noise disappears and the body relaxes naturally, your true self finally reveals itself without the interference of worry. Build habits to maintain this feeling. Study today\'s conditions carefully—what did you do differently? What did you avoid? Today\'s peace becomes the blueprint for tomorrow.', zh: '今天无压力的清澈能量在流动。这样的日子对处女座来说是罕见而珍贵的礼物——当心灵的噪音消失、身体自然放松时，真正的自我才得以显现。建立能维持这种感觉的习惯。仔细研究今天的状态——你做了哪些不同的事情？你避免了什么？今天的平静成为明天的蓝图。', ja: 'ストレスのない澄んだエネルギーが流れています。このような日は処女座にとって稀で貴重な贈り物です——心のノイズが消えて体が自然にリラックスする時、初めて本当の自分の姿が現れます。この気分を維持できる習慣を作っておいてください。今日の状態を丁寧に研究してください——今日は何を違うようにしましたか？何を避けましたか？今日の平和が明日のための設計図になります。', es: 'Fluye energía clara y sin estrés hoy—este tipo de día es un regalo raro y precioso para Virgo. Cuando el ruido de la mente desaparece y el cuerpo se relaja naturalmente, tu verdadero yo finalmente se revela sin la interferencia de la preocupación. Construye hábitos para mantener esta sensación. Estudia cuidadosamente las condiciones de hoy—¿qué hiciste diferente? ¿Qué evitaste? La paz de hoy se convierte en el plano de mañana.' },
    ],
    medium: [
      { ko: '전반적으로 안정적인 건강 상태입니다. 처녀자리에게 이 안정적인 상태는 꾸준한 루틴 덕분이며, 오늘 그 가치가 조용히 확인되고 있습니다. 기존의 건강 루틴을 꾸준히 유지하면 충분합니다—화려하게 무언가를 추가하기보다 이미 잘 작동하고 있는 것들을 계속 지켜나가는 지혜를 발휘하세요.', en: 'Overall stable health today—for Virgo, this stable state is thanks to your consistent routine, and today that value is quietly being confirmed. Consistently maintaining your current health routine is genuinely enough. Exercise the wisdom of continuing what is already working well rather than dramatically adding something new. Stable health maintained over time is the foundation of everything else.', zh: '今天整体健康状态稳定。对处女座来说，这种稳定状态得益于一贯的习惯，今天那种价值正在悄悄地得到确认。坚持现有的健康习惯就足够了——与其华丽地添加什么，不如发挥继续坚守已经运作良好的事情的智慧。长期保持的稳定健康是一切的基础。', ja: '全般的に安定した健康状態です。処女座にとってこの安定した状態はコツコツとしたルーティンのおかげであり、今日その価値が静かに確認されています。既存の健康ルーティンを着実に維持すれば十分です——派手に何かを追加するより、すでにうまく機能しているものを継続する知恵を発揮してください。', es: 'Salud general estable hoy—para Virgo, este estado estable es gracias a tu rutina consistente, y hoy ese valor se confirma silenciosamente. Mantener tu rutina de salud actual de forma constante es genuinamente suficiente. Ejerce la sabiduría de continuar lo que ya funciona bien en lugar de añadir algo dramáticamente nuevo. La salud estable mantenida a lo largo del tiempo es la base de todo lo demás.' },
      { ko: '소화에 부담이 가지 않도록 식사량과 식사 시간을 규칙적으로 관리하세요. 처녀자리는 소화기 계통이 민감한 별자리로, 불규칙한 식습관이 전반적인 컨디션에 미치는 영향이 큽니다. 오늘은 과식이나 급하게 먹는 것을 피하고, 천천히 씹어 먹는 의식적인 식사를 실천해보세요.', en: 'Manage meal portions and times regularly today to avoid burdening your digestion—Virgo is a sign with a sensitive digestive system, and irregular eating habits have a large impact on overall wellbeing. Avoid overeating or rushing through meals today and practice conscious eating with deliberate chewing. What happens during the meal matters as much as what you eat. Give your digestive system the respect it deserves.', zh: '今天规律管理食量和用餐时间，避免给消化系统增加负担。处女座是消化系统敏感的星座，不规律的饮食习惯对整体状态影响很大。今天避免暴饮暴食或匆忙进食，练习慢慢咀嚼的正念饮食。用餐期间发生的事情与你吃什么同样重要。给你的消化系统应有的尊重。', ja: '消化に負担がかからないよう食事量と食事時間を今日規則的に管理してください。処女座は消化器系統が敏感な星座で、不規則な食習慣が全般的なコンディションに与える影響が大きいです。今日は食べ過ぎや急いで食べることを避け、ゆっくり噛んで食べる意識的な食事を実践してみてください。', es: 'Gestiona porciones y horarios de comida regularmente hoy para no sobrecargar la digestión—Virgo es un signo con un sistema digestivo sensible, y los hábitos alimentarios irregulares tienen un gran impacto en el bienestar general. Evita comer en exceso o apresurarte durante las comidas hoy y practica comer conscientemente con masticación deliberada. Lo que sucede durante la comida importa tanto como lo que comes.' },
      { ko: '가벼운 스트레칭으로 하루를 시작하면 몸과 마음이 깨어납니다. 처녀자리에게 아침 루틴은 하루의 톤을 설정하는 중요한 의식입니다. 아침 루틴을 지켜보세요—단 10분의 스트레칭이 이후 몇 시간 동안의 집중력, 자세, 기분 전체에 긍정적인 파급효과를 만들어냅니다.', en: 'Starting the day with light stretching awakens body and mind—for Virgo, the morning routine is an important ritual that sets the tone for the entire day. Keep your morning routine carefully. Just ten minutes of stretching creates a positive ripple effect on hours of subsequent focus, posture, and mood. The way you begin is the way you continue, and Virgo\'s careful morning sets up everything that follows.', zh: '用轻度拉伸开始新的一天，唤醒身心。对处女座来说，晨间习惯是为一天奠定基调的重要仪式。保持晨间习惯——仅10分钟的拉伸就能在随后数小时的专注力、姿势和情绪上创造积极的涟漪效应。你如何开始就会如何继续，处女座细心的早晨为接下来的一切奠定基础。', ja: '軽いストレッチで一日を始めると体と心が目覚めます。処女座にとって朝のルーティンは一日のトーンを設定する重要な儀式です。朝のルーティンを守ってください——たった10分のストレッチがその後の何時間もの集中力、姿勢、気分全体にポジティブな波及効果を作り出します。', es: 'Empezar el día con estiramientos ligeros despierta cuerpo y mente—para Virgo, la rutina matutina es un ritual importante que establece el tono para todo el día. Mantén tu rutina matutina cuidadosamente. Solo diez minutos de estiramiento crea un efecto dominó positivo en horas de enfoque, postura y estado de ánimo subsiguientes. La manera en que comienzas es la manera en que continúas.' },
      { ko: '충분한 수분 섭취가 필요한 날입니다. 처녀자리는 일에 집중하다 보면 수분 섭취를 잊어버리는 경향이 있습니다. 따뜻한 물이나 허브차를 가까이 두세요—탈수는 처녀자리의 분석적 사고력을 가장 먼저 저하시키는 요인 중 하나이며, 오늘 그것을 방지하는 간단한 방법이 바로 눈앞에 컵 하나를 두는 것입니다.', en: 'A day that calls for plenty of water—Virgo tends to forget hydration when absorbed in work. Keep warm water or herbal tea within easy reach. Dehydration is one of the first things to impair Virgo\'s analytical thinking capacity, and the simple prevention today is just keeping a cup in front of you. Every sip is maintenance for the precise mental machinery Virgo relies on most.', zh: '今天需要充分摄入水分。处女座在专注于工作时往往会忘记补水。把温水或草本茶放在手边——脱水是最先损害处女座分析思维能力的因素之一，今天防止这一点的简单方法就是在眼前放一个杯子。每一口都是对处女座最依赖的精密心智机器的维护。', ja: '十分な水分摂取が必要な日です。処女座は仕事に集中すると水分摂取を忘れてしまう傾向があります。温かいお湯やハーブティーをそばに置いてください——脱水は処女座の分析的思考能力を最初に低下させる要因の一つであり、今日それを防ぐ簡単な方法はまさに目の前にカップを一つ置くことです。', es: 'Un día que requiere mucha hidratación—Virgo tiende a olvidar hidratarse cuando está absorbido en el trabajo. Ten agua tibia o té herbal al alcance fácil. La deshidratación es una de las primeras cosas en deteriorar la capacidad de pensamiento analítico de Virgo, y la prevención simple hoy es simplemente mantener una taza frente a ti. Cada sorbo es mantenimiento para la maquinaria mental precisa en la que Virgo más confía.' },
      { ko: '과로를 피하고 적절한 휴식 시간을 확보하세요. 처녀자리는 완료하지 못한 업무가 있을 때 쉬는 것에 죄책감을 느끼는 경향이 있지만, 그 죄책감 자체가 과로의 신호입니다. 일과 중 짧은 휴식이 효율을 높입니다—역설적으로, 쉬는 것이 더 많이 이루는 방법입니다.', en: 'Avoid overwork and secure proper rest time today—Virgo tends to feel guilty about resting when there\'s unfinished work, but that guilt itself is a signal of overwork. Short breaks during work genuinely boost efficiency. Paradoxically, resting is how you achieve more. The Virgo who rests well makes better decisions, catches more errors, and produces higher quality work than the one who exhausts themselves.', zh: '今天避免过度工作，确保适当的休息时间。处女座在有未完成工作时往往会对休息感到愧疚，但那种愧疚本身就是过劳的信号。工作中的短暂休息确实提高效率——矛盾的是，休息是实现更多的方式。休息好的处女座做出更好的决策，发现更多错误，产出比精疲力竭的自己更高质量的工作。', ja: '過労を避けて適切な休息時間を確保してください。処女座は未完成の業務がある時に休むことに罪悪感を感じる傾向がありますが、その罪悪感自体が過労のシグナルです。仕事中の短い休憩が効率を本当に高めます——逆説的に、休むことがより多くを達成する方法です。', es: 'Evita el exceso de trabajo y asegura tiempo de descanso adecuado hoy—Virgo tiende a sentirse culpable por descansar cuando hay trabajo sin terminar, pero esa culpa en sí misma es una señal de sobretrabajo. Los descansos cortos durante el trabajo aumentan genuinamente la eficiencia. Paradójicamente, descansar es cómo logras más. El Virgo que descansa bien toma mejores decisiones, captura más errores y produce trabajo de mayor calidad.' },
      { ko: '무리한 운동보다 꾸준한 가벼운 움직임이 더 효과적입니다. 처녀자리는 새 운동을 시작할 때 너무 완벽한 계획을 세워서 실제로 시작이 늦어지는 경우가 많습니다. 계단 이용, 짧은 산책을 실천하세요—거창한 계획 없이 지금 당장 할 수 있는 작은 움직임이 가장 좋은 운동입니다.', en: 'Consistent light movement is more effective than intense exercise today—Virgo often creates such a perfect exercise plan that the actual start is delayed. Use stairs and take short walks. The small movement you can do right now without a grand plan is the best exercise. Consistent small actions compound dramatically over time, and they don\'t require a perfect schedule to begin. Start now, adjust later.', zh: '今天比起过度运动，持续的轻度活动更有效。处女座在开始新运动时经常制定太完美的计划，导致实际开始延迟。多走楼梯，短距离散步——不需要宏大计划，现在就能做的小动作是最好的运动。持续的小行动随时间复利式增长，而且不需要完美的时间表就能开始。现在开始，之后调整。', ja: '無理な運動より着実な軽い動きの方が今日効果的です。処女座は新しい運動を始める時にあまりにも完璧な計画を立てて、実際の開始が遅れることが多いです。階段利用、短い散歩を実践してください——壮大な計画なしに今すぐできる小さな動きが最も良い運動です。一貫した小さな行動は時間とともに劇的に複利を生みます。', es: 'El movimiento ligero constante es más efectivo que el ejercicio intenso hoy—Virgo a menudo crea un plan de ejercicio tan perfecto que el inicio real se retrasa. Usa escaleras y toma caminatas cortas. El pequeño movimiento que puedes hacer ahora mismo sin un gran plan es el mejor ejercicio. Las pequeñas acciones consistentes se acumulan dramáticamente con el tiempo, y no requieren un horario perfecto para comenzar.' },
      { ko: '눈의 피로에 주의하세요. 처녀자리는 정밀한 작업에 집중하다 보면 눈의 피로를 자각하지 못하는 경향이 있습니다. 화면에서 눈을 떼고 먼 곳을 바라보는 시간을 가지세요—20-20-20 규칙(20분마다 20피트 거리를 20초간 바라보기)이 처녀자리의 생산성 루틴에 포함되어야 합니다.', en: 'Watch out for eye fatigue today—Virgo tends not to notice eye tiredness when concentrating on precise work. Take time to look away from screens at distant objects. The 20-20-20 rule—looking at something 20 feet away for 20 seconds every 20 minutes—should be part of Virgo\'s productivity routine. Your eyes are the input device for your most important tool: your precise, analytical mind.', zh: '今天注意眼睛疲劳。处女座在专注于精细工作时往往不会察觉眼睛疲劳。从屏幕上移开视线，看看远处——20-20-20规则（每20分钟看20英尺远的地方20秒）应该成为处女座生产力习惯的一部分。你的眼睛是最重要工具——精准分析性思维——的输入设备。', ja: '目の疲れに注意してください。処女座は精密な作業に集中すると目の疲れを自覚しにくい傾向があります。画面から目を離して遠くを見る時間を持ってください——20-20-20ルール（20分ごとに20フィート先を20秒間見る）が処女座の生産性ルーティンに含まれるべきです。', es: 'Cuidado con la fatiga ocular hoy—Virgo tiende a no notar el cansancio ocular cuando se concentra en trabajo preciso. Tómate tiempo para mirar lejos de la pantalla. La regla 20-20-20—mirar algo a 20 pies de distancia durante 20 segundos cada 20 minutos—debería ser parte de la rutina de productividad de Virgo. Tus ojos son el dispositivo de entrada para tu herramienta más importante: tu mente precisa y analítica.' },
      { ko: '영양 균형을 신경 쓰되 과도한 식단 제한은 오히려 스트레스가 됩니다. 처녀자리는 건강에 관한 정보를 수집하다 보면 규칙이 너무 많아져서 식사가 즐거움이 아닌 과제가 될 수 있습니다. 중용을 지키세요—80%를 잘 먹으면 나머지 20%는 여유를 허락해도 됩니다.', en: 'Mind nutritional balance, but excessive dietary restrictions cause stress today—Virgo can collect so many health rules that eating becomes a task rather than a pleasure. Keep moderation. If you eat well 80% of the time, you can allow yourself flexibility for the remaining 20%. A sustainable approach to nutrition beats a perfect-but-rigid approach every time, because the sustainable one is actually followed.', zh: '注意营养均衡，但今天过度的饮食限制反而会造成压力。处女座在收集健康信息时可能积累了太多规则，使饮食成为任务而非享受。保持中庸——如果80%的时间吃得好，剩余20%可以允许自己放松。可持续的营养方法每次都胜过完美但僵硬的方法，因为可持续的方法才真正被遵循。', ja: '栄養バランスに気を配りつつ過度な食事制限はかえってストレスになります。処女座は健康に関する情報を収集しているうちにルールが多くなりすぎて、食事が楽しみではなく課題になってしまうことがあります。中庸を守ってください——80%の時間をしっかり食べていれば、残りの20%は余裕を許していいです。', es: 'Cuida el equilibrio nutricional, pero las restricciones dietéticas excesivas causan estrés hoy—Virgo puede acumular tantas reglas de salud que comer se convierte en una tarea en lugar de un placer. Mantén la moderación. Si comes bien el 80% del tiempo, puedes permitirte flexibilidad para el 20% restante. Un enfoque sostenible de la nutrición vence a un enfoque perfecto pero rígido cada vez, porque el sostenible realmente se sigue.' },
      { ko: '잠들기 전 내일 걱정을 메모장에 적어두고 머리를 비우세요. 처녀자리의 분석적 두뇌는 멈추지 않고 밤에도 문제를 처리하려는 경향이 있어 수면을 방해합니다. 걱정을 종이로 내보내는 이 간단한 습관이 수면의 질을 크게 향상시킵니다—당신의 뇌에게 "이건 내일 처리해도 안전하다"는 신호를 주는 것입니다.', en: 'Write tomorrow\'s worries in a notepad before sleep and clear your mind—Virgo\'s analytical brain tends to keep processing problems without stopping, even at night, disrupting sleep. This simple habit of externalizing worry onto paper significantly improves sleep quality. You\'re giving your brain the signal that "it is safe to process this tomorrow." That permission to stop is exactly what the Virgo mind needs to truly rest.', zh: '睡前把明天的担忧写在记事本上，清空大脑。处女座的分析性大脑倾向于不停地处理问题，即使在夜间也不例外，从而干扰睡眠。这个把担忧写到纸上的简单习惯可以显著改善睡眠质量——你在给大脑一个"明天处理这个也安全"的信号。这种停止的许可正是处女座的思维真正休息所需要的。', ja: '寝る前に明日の心配をメモ帳に書き出して頭を空っぽにしてください。処女座の分析的な頭脳は夜でも止まることなく問題を処理しようとする傾向があり、睡眠を妨げます。心配を紙に外部化するこの簡単な習慣が睡眠の質を大きく向上させます——あなたの脳に「これは明日処理しても安全だ」というシグナルを送ることです。', es: 'Escribe las preocupaciones de mañana antes de dormir y despeja tu mente—el cerebro analítico de Virgo tiende a seguir procesando problemas sin parar, incluso de noche, perturbando el sueño. Este simple hábito de externalizar la preocupación en papel mejora significativamente la calidad del sueño. Le estás dando a tu cerebro la señal de que "es seguro procesar esto mañana." Esa permisión para detenerse es exactamente lo que la mente de Virgo necesita para descansar verdaderamente.' },
      { ko: '몸이 보내는 작은 신호에 주의를 기울이세요. 처녀자리는 타인의 필요는 잘 알아차리지만 자신의 몸이 보내는 신호는 무시하는 경향이 있습니다. 조기 대응이 큰 문제를 예방합니다—피로, 긴장, 불편함 같은 작은 신호들을 무시하지 말고 지금 바로 반응하세요. 몸은 거짓말하지 않습니다.', en: 'Pay attention to small signals from your body today—Virgo is good at noticing others\' needs but tends to ignore signals from their own body. Early response prevents bigger problems. Don\'t dismiss small signals like tiredness, tension, or discomfort—respond to them right now. Your body doesn\'t lie, and in Virgo\'s case the body\'s intelligence is especially trustworthy. Honor what it is communicating to you.', zh: '今天注意身体发出的小信号。处女座善于察觉他人的需求，但往往会忽视自己身体发出的信号。及早应对可以预防大问题——不要忽视疲劳、紧张、不适等小信号，立即做出反应。身体不会说谎，在处女座的情况下，身体的智慧尤其值得信赖。尊重它正在向你传达的信息。', ja: '体が送る小さなサインに注意を払ってください。処女座は他者のニーズはよく気づきますが、自分の体が送るシグナルを無視する傾向があります。早期対応が大きな問題を予防します——疲労、緊張、不快感といった小さなサインを無視せずに今すぐ反応してください。体は嘘をつきません。', es: 'Presta atención a las pequeñas señales de tu cuerpo hoy—Virgo es bueno notando las necesidades de otros pero tiende a ignorar las señales de su propio cuerpo. La respuesta temprana previene problemas mayores. No desestimes señales pequeñas como cansancio, tensión o incomodidad—responde a ellas ahora mismo. Tu cuerpo no miente, y en el caso de Virgo la inteligencia del cuerpo es especialmente confiable. Honra lo que te está comunicando.' },
    ],
    low: [
      { ko: '소화기 계통에 불편함이 나타날 수 있습니다. 처녀자리의 소화기는 스트레스와 불안에 특히 민감하게 반응하는데, 오늘 그 연결이 더 강하게 나타날 수 있습니다. 자극적인 음식과 과식을 피하세요—오늘 당신의 소화기에게 줄 수 있는 가장 좋은 선물은 소박하고 따뜻한 음식과 충분한 휴식입니다.', en: 'Digestive discomfort may appear today—Virgo\'s digestive system responds particularly sensitively to stress and anxiety, and today that connection may be stronger than usual. Avoid spicy food and overeating. The best gift you can give your digestive system today is simple, warm food and adequate rest. When in doubt about what to eat, choose the gentlest option available to you.', zh: '今天消化系统可能出现不适。处女座的消化系统对压力和焦虑特别敏感，今天那种联系可能比平时更强。避免刺激性食物和过量饮食——今天你能给消化系统最好的礼物是朴素温热的食物和充分的休息。对吃什么有疑问时，选择最温和的选项。', ja: '消化器系に不快感が現れる可能性があります。処女座の消化器はストレスと不安に特に敏感に反応しますが、今日その連結がより強く現れる可能性があります。刺激的な食べ物と食べ過ぎを避けてください——今日あなたの消化器に与えられる最良の贈り物は素朴で温かい食事と十分な休息です。', es: 'Pueden aparecer molestias digestivas hoy—el sistema digestivo de Virgo responde de manera particularmente sensible al estrés y la ansiedad, y hoy esa conexión puede ser más fuerte de lo usual. Evita comidas picantes y comer en exceso. El mejor regalo que puedes darle a tu sistema digestivo hoy es comida simple y cálida y descanso adecuado. Cuando dudes sobre qué comer, elige la opción más suave disponible.' },
      { ko: '과도한 걱정과 불안이 신경성 증상으로 나타날 수 있습니다. 처녀자리의 분석적 두뇌가 오늘 최악의 시나리오를 계속 실행하고 있다면, 그것은 뇌의 오작동이 아니라 과부하 신호입니다. 복식호흡으로 긴장을 풀어보세요—4초 들이쉬고 4초 멈추고 6초 내쉬는 패턴이 신경계를 빠르게 안정시킵니다.', en: 'Excessive worry and anxiety may cause nervous symptoms today—if Virgo\'s analytical brain is continuously running worst-case scenarios, that is not a malfunction but a signal of overload. Try abdominal breathing to relax: inhale for 4 seconds, hold for 4 seconds, exhale for 6 seconds. This pattern quickly stabilizes the nervous system. Your body is trying to communicate what your mind is too busy to hear.', zh: '今天过度的担忧和焦虑可能表现为神经性症状。如果处女座的分析性大脑今天不断运行最坏情况的场景，那不是大脑故障，而是过载的信号。试试腹式呼吸来放松——吸气4秒，暂停4秒，呼气6秒的模式能迅速稳定神经系统。你的身体在尝试传达你的思维太忙而无法听到的信息。', ja: '過度な心配と不安が神経性の症状として現れる可能性があります。処女座の分析的な頭脳が今日最悪のシナリオを続けて実行しているなら、それは脳の誤作動ではなく過負荷のシグナルです。腹式呼吸で緊張をほぐしてみてください——4秒吸って4秒止めて6秒吐くパターンが神経系を素早く安定させます。', es: 'La preocupación excesiva puede causar síntomas nerviosos hoy—si el cerebro analítico de Virgo está continuamente ejecutando escenarios de peor caso, eso no es un mal funcionamiento sino una señal de sobrecarga. Prueba respiración abdominal para relajarte: inhala durante 4 segundos, aguanta durante 4 segundos, exhala durante 6 segundos. Este patrón estabiliza rápidamente el sistema nervioso.' },
      { ko: '수면의 질이 떨어질 수 있는 날입니다. 처녀자리의 밤은 종종 낮에 처리하지 못한 생각들이 떠오르는 시간이 됩니다. 카페인 섭취를 줄이고 취침 환경을 점검하세요—화면 빛, 소음, 온도를 조정하는 것이 의외로 큰 차이를 만들어냅니다. 몸이 쉬어야 내일의 분석력도 살아납니다.', en: 'Sleep quality may decline today—for Virgo, nights often become the time when unprocessed thoughts from the day surface. Reduce caffeine and check your sleep environment. Adjusting screen light, noise, and temperature makes surprisingly large differences. Your body must rest for tomorrow\'s analytical power to come fully alive. A rested Virgo is one of the most capable minds available to the world.', zh: '今天睡眠质量可能下降。对处女座来说，夜晚往往成为白天未处理的思绪浮现的时间。减少咖啡因摄入，检查睡眠环境——调整屏幕光、噪音和温度会出乎意料地产生很大差异。身体必须休息，明天的分析力才能完全复活。休息充分的处女座是世界上最有能力的思维之一。', ja: '睡眠の質が落ちる可能性がある日です。処女座の夜は往々にして昼間に処理しきれなかった思考が浮かび上がる時間になります。カフェイン摂取を減らし就寝環境を点検してください——画面の光、騒音、温度を調整することが意外にも大きな差を生みます。体が休まなければ明日の分析力も戻りません。', es: 'La calidad del sueño puede disminuir hoy—para Virgo, las noches a menudo se convierten en el momento en que emergen los pensamientos no procesados del día. Reduce la cafeína y revisa tu entorno para dormir. Ajustar la luz de la pantalla, el ruido y la temperatura hace diferencias sorprendentemente grandes. Tu cuerpo debe descansar para que el poder analítico de mañana se reactive completamente.' },
      { ko: '모든 것을 완벽하게 관리하려는 스트레스가 면역력을 떨어뜨릴 수 있습니다. 처녀자리의 통제 본능은 사실 깊은 불안으로부터 자신을 보호하려는 방어 기제입니다. 그것이 이해되어도, 오늘 그 기제가 당신의 몸에 해를 끼치고 있습니다. 힘을 빼세요—오늘 하루 통제할 수 없는 것들을 내려놓고 몸을 쉬게 해주세요.', en: 'Stress from trying to manage everything perfectly may weaken immunity today—Virgo\'s control instinct is actually a defense mechanism trying to protect against deep anxiety, and while that is understandable, today that mechanism is physically harmful. Let go of tension. Give yourself permission to set down what you cannot control today and let your body rest. The world will not collapse during your recovery time.', zh: '试图完美管理一切的压力今天可能降低免疫力。处女座的控制本能实际上是一种试图保护自己免受深层焦虑的防御机制，尽管这可以理解，但今天那种机制正在伤害你的身体。放松一下——今天给自己许可，放下无法控制的事情，让身体休息。在你的恢复时间里世界不会崩溃。', ja: 'すべてを完璧に管理しようとするストレスが今日免疫力を落とす可能性があります。処女座のコントロール本能は実は深い不安から自分を守ろうとする防衛機制です。それが理解できても、今日その機制があなたの体を傷つけています。力を抜いてください——今日一日コントロールできないものを下ろして体を休ませてあげてください。', es: 'El estrés de querer manejar todo perfectamente puede debilitar la inmunidad hoy—el instinto de control de Virgo es en realidad un mecanismo de defensa que intenta protegerse de la ansiedad profunda, y aunque eso es comprensible, hoy ese mecanismo es físicamente dañino. Relájate. Date permiso para dejar lo que no puedes controlar hoy y deja que tu cuerpo descanse. El mundo no colapsará durante tu tiempo de recuperación.' },
      { ko: '근육 긴장과 어깨 결림에 주의하세요. 처녀자리는 스트레스를 특히 목과 어깨에 저장하는 경향이 있습니다. 틈틈이 스트레칭하고 온찜질을 해보세요—지금 잠깐 손을 멈추고 어깨를 뒤로 밀면서 깊게 호흡해보세요. 그 10초가 오늘 하루의 긴장을 상당히 해소해줄 것입니다.', en: 'Watch for muscle tension and stiff shoulders today—Virgo tends to store stress particularly in the neck and shoulders. Stretch often and try warm compresses. Right now, stop briefly and push your shoulders back while breathing deeply. Those 10 seconds will release a significant amount of today\'s tension. Your body carries what your mind won\'t process; give it the release it\'s asking for.', zh: '今天注意肌肉紧张和肩部僵硬。处女座倾向于将压力特别储存在颈部和肩部。抽空做拉伸和热敷——现在暂停一下，将肩膀向后推同时深呼吸。那10秒将显著缓解今天的紧张。你的身体携带着你的思维不愿处理的东西；给它它所要求的释放。', ja: '筋肉の緊張と肩こりに注意してください。処女座はストレスを特に首と肩に蓄積する傾向があります。隙間時間にストレッチして温湿布を試してみてください——今すぐ少し手を止めて、肩を後ろに押しながら深呼吸してみてください。その10秒が今日の緊張をかなり解消してくれるでしょう。', es: 'Cuidado con la tensión muscular y hombros rígidos hoy—Virgo tiende a almacenar estrés particularmente en el cuello y los hombros. Estira frecuentemente y prueba compresas calientes. Ahora mismo, detente brevemente y empuja los hombros hacia atrás mientras respiras profundamente. Esos 10 segundos liberarán una cantidad significativa de la tensión de hoy. Tu cuerpo lleva lo que tu mente no procesará; dale la liberación que está pidiendo.' },
      { ko: '건강 정보를 과도하게 검색하며 불안해하지 마세요. 처녀자리는 증상이 생기면 인터넷에서 관련 정보를 검색하다가 더 큰 불안에 빠지는 경향이 있습니다. 건강 관련 검색을 오늘 하루 제한하세요. 전문가 상담이 더 정확한 답을 줍니다—진짜 문제가 있다고 느낀다면, 구글 대신 의사에게 가는 것이 올바른 선택입니다.', en: 'Don\'t anxiously over-search health information today—Virgo tends to research symptoms online and fall into greater anxiety as a result. Limit health-related searching today. A professional consultation gives more accurate and less frightening answers. If you genuinely feel something is wrong, seeing a doctor is the right choice instead of Google. Trust your body\'s signals, but don\'t amplify them with unfiltered internet information.', zh: '今天不要过度搜索健康信息而焦虑。处女座在出现症状时倾向于在网上搜索相关信息，结果陷入更大的焦虑。今天限制健康相关的搜索。专家咨询能给出更准确、更少恐惧的答案——如果真的感觉有问题，去看医生而不是谷歌才是正确的选择。相信身体的信号，但不要用未经过滤的网络信息放大它们。', ja: '健康情報を過度に検索して不安にならないでください。処女座は症状が出ると関連情報をインターネットで検索し、より大きな不安に陥る傾向があります。健康関連の検索を今日一日制限してください。専門家の相談がより正確で恐ろしくない答えをくれます——本当に何か問題があると感じたら、グーグルより医師に行くことが正しい選択です。', es: 'No busques información de salud excesivamente con ansiedad hoy—Virgo tiende a investigar síntomas en línea y caer en mayor ansiedad como resultado. Limita las búsquedas relacionadas con la salud hoy. Una consulta profesional da respuestas más precisas y menos aterradoras. Si genuinamente sientes que algo está mal, ver a un médico en lugar de Google es la elección correcta. Confía en las señales de tu cuerpo, pero no las amplifiques con información de internet sin filtrar.' },
      { ko: '직장 스트레스가 피부 트러블로 나타날 수 있습니다. 처녀자리는 내면의 스트레스가 피부와 소화기로 먼저 나타나는 별자리입니다. 충분한 수분 섭취와 수면이 필요합니다—피부를 통해 내면의 상태가 보인다면, 오늘은 외부보다 내부를 돌보는 하루로 만드세요. 좋은 잠 한 번이 가장 좋은 스킨케어입니다.', en: 'Work stress may manifest as skin trouble today—Virgo is a sign where inner stress appears first in the skin and digestive system. You need adequate hydration and sleep. If your skin is showing your inner state, today is the day to care for the inside rather than the outside. Good sleep is the best skincare, and it\'s also the fastest way to restore the clear, precise thinking Virgo relies on most.', zh: '工作压力今天可能表现为皮肤问题。处女座是内心压力首先表现在皮肤和消化系统的星座。需要充分的水分摄入和睡眠——如果皮肤在显示你的内心状态，今天是一个关注内部而非外部的日子。好好睡一觉是最好的护肤，也是恢复处女座最依赖的清晰精准思维的最快方法。', ja: '職場のストレスが肌トラブルとして現れる可能性があります。処女座は内なるストレスが皮膚と消化器に最初に現れる星座です。十分な水分摂取と睡眠が必要です——皮膚を通じて内面の状態が見えるなら、今日は外側より内側を気遣う一日にしてください。良い睡眠一つが最高のスキンケアです。', es: 'El estrés laboral puede manifestarse como problemas de piel hoy—Virgo es un signo donde el estrés interior aparece primero en la piel y el sistema digestivo. Necesitas hidratación y sueño adecuados. Si tu piel está mostrando tu estado interior, hoy es el día de cuidar el interior en lugar del exterior. El buen sueño es el mejor cuidado de la piel, y también es la forma más rápida de restaurar el pensamiento claro y preciso en el que Virgo más confía.' },
      { ko: '오늘은 강도 높은 운동보다 가벼운 산책이나 명상이 적합합니다. 처녀자리는 "운동을 해야 한다"는 의무감으로 과도하게 움직이다가 지치는 경우가 있습니다. 오늘은 몸의 회복을 우선시하세요—가벼운 10분 산책이나 조용한 명상이 고강도 운동보다 더 깊은 회복을 가져다줍니다.', en: 'Light walks or meditation suit better than intense exercise today—Virgo sometimes exercises excessively out of a sense of obligation and ends up exhausted. Prioritize recovery for your body today. A light 10-minute walk or quiet meditation brings deeper recovery than high-intensity exercise. When the body is asking for rest, the most intelligent response is to give it exactly that.', zh: '今天轻松散步或冥想比高强度运动更合适。处女座有时出于义务感过度运动而精疲力竭。今天优先考虑身体恢复——轻度10分钟散步或安静冥想比高强度运动带来更深的恢复。当身体要求休息时，最聪明的回应就是给予它正需要的。', ja: '今日は高強度の運動より軽い散歩や瞑想が適しています。処女座は「運動しなければならない」という義務感で過度に動きすぎて疲れてしまうことがあります。今日は体の回復を優先してください——軽い10分の散歩や静かな瞑想が高強度の運動より深い回復をもたらします。', es: 'Hoy son mejores las caminatas ligeras o meditación que el ejercicio intenso—Virgo a veces hace ejercicio excesivamente por sentido de obligación y termina agotado. Prioriza la recuperación de tu cuerpo hoy. Una caminata ligera de 10 minutos o meditación tranquila trae una recuperación más profunda que el ejercicio de alta intensidad. Cuando el cuerpo pide descanso, la respuesta más inteligente es darle exactamente eso.' },
      { ko: '신경이 예민해져 두통이 올 수 있습니다. 처녀자리는 과한 정보와 자극에 노출될 때 신경계가 과부하에 걸리는 경향이 있습니다. 전자기기 사용을 줄이고 자연광 속에서 휴식하세요—화면에서 벗어나 하늘을 바라보는 5분이, 무한 스크롤보다 당신의 신경계를 훨씬 더 잘 회복시켜줍니다.', en: 'Frayed nerves may bring headaches today—Virgo\'s nervous system tends to become overloaded when exposed to excessive information and stimulation. Reduce device use and rest in natural light. Five minutes of looking away from screens toward the sky restores your nervous system far better than infinite scrolling does. Your attention is one of your most precious resources—protect it deliberately today.', zh: '今天神经敏感可能导致头痛。处女座的神经系统在暴露于过多信息和刺激时倾向于过载。减少电子设备使用，在自然光中休息——离开屏幕仰望天空的5分钟，比无限滚动更能恢复你的神经系统。你的注意力是你最宝贵的资源之一——今天有意识地保护它。', ja: '神経が敏感になって頭痛が来る可能性があります。処女座の神経系は過剰な情報と刺激にさらされると過負荷になる傾向があります。電子機器の使用を減らし自然光の中で休息してください——画面から離れて空を眺める5分間が、無限スクロールよりあなたの神経系をずっとよく回復させてくれます。', es: 'Los nervios sensibles pueden traer dolor de cabeza hoy—el sistema nervioso de Virgo tiende a sobrecargarse cuando se expone a información y estimulación excesivas. Reduce el uso de dispositivos y descansa con luz natural. Cinco minutos de mirar hacia el cielo alejándote de las pantallas restaura tu sistema nervioso mucho mejor que el desplazamiento infinito. Tu atención es uno de tus recursos más preciosos—protégelo deliberadamente hoy.' },
      { ko: '건강에 대한 과도한 집착이 오히려 스트레스를 유발합니다. 아이러니하게도 처녀자리의 건강에 대한 강한 관심이 때로는 건강 불안(health anxiety)으로 이어져 더 큰 스트레스를 만들어냅니다. 적당히 관리하고 마음을 편히 가지세요—건강한 삶은 완벽한 관리가 아닌 지속 가능한 즐거움에서 옵니다.', en: 'Excessive obsession with health causes more stress today—ironically, Virgo\'s strong interest in health sometimes leads to health anxiety that creates even greater stress. Manage moderately and ease your mind. Healthy living comes not from perfect management but from sustainable enjoyment. The moments of genuine pleasure you allow yourself are as healing as any supplement or protocol. Permission to rest is also medicine.', zh: '对健康的过度执着今天反而会引发更多压力。讽刺的是，处女座对健康的强烈关注有时会导致健康焦虑，从而制造更大的压力。适度管理，放松心情——健康的生活来自可持续的享受而非完美的管理。你允许自己拥有的真正快乐时刻与任何补充剂或方案一样具有治愈作用。休息的许可也是一种药。', ja: '健康への過度なこだわりがかえってストレスを引き起こします。皮肉なことに処女座の健康への強い関心が時に健康不安(health anxiety)につながり、さらに大きなストレスを生み出します。適度に管理して心を楽に持ってください——健康な生活は完璧な管理ではなく持続可能な喜びから来ます。自分に許した本物の喜びの瞬間がどんなサプリやプロトコルと同じくらい癒しになります。', es: 'La obsesión excesiva con la salud causa más estrés hoy—irónicamente, el fuerte interés de Virgo en la salud a veces lleva a ansiedad de salud que crea aún mayor estrés. Gestiona con moderación y relaja tu mente. La vida saludable viene no de la gestión perfecta sino del disfrute sostenible. Los momentos de placer genuino que te permites son tan curativos como cualquier suplemento o protocolo. El permiso para descansar también es medicina.' },
    ],
  },
  money: {
    high: [
      { ko: '꼼꼼한 재정 분석이 숨겨진 절약 기회를 발견하게 합니다. 처녀자리의 날카로운 분석 눈이 재정 데이터를 살펴볼 때, 다른 사람들이 그냥 지나치는 비효율적인 지출 패턴이 선명하게 보입니다. 가계부를 점검해보세요—오늘 발견하는 작은 절약 포인트 하나가 장기적으로 상당한 차이를 만들어냅니다.', en: 'Meticulous financial analysis reveals hidden savings opportunities today—when Virgo\'s sharp analytical eye examines financial data, inefficient spending patterns that others walk past become clearly visible. Check your household budget carefully. One small savings point discovered today creates a substantial long-term difference when compounded. Your ability to find these hidden leaks is a genuine financial superpower.', zh: '今天细致的财务分析让你发现隐藏的节约机会。当处女座敏锐的分析眼光审视财务数据时，他人忽略的低效支出模式清晰可见。检查一下家计簿——今天发现的一个小节约点长期复利后会产生相当大的差异。你发现这些隐藏漏洞的能力是真正的财务超能力。', ja: '丁寧な財務分析が隠れた節約の機会を発見させます。処女座の鋭い分析眼が財務データを見る時、他の人がそのまま通り過ぎる非効率な支出パターンが鮮明に見えます。家計簿を点検してみてください——今日発見する小さな節約ポイント一つが長期的にかなりの差を生み出します。', es: 'El análisis financiero meticuloso revela oportunidades de ahorro ocultas hoy—cuando el ojo analítico agudo de Virgo examina datos financieros, los patrones de gasto ineficientes que otros pasan por alto se vuelven claramente visibles. Revisa tu presupuesto cuidadosamente. Un pequeño punto de ahorro descubierto hoy crea una diferencia sustancial a largo plazo cuando se acumula. Tu capacidad de encontrar estas fugas ocultas es un genuino superpoder financiero.' },
      { ko: '수성의 소통 에너지가 금전적 협상에서 유리한 결과를 이끌어냅니다. 처녀자리는 논리적 근거와 정확한 데이터를 바탕으로 하는 협상에서 특히 강한데, 오늘 그 능력이 극대화됩니다. 당당하게 가치를 주장하세요—당신이 제공하는 것의 진정한 가치를 과소평가하지 마세요.', en: 'Mercury\'s communication energy leads to favorable financial negotiations today—Virgo is especially strong in negotiations backed by logical reasoning and precise data, and today that ability is maximized. Assert your value confidently. Don\'t underestimate the true value of what you provide. You have done the preparation; now trust the numbers and advocate for what you genuinely deserve.', zh: '水星的沟通能量今天在金钱谈判中带来有利结果。处女座在以逻辑理由和精确数据为后盾的谈判中特别强，今天那种能力达到最大化。自信地主张你的价值——不要低估你所提供的真正价值。你已经做了准备；现在信任数字，为你真正应得的东西辩护。', ja: '水星のコミュニケーションエネルギーが金銭的な交渉で有利な結果を導きます。処女座は論理的な根拠と正確なデータに基づく交渉で特に強いですが、今日その能力が最大化されます。堂々と価値を主張してください——あなたが提供するものの真の価値を過小評価しないでください。', es: 'La energía comunicativa de Mercurio lleva a negociaciones financieras favorables hoy—Virgo es especialmente fuerte en negociaciones respaldadas por razonamiento lógico y datos precisos, y hoy esa habilidad se maximiza. Afirma tu valor con confianza. No subestimes el verdadero valor de lo que ofreces. Has hecho la preparación; ahora confía en los números y aboga por lo que genuinamente mereces.' },
      { ko: '장기적으로 준비해온 투자나 저축이 가시적인 성과를 보이는 시기입니다. 처녀자리는 화려한 수익보다 꾸준하고 안정적인 성장을 선호하는 재정 철학을 가지고 있는데, 그 철학이 오늘 보상을 받습니다. 오랫동안 쌓아온 것들이 드디어 눈에 보이는 형태로 나타나고 있습니다—이 순간을 충분히 느끼세요.', en: 'Long-term investments or savings you\'ve prepared show visible results now—Virgo has a financial philosophy that prefers steady, stable growth over flashy returns, and today that philosophy is being rewarded. What you\'ve been building for a long time is finally appearing in visible form. Feel this moment fully, because the discipline that created it is the same discipline that will compound it further into the future.', zh: '长期准备的投资或储蓄现在开始显现可见成果。处女座有偏好稳定增长而非华丽回报的财务哲学，今天那种哲学正在获得回报。你长期积累的东西终于以可见的形式出现了——充分感受这个时刻，因为创造它的纪律同样会在未来进一步复利它。', ja: '長期的に準備してきた投資や貯蓄が目に見える成果を示す時期です。処女座は派手なリターンより着実で安定した成長を好む財政哲学を持っていますが、今日その哲学が報われます。長い間積み上げてきたものがついに目に見える形で現れています——この瞬間を十分に感じてください。', es: 'Las inversiones o ahorros a largo plazo que has preparado muestran resultados visibles ahora—Virgo tiene una filosofía financiera que prefiere el crecimiento constante y estable sobre los rendimientos llamativos, y hoy esa filosofía está siendo recompensada. Lo que has estado construyendo durante mucho tiempo está finalmente apareciendo en forma visible. Siente este momento plenamente, porque la disciplina que lo creó es la misma que lo seguirá componiéndolo en el futuro.' },
      { ko: '전문 지식을 활용한 부수입 기회가 열릴 수 있습니다. 처녀자리는 자신이 가진 전문성과 지식의 가치를 종종 과소평가하는데, 다른 사람들은 그것을 위해 기꺼이 돈을 지불할 준비가 되어 있습니다. 컨설팅이나 강의 제안에 귀 기울이세요—오늘 들어오는 제안이 당신의 경력에 새로운 수익 경로를 열 수 있습니다.', en: 'Side income opportunities using your expertise may open up today—Virgo often underestimates the value of their expertise and knowledge, but others are ready and willing to pay for it. Pay attention to consulting or lecture offers. A proposal arriving today could open a new income pathway in your career. Your knowledge is a genuine asset that can be monetized, and Virgo\'s precise delivery makes it especially compelling.', zh: '今天利用专业知识的副收入机会可能出现。处女座经常低估自己拥有的专业技能和知识的价值，但其他人已经准备好为此付费。关注咨询或讲课的提议——今天收到的提案可能为你的职业生涯开辟新的收入途径。你的知识是可以变现的真正资产，处女座精确的交付方式使其特别引人注目。', ja: '専門知識を活用した副収入の機会が今日開ける可能性があります。処女座は自分が持つ専門性と知識の価値をしばしば過小評価しますが、他の人はそれのために喜んでお金を支払う準備ができています。コンサルティングや講義の提案に耳を傾けてください——今日入る提案があなたのキャリアに新しい収益経路を開く可能性があります。', es: 'Pueden abrirse oportunidades de ingresos extra usando tu experiencia hoy—Virgo a menudo subestima el valor de su experiencia y conocimiento, pero otros están listos y dispuestos a pagar por ello. Presta atención a ofertas de consultoría o conferencias. Una propuesta llegando hoy podría abrir un nuevo camino de ingresos en tu carrera. Tu conocimiento es un activo genuino que puede monetizarse, y la entrega precisa de Virgo lo hace especialmente convincente.' },
      { ko: '실용적인 소비 습관이 재정적 여유를 만들어냅니다. 처녀자리는 과시적 소비보다 가치 대비 성과를 따지는 소비 철학을 가지고 있으며, 그것이 장기적으로 재정적 자유의 기반이 됩니다. 현명한 지출이 최고의 투자입니다—오늘 당신이 지출하는 모든 것이 진정으로 삶의 질을 높이는지 한 번 더 확인해보세요.', en: 'Practical spending habits create financial freedom today—Virgo has a consumption philosophy focused on value-for-performance rather than conspicuous spending, and that becomes the foundation of long-term financial freedom. Smart spending is the best investment. Check one more time today whether everything you spend money on genuinely improves your quality of life. That single question, asked consistently, is worth more than any budget app.', zh: '实用的消费习惯今天创造财务余裕。处女座有注重性价比而非炫耀性消费的消费哲学，这长期来看成为财务自由的基础。明智的支出是最好的投资——今天再确认一次，你花的每一分钱是否真正提高了生活质量。这个问题持续问下去，比任何预算应用都更有价值。', ja: '実用的な消費習慣が今日財政的な余裕を作り出します。処女座は見栄えより価値対効果を重視する消費哲学を持っており、それが長期的に財政的自由の基盤になります。賢い支出が最高の投資です——今日支出するものすべてが本当に生活の質を高めているかもう一度確認してみてください。', es: 'Los hábitos de gasto prácticos crean libertad financiera hoy—Virgo tiene una filosofía de consumo enfocada en el rendimiento por valor en lugar del gasto ostentoso, y eso se convierte en la base de la libertad financiera a largo plazo. Gastar con inteligencia es la mejor inversión. Verifica una vez más hoy si todo en lo que gastas dinero genuinamente mejora tu calidad de vida. Esa pregunta única, hecha consistentemente, vale más que cualquier aplicación de presupuesto.' },
      { ko: '흙 원소의 풍요 에너지가 재물운을 상승시킵니다. 처녀자리의 흙 원소가 오늘 풍요와 안정의 에너지를 극대화하며, 안정적인 수입 흐름이 유지됩니다. 이 풍요의 에너지를 활용하여 오래 미루어온 재정 목표를 다시 점검하세요—오늘이 그 계획을 실행에 옮기기에 가장 좋은 날입니다.', en: 'Earth element\'s abundance energy boosts your financial fortune today—Virgo\'s earth element maximizes the energy of abundance and stability, with stable income flow maintained. Use this abundance energy to re-examine long-postponed financial goals. Today is the best day to move those plans into execution. The conditions are aligned, and your earth-element groundedness ensures decisions made today are both wise and durable.', zh: '土元素的丰饶能量今天提升财运。处女座的土元素最大化丰饶和稳定的能量，稳定的收入流继续维持。利用这种丰饶能量，重新审视长期推迟的财务目标——今天是将那些计划付诸实施的最佳日子。', ja: '土のエレメントの豊穣エネルギーが財運を上昇させます。処女座の土のエレメントが今日豊かさと安定のエネルギーを最大化し、安定した収入の流れが維持されます。この豊かさのエネルギーを活用して長い間先延ばしにしてきた財政目標を再点検してください——今日がその計画を実行に移す最良の日です。', es: 'La energía de abundancia del elemento tierra impulsa tu fortuna financiera hoy—el elemento tierra de Virgo maximiza la energía de abundancia y estabilidad, con el flujo de ingresos estable manteniéndose. Usa esta energía de abundancia para re-examinar metas financieras largo tiempo pospuestas. Hoy es el mejor día para mover esos planes hacia la ejecución. Las condiciones están alineadas, y la solidez de tu elemento tierra asegura que las decisiones tomadas hoy sean tanto sabias como duraderas.' },
      { ko: '세밀한 계약 검토가 예상치 못한 이익을 가져다줍니다. 처녀자리는 계약서의 작은 글씨를 읽어내는 타고난 능력을 가지고 있으며, 오늘 그 능력이 실질적인 재정적 이익으로 이어질 수 있습니다. 작은 글씨도 놓치지 마세요—오늘 당신이 발견하는 조항 하나가 상당한 금액의 차이를 만들 수 있습니다.', en: 'Detailed contract review brings unexpected gains today—Virgo has an innate ability to read the fine print in contracts, and today that ability can lead to tangible financial benefit. Don\'t miss any fine print. A single clause you discover today could create a significant monetary difference. Your careful reading is both a protection against loss and an active source of gain. Apply it without apology.', zh: '今天仔细的合同审查带来意想不到的利益。处女座天生具有读取合同小字条款的能力，今天那种能力可以带来实质性的财务收益。不要忽略小字条款——今天你发现的一个条款可能造成相当数额的差异。你仔细的阅读既是防止损失的保护，也是主动的收益来源。毫无歉意地运用它。', ja: '細やかな契約検討が予想外の利益をもたらします。処女座は契約書の小さな文字を読み取る生まれながらの能力を持っており、今日その能力が実質的な財政的利益につながる可能性があります。小さな文字も見逃さないでください——今日あなたが発見する条項一つがかなりの金額の差を生み出すかもしれません。', es: 'La revisión detallada de contratos trae ganancias inesperadas hoy—Virgo tiene una habilidad innata para leer la letra pequeña en contratos, y hoy esa habilidad puede conducir a beneficios financieros tangibles. No pierdas la letra pequeña. Una cláusula que descubras hoy podría crear una diferencia monetaria significativa. Tu lectura cuidadosa es tanto una protección contra pérdidas como una fuente activa de ganancias.' },
      { ko: '체계적인 재무 계획이 경제적 자유에 한 걸음 더 다가가게 합니다. 처녀자리에게 재무 계획은 제약이 아닌 자유를 위한 설계입니다. 목표를 재확인하세요—지금 어디에 있고 어디를 향하고 있는지를 명확히 보는 것이 처녀자리의 재정 여정에서 가장 강력한 도구입니다. 지도 없이 걷지 마세요.', en: 'Systematic financial planning brings you one step closer to economic freedom today—for Virgo, financial planning is not a constraint but a design for freedom. Reconfirm your goals. Clearly seeing where you are and where you\'re headed is the most powerful tool in Virgo\'s financial journey. Don\'t walk without a map. The precision you bring to other areas of life, applied to finances, creates extraordinary results over time.', zh: '今天系统的财务规划让你更接近经济自由。对处女座来说，财务规划不是约束而是为自由设计。重新确认你的目标——清楚地看到你现在在哪里以及你正在走向哪里，是处女座财务旅程中最强大的工具。不要没有地图地行走。', ja: '体系的な財務計画が経済的自由に今日一歩近づかせます。処女座にとって財務計画は制約ではなく自由のための設計です。目標を再確認してください——今どこにいてどこへ向かっているかを明確に見ることが処女座の財政の旅で最も強力なツールです。地図なしで歩かないでください。', es: 'La planificación financiera sistemática te acerca un paso más a la libertad económica hoy—para Virgo, la planificación financiera no es una restricción sino un diseño para la libertad. Reconfirma tus metas. Ver claramente dónde estás y hacia dónde te diriges es la herramienta más poderosa en el viaje financiero de Virgo. No camines sin mapa. La precisión que aportas a otras áreas de la vida, aplicada a las finanzas, crea resultados extraordinarios con el tiempo.' },
      { ko: '불필요한 지출을 줄인 노력이 통장 잔고로 보답합니다. 처녀자리의 절약 정신은 인색함이 아니라 현명함의 표현입니다. 알뜰한 생활이 빛나는 날입니다—오늘 잔고를 확인하면서 그 숫자 뒤에 있는 당신의 의식적인 선택들을 자랑스럽게 느껴보세요. 그 절제가 결국 진정한 자유를 만들어냅니다.', en: 'Efforts to cut unnecessary spending are rewarded in your bank balance today—Virgo\'s thrifty spirit is an expression of wisdom, not stinginess. Your frugal lifestyle genuinely shines right now. Check your balance today and feel proud of the conscious choices behind that number. The restraint you\'ve practiced is ultimately creating genuine freedom—a word that means something very different when you have the financial security to back it up.', zh: '减少不必要支出的努力今天在银行余额中得到回报。处女座的节俭精神是智慧而非吝啬的表达。节俭生活今天闪耀着光芒——查看余额时，为那个数字背后的有意识选择感到自豪。你所实践的克制最终创造了真正的自由——当你有财务安全支撑时，这个词意味着截然不同的东西。', ja: '不要な支出を減らした努力が通帳残高で報います。処女座の節約精神はけちではなく賢さの表れです。倹約な生活が輝く日です——今日残高を確認しながら、その数字の背景にあるあなたの意識的な選択を誇らしく感じてみてください。その節制が結局真の自由を作り出します。', es: 'Los esfuerzos por reducir gastos innecesarios se recompensan en tu saldo bancario hoy—el espíritu ahorrativo de Virgo es una expresión de sabiduría, no de tacañería. Tu estilo de vida frugal genuinamente brilla ahora mismo. Revisa tu saldo hoy y siéntete orgulloso de las elecciones conscientes detrás de ese número. La moderación que has practicado está creando en última instancia una libertad genuina.' },
      { ko: '건강한 재정 습관이 마음의 안정까지 가져다주는 날입니다. 처녀자리에게 재정적 불안은 정신 건강을 크게 위협하는 요소인데, 오늘 그 불안이 사라진 자리에 평온함이 들어와 있습니다. 돈 걱정 없는 평온함을 느끼세요—이것이 처녀자리가 재정을 잘 관리할 때 얻는 가장 소중한 보상입니다.', en: 'Healthy financial habits bring peace of mind today—financial anxiety is a major threat to Virgo\'s mental health, and today that anxiety has given way to tranquility. Feel the calm of financial security fully. This is the most precious reward Virgo receives when managing finances well—not just wealth itself, but the mental freedom that comes when money worries no longer occupy your analytical mind\'s precious capacity.', zh: '健康的财务习惯今天也带来内心的安宁。对处女座来说，财务焦虑是严重威胁心理健康的因素，今天那种焦虑退场，平静进来了。充分感受没有金钱忧虑的平静——这是处女座在理财得当时获得的最宝贵的奖励，不只是财富本身，而是当金钱忧虑不再占据你分析性思维宝贵容量时所获得的心灵自由。', ja: '健全な財政習慣が心の安定までもたらす日です。処女座にとって財政的不安は精神健康を大きく脅かす要素ですが、今日その不安が消えた場所に平穏さが入ってきています。お金の心配のない平穏さを感じてください——これが処女座が財政をしっかり管理した時に得る最も大切な報酬です。', es: 'Los hábitos financieros saludables traen paz mental hoy—la ansiedad financiera es una amenaza importante para la salud mental de Virgo, y hoy esa ansiedad ha dado paso a la tranquilidad. Siente plenamente la calma de la seguridad financiera. Esta es la recompensa más preciosa que Virgo recibe cuando gestiona bien las finanzas—no solo la riqueza en sí, sino la libertad mental que llega cuando las preocupaciones monetarias ya no ocupan la preciosa capacidad de tu mente analítica.' },
    ],
    medium: [
      { ko: '안정적인 재정 상태가 유지됩니다. 처녀자리의 꼼꼼한 재정 관리가 이 안정의 조용한 기반입니다. 큰 변동 없이 계획대로 지출을 관리하세요—이 안정은 당연한 것이 아니라 당신의 의식적인 노력의 결과이며, 그것을 인식하는 것 자체가 앞으로의 재정 행동에 긍정적인 영향을 줍니다.', en: 'Stable financial status continues today—Virgo\'s meticulous financial management is the quiet foundation of this stability. Manage spending as planned without major changes. This stability is not something to take for granted; it is the result of your conscious effort, and recognizing that itself has a positive impact on your financial behavior going forward. Appreciate what steady discipline has built.', zh: '今天稳定的财务状况得以维持。处女座细致的财务管理是这种稳定的安静基础。按计划管理支出，没有大的变动——这种稳定不是理所当然的，而是你有意识努力的结果。认识到这一点本身就会对你未来的财务行为产生积极影响。欣赏稳定纪律所建立的东西。', ja: '安定した財政状態が維持されます。処女座の丁寧な財政管理がこの安定の静かな基盤です。大きな変動なく計画通りに支出を管理してください——この安定は当然のことではなく、あなたの意識的な努力の結果であり、それを認識すること自体が今後の財政行動にポジティブな影響を与えます。', es: 'El estado financiero estable continúa hoy—la meticulosa gestión financiera de Virgo es la base silenciosa de esta estabilidad. Gestiona los gastos según el plan sin grandes cambios. Esta estabilidad no es algo que dar por sentado; es el resultado de tu esfuerzo consciente, y reconocer eso en sí mismo tiene un impacto positivo en tu comportamiento financiero en el futuro. Aprecia lo que ha construido la disciplina constante.' },
      { ko: '가격 대비 가치를 따지는 당신의 습관이 합리적인 소비를 이끕니다. 처녀자리는 충동적으로 사지 않고 진정한 가치를 분석하는 능력이 있어, 그 습관이 장기적으로 상당한 절약을 만들어냅니다. 비교 검색을 활용하세요—오늘 이 습관을 의식적으로 더 철저하게 적용하면 좋은 결과가 있을 것입니다.', en: 'Your habit of weighing value for money leads to rational spending today—Virgo has the ability to analyze true value rather than buying impulsively, and that habit creates substantial long-term savings. Use comparison shopping. Consciously applying this habit more thoroughly today will yield good results. The small amount of extra time you invest in comparison is consistently returned at a significant multiple.', zh: '你注重性价比的习惯今天引导合理消费。处女座有分析真正价值而非冲动购买的能力，这种习惯长期来看创造了可观的节约。利用比价搜索——今天更彻底地有意识地应用这种习惯会有好的结果。你在比较上投入的少量额外时间始终以相当大的倍数返回。', ja: '価格対価値を見極めるあなたの習慣が今日合理的な消費を導きます。処女座は衝動的に買わず真の価値を分析する能力があり、その習慣が長期的にかなりの節約を作り出します。比較検索を活用してください——今日この習慣をより意識的に徹底的に適用すると良い結果があるでしょう。', es: 'Tu hábito de evaluar la relación calidad-precio lleva a un gasto racional hoy—Virgo tiene la habilidad de analizar el verdadero valor en lugar de comprar impulsivamente, y ese hábito crea ahorros sustanciales a largo plazo. Usa la comparación de precios. Aplicar este hábito más conscientemente y a fondo hoy producirá buenos resultados. La pequeña cantidad de tiempo adicional que inviertes en comparación se devuelve consistentemente en un múltiplo significativo.' },
      { ko: '저축 목표를 점검하고 필요하면 금액을 조정하세요. 처녀자리는 목표를 세밀하게 설정하는 데 탁월하지만, 현실이 변하면 목표도 유연하게 조정해야 합니다. 현실적인 목표가 동기를 유지시킵니다—너무 높아서 좌절을 주는 목표보다 꾸준히 달성 가능한 목표가 장기적으로 훨씬 더 많은 것을 만들어냅니다.', en: 'Check savings goals and adjust amounts if needed today—Virgo excels at setting detailed goals, but when reality changes, goals must also be flexibly adjusted. Realistic goals maintain motivation far better than impossible ones. A goal that is consistently achievable builds far more over the long term than one that is so high it creates only frustration. Adjust without shame; staying the course matters more than any original number.', zh: '今天检查储蓄目标，必要时调整金额。处女座擅长精细地设定目标，但现实变化时，目标也需要灵活调整。现实的目标比不可能的目标更能维持动力——持续可实现的目标长期来看比因太高而只带来挫折的目标创造更多。毫无羞愧地调整；坚持方向比任何原始数字都更重要。', ja: '貯蓄目標を点検し必要なら金額を調整してください。処女座は目標を細かく設定するのに優れていますが、現実が変わると目標も柔軟に調整する必要があります。現実的な目標が動機を維持します——達成可能な目標が長期的にはるかに多くのものを作り出します。恥ずかしがらずに調整してください。方向を維持することが元々の数字より重要です。', es: 'Revisa las metas de ahorro y ajusta montos si es necesario hoy—Virgo sobresale en establecer metas detalladas, pero cuando la realidad cambia, las metas también deben ajustarse flexiblemente. Las metas realistas mantienen la motivación mucho mejor que las imposibles. Una meta consistentemente alcanzable construye mucho más a largo plazo que una que es tan alta que solo crea frustración. Ajusta sin vergüenza; mantener el rumbo importa más que cualquier número original.' },
      { ko: '불필요한 구독 서비스나 정기 지출을 재점검해보세요. 처녀자리의 체계적인 분석이 오늘 이 작업에 딱 맞습니다. 매월 빠져나가지만 실제로 사용하지 않는 지출들을 찾아내세요. 작은 절약이 모여 큰 차이를 만듭니다—월 2만원의 절약이 10년이면 상당한 금액이 됩니다. 지금 확인해보세요.', en: 'Re-examine unnecessary subscriptions or recurring expenses today—Virgo\'s systematic analysis is perfectly suited for this task right now. Find the payments going out monthly that you\'re not actually using. Small savings add up to big differences. Saving the equivalent of a modest monthly amount compounds into a substantial sum over ten years. Check your subscriptions now and cancel what no longer serves you.', zh: '今天重新审视不必要的订阅服务或定期支出。处女座系统化的分析今天非常适合这项工作。找出每月支出但实际上没有使用的费用。小节约积少成多——每月节约少量金额，十年后就变成可观的数目。现在检查你的订阅，取消不再服务你的。', ja: '不要なサブスクリプションや定期支出を今日再点検してみてください。処女座の体系的な分析が今日この作業にぴったりです。毎月引き落とされているが実際には使っていない支出を見つけ出してください。小さな節約が集まって大きな違いを生みます——月2万円の節約が10年でかなりの金額になります。今確認してみてください。', es: 'Reexamina suscripciones o gastos recurrentes innecesarios hoy—el análisis sistemático de Virgo es perfectamente adecuado para esta tarea ahora mismo. Encuentra los pagos que salen mensualmente pero que en realidad no estás usando. Los pequeños ahorros suman grandes diferencias. Ahorrar un modesto monto mensual se acumula en una suma sustancial en diez años. Revisa tus suscripciones ahora y cancela lo que ya no te sirve.' },
      { ko: '지출 기록을 정리하면 돈의 흐름이 보입니다. 처녀자리의 분석 능력이 가장 빛나는 영역 중 하나가 바로 이 패턴 인식입니다. 이번 주 지출 내역을 카테고리별로 분석해보세요—숫자들이 당신의 실제 우선순위를 거울처럼 보여줄 것입니다. 그 거울이 보여주는 것을 솔직하게 받아들이세요.', en: 'Organizing spending records reveals money flow today—one of the areas where Virgo\'s analytical ability shines most brightly is exactly this pattern recognition. Analyze this week\'s expenses by category. The numbers will mirror your actual priorities back to you with perfect honesty. Accept what that mirror shows you honestly—it is the starting point of every meaningful financial improvement you can make from here.', zh: '整理支出记录今天就能看到资金流向。处女座分析能力最闪耀的领域之一就是这种模式识别。按类别分析本周的支出明细——数字将如镜子般完全诚实地向你展示你的实际优先事项。诚实地接受那面镜子所展示的内容——那是你从此能做出的每一个有意义的财务改善的起点。', ja: '支出記録を整理するとお金の流れが見えます。処女座の分析能力が最も輝く領域の一つがまさにこのパターン認識です。今週の支出内容をカテゴリー別に分析してみてください——数字があなたの実際の優先順位を鏡のように見せてくれるでしょう。その鏡が見せるものを正直に受け入れてください。', es: 'Organizar los registros de gasto revela el flujo de dinero hoy—una de las áreas donde más brilla la capacidad analítica de Virgo es exactamente este reconocimiento de patrones. Analiza los gastos de esta semana por categoría. Los números te mostrarán tus prioridades reales como un espejo con perfecta honestidad. Acepta honestamente lo que ese espejo te muestra—es el punto de partida de cada mejora financiera significativa que puedes hacer desde aquí.' },
      { ko: '충동구매 충동이 있다면 24시간 대기 규칙을 적용하세요. 처녀자리는 논리적으로 생각하는 사람이지만, 특정 상황에서 감정적 구매를 할 수 있습니다. 내일도 갖고 싶으면 그때 사세요—24시간 후에도 그것이 필요하다고 느껴진다면 그때 구매하는 것이 진정한 필요, 아니라면 충동이었던 것입니다.', en: 'If you feel impulse buying urges, apply the 24-hour rule today—Virgo is a logical thinker but can make emotional purchases in certain situations. Buy it tomorrow if you still want it. If after 24 hours it still feels necessary, that purchase is a genuine need; if not, it was an impulse. This simple rule saves Virgo from a significant portion of purchases they would regret, and the money saved is real money gained.', zh: '如果有冲动购买的欲望，今天适用24小时等待规则。处女座是逻辑思维者，但在特定情况下可能做出情绪性购买。明天还想要再买——24小时后如果仍然感到需要，那次购买是真正的需求；如果不是，那就是冲动。这个简单规则为处女座省去了相当一部分他们会后悔的购买，省下的钱就是真正赚到的钱。', ja: '衝動買いの衝動があれば24時間待機ルールを今日適用してください。処女座は論理的に考える人ですが、特定の状況で感情的な購入をすることがあります。明日も欲しければその時買いましょう——24時間後もそれが必要だと感じれば真の必要、そうでなければ衝動だったということです。', es: 'Si sientes impulso de comprar, aplica la regla de 24 horas hoy—Virgo es un pensador lógico pero puede hacer compras emocionales en ciertas situaciones. Cómpralo mañana si aún lo quieres. Si después de 24 horas aún se siente necesario, esa compra es una necesidad genuina; si no, era un impulso. Esta simple regla salva a Virgo de una parte significativa de compras de las que se arrepentiría, y el dinero ahorrado es dinero real ganado.' },
      { ko: '재테크 공부를 시작하기 좋은 시기입니다. 처녀자리의 분석적 두뇌와 수성의 학습 에너지가 결합하면 금융 지식을 흡수하는 속도가 평소보다 훨씬 빠릅니다. 수성의 학습 에너지로 금융 지식을 쌓으세요—한 권의 책이나 한 가지 개념이 당신의 재정 미래를 바꿀 수 있습니다.', en: 'A good time to start studying finance today—when Virgo\'s analytical brain combines with Mercury\'s learning energy, the speed of absorbing financial knowledge becomes much faster than usual. Build financial knowledge with Mercury\'s learning energy. One book or one concept can change your financial future. The knowledge Virgo accumulates compounds just as surely as the money it helps manage wisely.', zh: '今天是开始学习理财的好时机。当处女座的分析性大脑与水星的学习能量结合时，吸收金融知识的速度比平时快得多。利用水星的学习能量积累金融知识——一本书或一个概念可以改变你的财务未来。处女座积累的知识像它帮助明智管理的金钱一样可靠地复利增长。', ja: '財テクの勉強を始めるのに良い時期です。処女座の分析的な頭脳と水星の学習エネルギーが組み合わさると、金融知識を吸収する速度が普段よりずっと速くなります。水星の学習エネルギーで金融知識を積み上げてください——一冊の本や一つの概念があなたの財政の未来を変えることができます。', es: 'Buen momento para empezar a estudiar finanzas hoy—cuando el cerebro analítico de Virgo se combina con la energía de aprendizaje de Mercurio, la velocidad de absorber conocimiento financiero se vuelve mucho más rápida de lo usual. Acumula conocimiento financiero con la energía de aprendizaje de Mercurio. Un libro o un concepto puede cambiar tu futuro financiero. El conocimiento que Virgo acumula se compone tan seguramente como el dinero que ayuda a gestionar sabiamente.' },
      { ko: '타인에게 금전적 도움을 줄 때는 감당 가능한 범위 내에서만 하세요. 처녀자리의 봉사 정신은 타고난 것이지만, 자신의 재정 건강을 희생하면서까지 줄 수는 없습니다. 봉사와 재정 건전성의 균형이 필요합니다—빈 컵으로는 다른 사람을 채울 수 없습니다. 재정적 경계 설정도 사랑의 한 형태입니다.', en: 'When giving financial help, stay within what you can afford today—Virgo\'s spirit of service is innate, but you cannot give until it sacrifices your own financial health. Balance service and financial health. You cannot fill others from an empty cup. Setting financial boundaries is also a form of love—both for yourself and for others who benefit most from a financially stable version of you, not a depleted one.', zh: '今天给他人经济帮助时只在可承受范围内。处女座的奉献精神是天生的，但不能牺牲自己的财务健康去给予。需要平衡奉献和财务健全——空杯子无法填满他人。设定财务边界也是一种爱的形式——对你自己和对那些从财务稳定的你那里受益最多的人，而不是精疲力竭的你。', ja: '他人に金銭的な助けを与える時は感当可能な範囲内でだけにしてください。処女座の奉仕精神は生まれながらのものですが、自分の財政健康を犠牲にしてまで与えることはできません。奉仕と財政健全性のバランスが必要です——空のコップからは他の人を満たすことができません。財政的な境界設定も愛の一形態です。', es: 'Al dar ayuda financiera, quédate dentro de lo que puedas hoy—el espíritu de servicio de Virgo es innato, pero no puedes dar hasta sacrificar tu propia salud financiera. Equilibra el servicio y la salud financiera. No puedes llenar a otros desde una copa vacía. Establecer límites financieros también es una forma de amor—tanto para ti como para otros que se benefician más de una versión financieramente estable de ti, no de una agotada.' },
      { ko: '현재 수입 내에서 만족감을 찾는 연습을 하세요. 처녀자리는 더 나은 상태를 향한 끊임없는 개선 욕구를 가지고 있는데, 그것이 재정에서는 영원한 불만족으로 이어질 수 있습니다. 감사하는 마음이 풍요를 부릅니다—지금 가진 것에 대한 진심 어린 감사가 오히려 더 많은 것을 끌어당기는 역설을 경험해보세요.', en: 'Practice finding contentment within current income today—Virgo has a constant desire for improvement toward a better state, but in finances that can lead to perpetual dissatisfaction. A grateful heart attracts abundance. Experience the paradox that genuine gratitude for what you have now actually draws more toward you. Contentment is not the enemy of ambition; it is the peaceful foundation from which sustainable ambition grows.', zh: '今天练习在现有收入中寻找满足感。处女座有对更好状态的不断改进欲望，但在财务上这可能导致永久的不满足。感恩的心会带来富足——体验对你现在拥有的真诚感恩实际上会吸引更多的悖论。满足不是野心的敌人；它是可持续野心生长的平静基础。', ja: '現在の収入の中で満足感を見つける練習をしてください。処女座はより良い状態への絶え間ない改善欲求を持っていますが、それが財政では永遠の不満足につながることがあります。感謝する心が豊かさを呼びます——今持っているものへの真心からの感謝がむしろより多くのものを引き寄せるという逆説を経験してみてください。', es: 'Practica encontrar satisfacción con tus ingresos actuales hoy—Virgo tiene un deseo constante de mejora hacia un estado mejor, pero en las finanzas eso puede llevar a insatisfacción perpetua. Un corazón agradecido atrae abundancia. Experimenta la paradoja de que la gratitud genuina por lo que tienes ahora realmente atrae más hacia ti. La satisfacción no es el enemigo de la ambición; es la base pacífica desde la cual crece la ambición sostenible.' },
      { ko: '재정 목표를 스프레드시트에 정리하면 명확해집니다. 처녀자리는 데이터를 구조화하는 천부적인 재능을 가지고 있어, 재정 목표를 가시화하는 것이 다른 누구보다 효과적입니다. 숫자는 거짓말하지 않습니다—오늘 당신의 재정 목표를 숫자로 명확히 표현하면, 그것이 이미 달성 가능한 계획의 시작입니다.', en: 'Organizing financial goals in a spreadsheet brings clarity today—Virgo has a natural talent for structuring data, making visualizing financial goals more effective than for anyone else. Numbers don\'t lie. When you express your financial goals clearly in numbers today, that is already the beginning of an achievable plan. The act of writing the number down changes your relationship to it in a way that changes your behavior toward it.', zh: '今天把财务目标整理到电子表格中会变得清晰。处女座有天赋般地构建数据的才能，使可视化财务目标比任何人都更有效。数字不会说谎——今天用数字清晰地表达你的财务目标，那已经是可实现计划的开始。写下那个数字的行为会以一种改变你对它行为的方式改变你与它的关系。', ja: '財政目標をスプレッドシートに整理すると明確になります。処女座はデータを構造化する天賦の才能を持っており、財政目標を可視化することが他の誰よりも効果的です。数字は嘘をつきません——今日財政目標を数字で明確に表現すれば、それがすでに達成可能な計画の始まりです。', es: 'Organizar metas financieras en una hoja de cálculo trae claridad hoy—Virgo tiene un talento natural para estructurar datos, haciendo que visualizar metas financieras sea más efectivo que para cualquier otro. Los números no mienten. Cuando expresas tus metas financieras claramente en números hoy, eso ya es el comienzo de un plan alcanzable. El acto de escribir el número cambia tu relación con él de una manera que cambia tu comportamiento hacia él.' },
    ],
    low: [
      { ko: '예상치 못한 수리비나 의료비가 발생할 수 있습니다. 처녀자리는 미래를 대비하는 것을 중시하지만, 모든 비용을 예측하는 것은 불가능합니다. 비상 자금을 확인해두세요—그것이 충분하지 않다면, 오늘이 비상 자금 계획을 세우기 시작하기 가장 좋은 날입니다. 예측하지 못한 것에 대한 최선의 방어는 준비입니다.', en: 'Unexpected repair or medical costs may arise today—Virgo values preparing for the future, but predicting every expense is impossible. Check your emergency fund. If it is not sufficient, today is the best day to begin planning your emergency fund. The best defense against the unpredictable is preparation, and Virgo\'s systematic nature makes building that buffer more natural than for most signs.', zh: '今天可能发生意外的维修费或医疗费。处女座重视为未来做准备，但预测所有费用是不可能的。确认你的应急资金——如果不够充分，今天是开始制定应急资金计划的最佳日子。对无法预测的事情最好的防御是准备，处女座系统化的本性使建立那个缓冲比大多数星座更自然。', ja: '予想外の修理費や医療費が発生する可能性があります。処女座は未来に備えることを大切にしますが、すべての費用を予測することは不可能です。非常資金を確認しておいてください——それが十分でなければ、今日が非常資金の計画を立て始めるのに最良の日です。予測できないことに対する最良の防御は準備であり、処女座の体系的な本質がそのバッファを構築することをほとんどの星座より自然にします。', es: 'Pueden surgir costos inesperados de reparación o médicos hoy—Virgo valora prepararse para el futuro, pero predecir cada gasto es imposible. Verifica tu fondo de emergencia. Si no es suficiente, hoy es el mejor día para comenzar a planificar tu fondo de emergencia. La mejor defensa contra lo impredecible es la preparación, y la naturaleza sistemática de Virgo hace que construir ese colchón sea más natural que para la mayoría de los signos.' },
      { ko: '과도한 분석으로 투자 타이밍을 놓칠 수 있습니다. 처녀자리는 모든 리스크를 제거하려는 경향이 있지만, 재정에서 완벽한 타이밍은 존재하지 않습니다. 완벽한 시점은 존재하지 않습니다—지금 행동하지 않는 것 자체가 기회비용을 만들어내는 결정임을 기억하세요. 충분히 좋은 타이밍에 충분히 좋은 결정이면 충분합니다.', en: 'Over-analysis may cause you to miss investment timing today—Virgo tends to want to eliminate every risk, but in finances the perfect timing doesn\'t exist. Remember that not acting now itself is a decision that creates opportunity cost. Good-enough timing with a good-enough decision is sufficient. The Virgo who waits for perfect conditions ends up watching others benefit from the opportunities they analyzed to death.', zh: '过度分析今天可能让你错过投资时机。处女座倾向于想要消除所有风险，但在财务中完美的时间点是不存在的。记住，现在不行动本身就是一个创造机会成本的决定。足够好的时机加上足够好的决定就够了。等待完美条件的处女座最终会眼看着别人从他们分析至死的机会中受益。', ja: '過度な分析で投資のタイミングを今日逃す可能性があります。処女座はすべてのリスクを排除しようとする傾向がありますが、財政において完璧なタイミングは存在しません。今行動しないこと自体が機会費用を作り出す決断であることを覚えておいてください。十分に良いタイミングと十分に良い決断で十分です。', es: 'El análisis excesivo puede hacerte perder el momento de inversión hoy—Virgo tiende a querer eliminar cada riesgo, pero en finanzas el momento perfecto no existe. Recuerda que no actuar ahora en sí mismo es una decisión que crea costo de oportunidad. Un momento suficientemente bueno con una decisión suficientemente buena es suficiente. El Virgo que espera condiciones perfectas termina viendo a otros beneficiarse de las oportunidades que analizó hasta la muerte.' },
      { ko: '자신의 서비스나 능력을 저평가하지 마세요. 처녀자리는 겸손함과 완벽주의가 결합하여 자신이 제공하는 것의 가치를 실제보다 낮게 평가하는 경향이 있습니다. 적정한 대가를 받는 것은 당연한 권리입니다—오늘 당신의 서비스나 시간의 가격을 현실적으로 평가해보세요. 당신의 꼼꼼함과 전문성은 시장에서 프리미엄 가치를 가집니다.', en: 'Don\'t undervalue your services or abilities today—Virgo\'s combination of humility and perfectionism tends to cause underestimation of what they provide\'s true value. Receiving fair compensation is your right. Evaluate the price of your services or time realistically today. Your meticulousness and expertise hold premium value in the market, and claiming that value is not arrogance—it is accuracy.', zh: '今天不要低估自己的服务或能力。处女座谦逊与完美主义的结合倾向于低估自己所提供的真正价值。获得合理的报酬是理所当然的权利——今天现实地评估你的服务或时间的价格。你的细致和专业技能在市场上具有溢价价值，主张那种价值不是傲慢——而是准确。', ja: '自分のサービスや能力を過小評価しないでください。処女座の謙虚さと完璧主義の組み合わせが自分が提供するものの真の価値を実際より低く評価する傾向があります。適正な対価を受け取ることは当然の権利です——今日あなたのサービスや時間の価格を現実的に評価してみてください。あなたの丁寧さと専門性は市場でプレミアム価値を持っています。', es: 'No subvalores tus servicios o habilidades hoy—la combinación de humildad y perfeccionismo de Virgo tiende a causar subestimación del verdadero valor de lo que proporciona. Recibir una compensación justa es tu derecho. Evalúa el precio de tus servicios o tiempo de manera realista hoy. Tu meticulosidad y experiencia tienen valor premium en el mercado, y reclamar ese valor no es arrogancia—es precisión.' },
      { ko: '지나친 절약이 삶의 질을 떨어뜨릴 수 있습니다. 처녀자리의 절약 정신이 지나치면 삶의 모든 즐거움을 차단하고 재정이 목적이 아닌 삶의 주인이 되어버립니다. 필요한 곳에는 과감하게 투자하세요—건강, 성장, 관계를 위한 지출은 낭비가 아니라 투자입니다.', en: 'Excessive frugality may lower quality of life today—when Virgo\'s thriftiness goes too far, it blocks all of life\'s pleasures and makes finances the master of life rather than the servant of it. Invest boldly where needed. Spending on health, growth, and relationships is not waste but investment. The purpose of money is to fund the life you want, and denying yourself that purpose defeats the entire point.', zh: '今天过度节约可能降低生活质量。处女座的节俭精神如果过度，就会阻断生活中的所有乐趣，让财务成为生活的主人而非仆人。在需要的地方大胆投资——用于健康、成长和关系的支出不是浪费而是投资。金钱的目的是资助你想要的生活，拒绝自己这个目的就破坏了整个意义。', ja: '過度な節約が生活の質を下げる可能性があります。処女座の節約精神が行き過ぎると、生活のすべての楽しみを遮断し、財政が人生の目的ではなく主人になってしまいます。必要な場所には思い切って投資してください——健康、成長、関係のための支出は無駄ではなく投資です。', es: 'La frugalidad excesiva puede reducir la calidad de vida hoy—cuando el ahorro de Virgo va demasiado lejos, bloquea todos los placeres de la vida y hace de las finanzas el amo de la vida en lugar de su siervo. Invierte con decisión donde sea necesario. Gastar en salud, crecimiento y relaciones no es desperdicio sino inversión. El propósito del dinero es financiar la vida que quieres, y negarte ese propósito derrota el punto entero.' },
      { ko: '금전 관련 서류는 꼼꼼하게 확인하되 서명은 서두르지 마세요. 처녀자리는 문서 검토를 잘 하지만, 오늘 압박을 받아 서명할 경우 중요한 것을 놓칠 수 있습니다. 전문가 상담 후 결정하세요—처녀자리가 서두름의 대가를 후회하는 것만큼 힘든 일도 없습니다. 오늘은 검토하고, 내일 결정하세요.', en: 'Check financial documents carefully today but don\'t rush to sign—Virgo reviews documents well, but today under pressure you might miss something important. Decide after consulting an expert. Few things are as difficult for Virgo as regretting the cost of rushing. Review today, decide tomorrow. The extra day of consideration almost never costs you the deal but frequently saves you from regret.', zh: '今天仔细检查金融文件，但不要急于签名。处女座擅长审查文件，但今天在压力下可能会错过重要的东西。咨询专家后再决定——对处女座来说，几乎没有什么比后悔仓促的代价更痛苦的了。今天审查，明天决定。额外的一天考虑时间几乎从不让你失去交易，却经常让你避免后悔。', ja: '金銭関連の書類は丁寧に確認しつつサインは急がないでください。処女座は文書の見直しは上手ですが、今日プレッシャーを受けて署名する場合に重要なものを見逃す可能性があります。専門家に相談してから決めてください——処女座が焦りの代価を後悔するほど辛いことはありません。今日は確認して、明日決断してください。', es: 'Revisa documentos financieros cuidadosamente hoy pero no firmes apresuradamente—Virgo revisa bien los documentos, pero hoy bajo presión podrías perderte algo importante. Decide después de consultar a un experto. Pocas cosas son tan difíciles para Virgo como lamentar el costo de la prisa. Revisa hoy, decide mañana. El día adicional de consideración casi nunca te cuesta el trato pero frecuentemente te salva del arrepentimiento.' },
      { ko: '타인을 위한 과도한 금전적 봉사가 자신의 재정을 위협할 수 있습니다. 처녀자리의 봉사 정신은 아름답지만, 오늘은 그 선이 재정적 안전을 위협하는 수준까지 넘어갈 위험이 있습니다. 경계를 설정하세요—"아니오"라고 말할 수 있는 처녀자리가 더 오래, 더 지속적으로 도울 수 있습니다.', en: 'Excessive financial giving for others may threaten your own finances today—Virgo\'s spirit of service is beautiful, but today there is a risk of crossing the line to a level that threatens financial security. Set boundaries clearly. A Virgo who can say "no" can help more durably and sustainably over the long term. Protecting your financial foundation is the prerequisite for any meaningful service to others.', zh: '今天为他人过度的金钱奉献可能威胁自己的财务。处女座的奉献精神是美好的，但今天有越过危及财务安全界限的风险。设定明确的界限——能够说"不"的处女座可以更持久、更可持续地帮助他人。保护你的财务基础是对他人进行任何有意义服务的前提。', ja: '他人のための過度な金銭的奉仕が自分の財政を今日脅かす可能性があります。処女座の奉仕精神は美しいですが、今日は財政的安全を脅かすレベルまでその線を超えるリスクがあります。境界線を設定してください——「ノー」と言える処女座がより長く、より持続的に助けることができます。', es: 'Dar financieramente en exceso a otros puede amenazar tus finanzas hoy—el espíritu de servicio de Virgo es hermoso, pero hoy existe el riesgo de cruzar la línea a un nivel que amenaza la seguridad financiera. Establece límites claramente. Un Virgo que puede decir "no" puede ayudar de manera más duradera y sostenible a largo plazo. Proteger tu base financiera es el prerrequisito para cualquier servicio significativo a otros.' },
      { ko: '건강 관련 지출이 늘어날 수 있습니다. 처녀자리는 건강 문제를 절약의 대상으로 삼는 경향이 있는데, 그것은 종종 역효과를 냅니다. 예방 차원의 건강 관리가 결국 돈을 절약합니다—오늘 그 비용을 쓰는 것이 나중에 더 큰 비용을 막는 가장 합리적인 투자임을 기억하세요. 건강은 절약이 아닌 투자 영역입니다.', en: 'Health-related expenses may increase today—Virgo tends to apply savings mentality to health matters, but that often backfires. Preventive health care ultimately saves money. Remember that spending on your health today is the most rational investment for preventing much larger costs later. Health is not an area for savings but for investment. The Virgo body, maintained well, performs far better and costs far less in the long run.', zh: '今天健康相关支出可能增加。处女座倾向于将节约思维应用于健康事务，但这往往适得其反。预防性健康管理最终能省钱——记住，今天的健康支出是防止日后更大费用的最合理投资。健康不是节约的领域而是投资的领域。维护良好的处女座身体从长远来看表现更好，花费也更少。', ja: '健康関連の支出が今日増える可能性があります。処女座は健康問題に節約思考を適用する傾向がありますが、それはしばしば逆効果を生みます。予防的な健康管理が結局お金を節約します——今日その費用を使うことが後でより大きな費用を防ぐ最も合理的な投資であることを覚えておいてください。健康は節約ではなく投資の領域です。', es: 'Los gastos de salud pueden aumentar hoy—Virgo tiende a aplicar mentalidad de ahorro a asuntos de salud, pero eso a menudo resulta contraproducente. El cuidado preventivo ahorra dinero a largo plazo. Recuerda que gastar en tu salud hoy es la inversión más racional para prevenir costos mucho mayores más tarde. La salud no es un área de ahorro sino de inversión. El cuerpo de Virgo, bien mantenido, funciona mucho mejor y cuesta mucho menos a largo plazo.' },
      { ko: '수성의 혼란스러운 에너지가 계산 실수를 유발할 수 있습니다. 처녀자리의 정밀한 수학적 두뇌도 오늘 수성의 간섭으로 평소보다 실수를 할 가능성이 있습니다. 중요한 금액은 두 번 확인하세요—이체, 계산서, 가격 협상 등 금액이 관련된 모든 것을 평소보다 한 번 더 점검하는 날입니다.', en: 'Mercury\'s chaotic energy may cause calculation errors today—even Virgo\'s precise mathematical brain has a higher chance of making mistakes than usual due to Mercury\'s interference. Double-check important amounts. Transfers, invoices, price negotiations—anything involving amounts needs one extra review today. Your natural meticulousness is your ally; deploy it more deliberately than usual right now.', zh: '水星混乱的能量今天可能导致计算失误。即使是处女座精确的数学大脑，由于水星的干扰，今天也比平时更有可能出错。重要金额请确认两遍——转账、账单、价格谈判——所有涉及金额的事情今天都需要额外检查一次。你天生的细致是你的盟友；现在比平时更刻意地运用它。', ja: '水星の混乱したエネルギーが計算ミスを引き起こす可能性があります。処女座の精密な数学的頭脳も今日水星の干渉でいつもより間違いをする可能性があります。重要な金額は二度確認してください——振込み、請求書、価格交渉など金額が関わるすべてのものを今日はいつもより一度多く点検する日です。', es: 'La energía caótica de Mercurio puede causar errores de cálculo hoy—incluso el preciso cerebro matemático de Virgo tiene mayor probabilidad de cometer errores que lo usual debido a la interferencia de Mercurio. Verifica los montos importantes dos veces. Transferencias, facturas, negociaciones de precios—cualquier cosa que involucre montos necesita una revisión adicional hoy. Tu meticulosidad natural es tu aliada; despliégala más deliberadamente de lo usual ahora mismo.' },
      { ko: '불안감에 의한 충동적 보험 가입이나 투자는 피하세요. 처녀자리는 불안할 때 "뭔가를 해야 한다"는 충동에 취약한데, 재정에서 그 충동은 종종 나쁜 결정으로 이어집니다. 감정이 아닌 데이터로 결정하세요—오늘 어떤 재정적 결정이든 24시간 후에 다시 검토하는 것이 현명합니다.', en: 'Avoid impulsive insurance purchases or investments driven by anxiety today—Virgo is vulnerable to the impulse to "do something" when anxious, and in finances that impulse often leads to poor decisions. Decide with data, not emotions. For any financial decision today, reviewing it again after 24 hours is wise. Fear-driven financial decisions almost always look different in the morning light when the anxiety has passed.', zh: '今天避免因焦虑而冲动购买保险或投资。处女座在焦虑时容易受到"必须做点什么"冲动的影响，而在财务上这种冲动往往导致糟糕的决定。用数据而非情绪做决定——今天的任何财务决定，24小时后再次审查都是明智的。出于恐惧的财务决定，当焦虑过去后，在清晨的光线下几乎总是看起来不同。', ja: '不安感による衝動的な保険加入や投資は今日避けてください。処女座は不安な時に「何かしなければならない」という衝動に弱く、財政においてその衝動はしばしば悪い決断につながります。感情ではなくデータで決定してください——今日どんな財政的決定でも24時間後に再確認することが賢明です。', es: 'Evita compras impulsivas de seguros o inversiones motivadas por ansiedad hoy—Virgo es vulnerable al impulso de "hacer algo" cuando está ansioso, y en finanzas ese impulso a menudo lleva a malas decisiones. Decide con datos, no emociones. Para cualquier decisión financiera hoy, revisarla nuevamente después de 24 horas es sabio. Las decisiones financieras impulsadas por el miedo casi siempre se ven diferentes a la luz de la mañana cuando la ansiedad ha pasado.' },
      { ko: '재정적 완벽주의가 오히려 기회비용을 높이고 있을 수 있습니다. 완벽한 타이밍, 완벽한 조건, 완벽한 수익률을 기다리는 동안 기회가 지나가고 있습니다. 적절한 시점에 실행하세요—"충분히 좋은 결정을 제때에 실행하는 것"이 "완벽한 결정을 영원히 기다리는 것"보다 항상 더 나은 재정 전략입니다.', en: 'Financial perfectionism may be raising opportunity costs today—while waiting for perfect timing, perfect conditions, and perfect returns, opportunities are passing. Execute at the right time. "Executing a good-enough decision in time" is always a better financial strategy than "waiting forever for the perfect decision." The compound interest on action taken beats the compound opportunity cost of endless waiting every single time.', zh: '今天财务完美主义可能反而在提高机会成本。在等待完美时机、完美条件和完美回报的同时，机会正在流逝。在合适的时机执行——"在正确时间执行足够好的决定"总是比"永远等待完美决定"更好的财务策略。行动带来的复利永远胜过无尽等待的复利机会成本。', ja: '財政的な完璧主義がかえって機会費用を高めている可能性があります。完璧なタイミング、完璧な条件、完璧な収益率を待っている間に機会が過ぎ去っています。適切な時点で実行してください——「十分に良い決断を適時に実行すること」は「完璧な決断を永遠に待つこと」より常により良い財政戦略です。', es: 'El perfeccionismo financiero puede estar elevando costos de oportunidad hoy—mientras esperas el momento perfecto, las condiciones perfectas y los rendimientos perfectos, las oportunidades pasan. Ejecuta en el momento adecuado. "Ejecutar una decisión suficientemente buena a tiempo" es siempre una mejor estrategia financiera que "esperar para siempre la decisión perfecta." El interés compuesto de la acción tomada vence al costo de oportunidad compuesto de la espera sin fin en todo momento.' },
    ],
  },
};
